  ADMIN = 'Administrator',
  STOCK_KEEPER = 'Stock Keeper'
}

export enum ItemCategory {
  STATIONERY = '01',
  IT_EQUIPMENT = '02',
  FURNITURE = '03',
  VEHICLES = '04',
  MAINTENANCE = '05'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  department: string;
}

export interface InventoryItem {
  id: string;
  name: string;
  sku?: string;
