  stockKeeperSignature?: string;
  stockCheckDate?: string;

  // Step 3: Purchase Request (if not in stock)
  prRefNumber?: string;
  authorizedBySignature?: string;

  // Step 4: Price Eval
  evalRefNumber?: string;
  quotations?: {
    vendorName: string;
    price: number;
    selected: boolean;
  }[];

  // Step 5: PO
  poNumber?: string;
  selectedVendor?: string;

  // Logs
  logs: {
    date: string;
    action: string;
    actor: string;
  }[];
}

