export const InventoryService = {
  getAll: () => Promise.resolve([...MOCK_INVENTORY]),
  add: (item: Omit<InventoryItem, 'id' | 'lastUpdated'>) => {
    const newItem = { ...item, id: Math.random().toString(36).substr(2, 9), lastUpdated: new Date().toISOString() };
    MOCK_INVENTORY.push(newItem);
