import React from 'react';
import { ProcurementWorkflow } from '../types';

interface DocumentTemplateProps {
  type: 'GSRF' | 'PRF' | 'PO';
  data: ProcurementWorkflow;
}

export const DocumentTemplate: React.FC<DocumentTemplateProps> = ({ type, data }) => {
  const currentYear = new Date().getFullYear();

  const renderHeader = (title: string, refNo: string) => (
    <div className="flex flex-col items-center mb-8 border-b-2 border-black pb-4">
      <div className="text-center">
        <h1 className="text-xl font-bold uppercase tracking-wider mb-1 font-serif">Government Entity of State</h1>
        <h2 className="text-sm uppercase text-slate-600 mb-4 font-serif">Department of Administration & Finance</h2>
      </div>
      <div className="w-full flex justify-between items-end mt-4">
        <div>
          <p className="text-xs font-bold">Document: {title}</p>
        </div>
        <div className="text-right">
          <p className="text-sm"><span className="font-bold">Ref No:</span> {refNo}</p>
          <p className="text-sm"><span className="font-bold">Date:</span> {new Date().toLocaleDateString()}</p>
        </div>
      </div>
    </div>
  );

  const renderSignatureBlock = (role: string, name: string | undefined, signature: string | undefined, date: string | undefined) => (
    <div className="flex-1 flex flex-col items-center">
      <div className="h-16 w-32 mb-2 flex items-end justify-center">
        {signature ? <img src={signature} alt="Signed" className="max-h-16" /> : <div className="text-xs text-slate-300 italic">Not Signed</div>}
      </div>
      <div className="w-32 border-t border-black pt-1 text-center">
        <p className="text-xs font-bold">{role}</p>
        <p className="text-xs">{name || '___________'}</p>
        <p className="text-[10px] text-slate-500">{date ? new Date(date).toLocaleDateString() : ''}</p>
      </div>
    </div>
  );

  // --- Goods & Services Requisition Form (GSRF) ---
  if (type === 'GSRF') {
    return (
      <div className="printable-area bg-white p-8 max-w-[210mm] mx-auto min-h-[297mm] shadow-lg text-black">
        {renderHeader('GOODS & SERVICES REQUISITION FORM', data.gsrfRefNumber || `GSRF/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-4 text-sm">
          <div><span className="font-bold">Department:</span> {data.requesterDepartment}</div>
          <div><span className="font-bold">Required Date:</span> {new Date(data.requestDate).toLocaleDateString()}</div>
        </div>

        <table className="w-full border-collapse border border-black mb-8 text-sm">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">No.</th>
              <th className="border border-black p-2 text-left">Description / Particulars</th>
              <th className="border border-black p-2 w-24">Qty Req</th>
              <th className="border border-black p-2 w-24">Qty Issued</th>
              <th className="border border-black p-2">Remarks</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center">{item.quantity}</td>
                <td className="border border-black p-2 text-center"></td>
                <td className="border border-black p-2"></td>
              </tr>
            ))}
            {/* Fill empty rows */}
            {[...Array(5 - data.items.length)].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

        <div className="flex justify-between mt-12 gap-4">
          {renderSignatureBlock('REQUESTED BY', data.requesterName, data.requesterSignature, data.requestDate)}
          {renderSignatureBlock('AUTHORIZED BY', 'Dept Head', undefined, undefined)}
          {renderSignatureBlock('ISSUED BY', 'Stock Keeper', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('RECEIVED BY', 'Receiver', undefined, undefined)}
        </div>
      </div>
    );
  }

  // --- Purchase Request Form (PRF) ---
  if (type === 'PRF') {
     return (
      <div className="printable-area bg-white p-8 max-w-[210mm] mx-auto min-h-[297mm] shadow-lg text-black">
        {renderHeader('PURCHASE REQUEST FORM', data.prRefNumber || `PR/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-4 text-sm">
           <div><span className="font-bold">GSRF Ref No:</span> {data.gsrfRefNumber || 'N/A'}</div>
           <div><span className="font-bold">Department:</span> {data.requesterDepartment}</div>
           <div><span className="font-bold">Required Date:</span> {new Date(data.requestDate).toLocaleDateString()}</div>
        </div>

        <table className="w-full border-collapse border border-black mb-8 text-sm">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">No.</th>
              <th className="border border-black p-2 text-left">Description</th>
              <th className="border border-black p-2 w-24">Stock Qty</th>
              <th className="border border-black p-2 w-24">Req Qty</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center">0</td>
                <td className="border border-black p-2 text-center">{item.quantity}</td>
              </tr>
            ))}
          </tbody>
        </table>

         <div className="flex justify-between mt-12 gap-8">
          {renderSignatureBlock('PREPARED BY', 'Stock Keeper', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('AUTHORIZED BY', 'Head of Procurement', data.authorizedBySignature, undefined)}
        </div>
      </div>
     );
  }

  return <div>Document template not found.</div>;
};

