  }, []);

  const loadData = async () => {
    const data = await ProcurementService.getAll();
    setRequests(data);
  };

  const handleCreateRequest = async () => {
    if (requestItems.length === 0) return;

    await ProcurementService.create({
      requestType: 'GOODS',
      status: ProcurementStatus.SUBMITTED,
      requesterId: currentUser.id,
      requesterName: currentUser.name,
      requesterDepartment: currentUser.department,
      section: section,
      requestDate: new Date().toISOString(),
      requiredDate: requiredDate || new Date().toISOString(),
      remarks: remarks,
      items: requestItems,
      requesterSignature: signature
    });

    setView('LIST');
    resetForm();
    loadData();
  };

  const resetForm = () => {
    setRequestItems([]);
    setSignature('');
    setSection(currentUser.department);
    setRequiredDate('');
    setRemarks('');
    setNewItemDesc('');
    setNewItemQty(1);
  };

  const updateStatus = async (id: string, status: ProcurementStatus, log: string, extraUpdates = {}) => {
    await ProcurementService.updateStatus(id, status, log, currentUser.name, extraUpdates);
    if (selectedRequest) {
      // Refresh local selected request
      const updated = await ProcurementService.getAll();
      const found = updated.find(r => r.id === id);
      setSelectedRequest(found || null);
    }
    loadData();
  };

  const addItemToRequest = () => {
    if(!newItemDesc) return;
    setRequestItems([...requestItems, { description: newItemDesc, quantity: newItemQty }]);
    setNewItemDesc('');
    setNewItemQty(1);
  };

  const renderStatusBadge = (status: ProcurementStatus) => {
    const colors = {
      [ProcurementStatus.DRAFT]: 'bg-slate-100 text-slate-800',
      [ProcurementStatus.SUBMITTED]: 'bg-blue-100 text-blue-800',
      [ProcurementStatus.APPROVED]: 'bg-green-100 text-green-800',
      [ProcurementStatus.REJECTED]: 'bg-red-100 text-red-800',
      [ProcurementStatus.ISSUED]: 'bg-purple-100 text-purple-800',
      [ProcurementStatus.PROCUREMENT_NEEDED]: 'bg-orange-100 text-orange-800',
      [ProcurementStatus.PR_CREATED]: 'bg-indigo-100 text-indigo-800',
      [ProcurementStatus.EVALUATION]: 'bg-yellow-100 text-yellow-800',
      [ProcurementStatus.PO_ISSUED]: 'bg-teal-100 text-teal-800',
      [ProcurementStatus.COMPLETED]: 'bg-emerald-100 text-emerald-800',
    };
    return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${colors[status]}`}>{status}</span>;
  };

  if (view === 'CREATE') {
    return (
      <Card title="New Goods & Service Requisition Form (GSRF)">
        <div className="space-y-6 max-w-3xl">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Select Section</label>
                <select 
                  className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                  value={section}
                  onChange={e => setSection(e.target.value)}
                >
                  <option value="">-- Select Section --</option>
                  {sections.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
             </div>
             <Input 
               type="date" 
               label="Required Date" 
               value={requiredDate} 
               onChange={e => setRequiredDate(e.target.value)} 
             />
          </div>

          <div>
             <label className="block text-sm font-medium text-slate-700 mb-1">Remarks / Purpose of Use</label>
             <textarea 
               className="flex w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-gov-500 h-24 resize-none"
               placeholder="Enter use case or details..."
               value={remarks}
               onChange={e => setRemarks(e.target.value)}
             />
          </div>

          <div className="bg-slate-50 p-4 rounded-md border border-slate-200">
            <h3 className="text-sm font-medium mb-2">Add Items</h3>
            <div className="flex gap-2 mb-2">
              <Input 
                placeholder="Item Description" 
                value={newItemDesc} 
                onChange={e => setNewItemDesc(e.target.value)} 
                className="flex-1 mb-0"
              />
              <Input 
                type="number" 
                placeholder="Qty" 
                value={newItemQty} 
                onChange={e => setNewItemQty(parseInt(e.target.value))} 
                className="w-24 mb-0"
                min={1}
              />
              <Button onClick={addItemToRequest} size="sm" icon={Plus} type="button">Add</Button>
            </div>
            <ul className="text-sm space-y-1">
              {requestItems.map((item, idx) => (
                <li key={idx} className="flex justify-between border-b border-slate-200 py-1">
                  <span>{item.description}</span>
                  <span className="font-mono">{item.quantity}</span>
                </li>
              ))}
              {requestItems.length === 0 && <li className="text-slate-400 italic">No items added yet.</li>}
            </ul>
          </div>

          <SignaturePad onChange={setSignature} label="Requester Signature" />

          <div className="flex justify-end gap-2 pt-4">
            <Button variant="outline" onClick={() => { setView('LIST'); resetForm(); }}>Cancel</Button>
            <Button disabled={requestItems.length === 0 || !signature} onClick={handleCreateRequest}>Submit Request</Button>
          </div>
        </div>
      </Card>
    );
  }

  if (view === 'DETAIL' && selectedRequest) {
    const r = selectedRequest;
    return (
      <div className="space-y-6">
        <div className="flex justify-between items-center">
          <Button variant="outline" onClick={() => { setView('LIST'); setIsPrintMode(false); }} icon={ArrowRight} className="rotate-180">Back</Button>
          <div className="flex gap-2">
            {!isPrintMode && <Button variant="secondary" icon={Printer} onClick={() => { setIsPrintMode(true); setTimeout(() => window.print(), 100); }}>Print / Preview</Button>}
            {isPrintMode && <Button variant="outline" onClick={() => setIsPrintMode(false)}>Close Preview</Button>}
          </div>
        </div>

        {isPrintMode ? (
          <div className="border border-slate-300 bg-slate-100 p-8 flex justify-center">
            {/* Logic to determine which doc to show based on status */}
            {r.status === ProcurementStatus.SUBMITTED ? 
              <DocumentTemplate type="GSRF" data={r} /> : 
             (r.status === ProcurementStatus.PR_CREATED || r.status === ProcurementStatus.PROCUREMENT_NEEDED) ? 
              <DocumentTemplate type="PRF" data={r} /> :
              <DocumentTemplate type="GSRF" data={r} />
            }
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-2 space-y-6">
              <Card title={`Request #${r.gsrfRefNumber || r.id.toUpperCase()}`}>
                <div className="flex justify-between mb-4">
                  <div>
                    <p className="text-sm text-slate-500">Requester</p>
                    <p className="font-medium">{r.requesterName} ({r.section || r.requesterDepartment})</p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm text-slate-500">Status</p>
                    {renderStatusBadge(r.status)}
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4 mb-4 text-sm">
                   <div>
                     <span className="text-slate-500 block">Date Submitted</span>
                     <span>{new Date(r.requestDate).toLocaleDateString()}</span>
                   </div>
                   <div>
                     <span className="text-slate-500 block">Required By</span>
                     <span>{r.requiredDate ? new Date(r.requiredDate).toLocaleDateString() : 'N/A'}</span>
                   </div>
                   <div className="col-span-2">
                     <span className="text-slate-500 block">Remarks</span>
                     <p className="bg-slate-50 p-2 rounded border border-slate-100">{r.remarks || 'No remarks provided.'}</p>
                   </div>
                </div>

                <div className="mt-4">
                  <h4 className="text-sm font-medium border-b border-slate-100 pb-2 mb-2">Items Requested</h4>
                  {r.items.map((item, i) => (
                    <div key={i} className="flex justify-between py-2 border-b border-slate-50 text-sm">
                      <span>{item.description}</span>
                      <span className="font-mono bg-slate-100 px-2 rounded">{item.quantity}</span>
                    </div>
                  ))}
                </div>
              </Card>

              {/* Workflow Actions for Stock Keeper */}
              {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.SUBMITTED && (
                <Card title="Stock Keeper Action">
                  <p className="text-sm text-slate-600 mb-4">Check stock availability for requested items.</p>
                  <div className="flex gap-4">
                    <Button 
                      className="flex-1"
                      onClick={() => updateStatus(r.id, ProcurementStatus.ISSUED, 'Items Issued from Stock', { stockKeeperSignature: 'signed', stockCheckDate: new Date().toISOString() })}
                    >
                      <Check className="mr-2 h-4 w-4" /> Available - Issue Stock
                    </Button>
                    <Button 
                      className="flex-1"
                      variant="secondary"
                      onClick={() => updateStatus(r.id, ProcurementStatus.PROCUREMENT_NEEDED, 'Marked for Procurement', { stockKeeperSignature: 'signed', stockCheckDate: new Date().toISOString(), gsrfRefNumber: r.gsrfRefNumber })}
                    >
                      <X className="mr-2 h-4 w-4" /> Not Available - Create PR
                    </Button>
                  </div>
                </Card>
              )}

               {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PROCUREMENT_NEEDED && (
                <Card title="Procurement Processing">
                  <p className="text-sm text-slate-600 mb-4">Convert this request into a formal Purchase Request.</p>
                  <Button 
                    onClick={() => updateStatus(r.id, ProcurementStatus.PR_CREATED, 'Purchase Request Created', { prRefNumber: `PR/${new Date().getFullYear()}/${Math.floor(Math.random()*1000)}` })}
                  >
                    Generate Purchase Request (PR)
                  </Button>
                </Card>
              )}
            </div>

            <div className="space-y-6">
               <Card title="Signatures">
                 <div className="space-y-4">
                   <div>
                     <p className="text-xs text-slate-500">Requester</p>
                     {r.requesterSignature ? <img src={r.requesterSignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                   </div>
                   <div>
                     <p className="text-xs text-slate-500">Stock Keeper</p>
                     {r.stockKeeperSignature ? <div className="text-sm font-serif italic text-blue-800">Signed Digitally</div> : <span className="text-xs italic">Pending</span>}
                   </div>
                 </div>
               </Card>

               <Card title="History Log">
                 <ul className="space-y-3 relative border-l border-slate-200 ml-2 pl-4">
                   {r.logs.map((log, i) => (
                     <li key={i} className="text-xs">
                       <div className="absolute w-2 h-2 bg-slate-300 rounded-full -left-[5px] mt-1"></div>
                       <p className="font-semibold text-slate-700">{log.action}</p>
                       <p className="text-slate-500">{new Date(log.date).toLocaleString()} by {log.actor}</p>
                     </li>
                   ))}
                 </ul>
               </Card>
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Procurement & Requests</h2>
        <Button onClick={() => setView('CREATE')} icon={Plus}>New Request</Button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {requests.map(req => (
          <div key={req.id} onClick={() => { setSelectedRequest(req); setView('DETAIL'); }} className="cursor-pointer group">
            <Card className="hover:shadow-md transition-shadow h-full border-l-4 border-l-gov-500">
              <div className="flex justify-between items-start mb-2">
                <span className="font-mono text-xs text-slate-500">{req.gsrfRefNumber || req.id.toUpperCase()}</span>
                {renderStatusBadge(req.status)}
              </div>
              <h3 className="font-medium text-slate-800 mb-1 truncate">{req.items[0]?.description} {req.items.length > 1 && `+${req.items.length - 1} more`}</h3>
              <div className="text-sm text-slate-500 mb-4">
                Req by: {req.requesterName}
              </div>
              <div className="text-xs text-slate-400 flex items-center">
                 <FileText className="w-3 h-3 mr-1" /> {new Date(req.requestDate).toLocaleDateString()}
              </div>
            </Card>
          </div>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import { ProcurementWorkflow } from '../types';

interface DocumentTemplateProps {
  type: 'GSRF' | 'PRF' | 'PO';
  data: ProcurementWorkflow;
}

export const DocumentTemplate: React.FC<DocumentTemplateProps> = ({ type, data }) => {
  const currentYear = new Date().getFullYear();

  const renderHeader = (title: string, refNo: string) => (
    <div className="flex flex-col items-center mb-8 border-b-2 border-black pb-4">
      <div className="text-center">
        <h1 className="text-xl font-bold uppercase tracking-wider mb-1 font-serif">Government Entity of State</h1>
        <h2 className="text-sm uppercase text-slate-600 mb-4 font-serif">Department of Administration & Finance</h2>
      </div>
      <div className="w-full flex justify-between items-end mt-4">
        <div>
          <p className="text-xs font-bold">Document: {title}</p>
        </div>
        <div className="text-right">
          <p className="text-sm"><span className="font-bold">Ref No:</span> {refNo}</p>
          <p className="text-sm"><span className="font-bold">Date:</span> {new Date().toLocaleDateString()}</p>
        </div>
      </div>
    </div>
  );

  const renderSignatureBlock = (role: string, name: string | undefined, signature: string | undefined, date: string | undefined) => (
    <div className="flex-1 flex flex-col items-center">
      <div className="h-16 w-32 mb-2 flex items-end justify-center">
        {signature ? <img src={signature} alt="Signed" className="max-h-16" /> : <div className="text-xs text-slate-300 italic">Not Signed</div>}
      </div>
      <div className="w-32 border-t border-black pt-1 text-center">
        <p className="text-xs font-bold">{role}</p>
        <p className="text-xs">{name || '___________'}</p>
        <p className="text-[10px] text-slate-500">{date ? new Date(date).toLocaleDateString() : ''}</p>
      </div>
    </div>
  );

  // --- Goods & Services Requisition Form (GSRF) ---
  if (type === 'GSRF') {
    return (
      <div className="printable-area bg-white p-8 max-w-[210mm] mx-auto min-h-[297mm] shadow-lg text-black">
        {renderHeader('GOODS & SERVICES REQUISITION FORM', data.gsrfRefNumber || `GSRF/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-4 text-sm">
          <div><span className="font-bold">Section / Dept:</span> {data.section || data.requesterDepartment}</div>
          <div><span className="font-bold">Required Date:</span> {data.requiredDate ? new Date(data.requiredDate).toLocaleDateString() : 'N/A'}</div>
          <div className="col-span-2"><span className="font-bold">Remarks / Purpose:</span> <span className="italic">{data.remarks || 'N/A'}</span></div>
        </div>

        <table className="w-full border-collapse border border-black mb-8 text-sm">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">No.</th>
              <th className="border border-black p-2 text-left">Description / Particulars</th>
              <th className="border border-black p-2 w-24">Qty Req</th>
              <th className="border border-black p-2 w-24">Qty Issued</th>
              <th className="border border-black p-2">Notes</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center">{item.quantity}</td>
                <td className="border border-black p-2 text-center"></td>
                <td className="border border-black p-2"></td>
              </tr>
            ))}
            {/* Fill empty rows */}
            {[...Array(Math.max(0, 5 - data.items.length))].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

        <div className="flex justify-between mt-12 gap-4">
          {renderSignatureBlock('REQUESTED BY', data.requesterName, data.requesterSignature, data.requestDate)}
          {renderSignatureBlock('AUTHORIZED BY', 'Dept Head', undefined, undefined)}
          {renderSignatureBlock('ISSUED BY', 'Stock Keeper', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('RECEIVED BY', 'Receiver', undefined, undefined)}
        </div>
      </div>
    );
  }

  // --- Purchase Request Form (PRF) ---
  if (type === 'PRF') {
     return (
      <div className="printable-area bg-white p-8 max-w-[210mm] mx-auto min-h-[297mm] shadow-lg text-black">
        {renderHeader('PURCHASE REQUEST FORM', data.prRefNumber || `PR/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-4 text-sm">
           <div><span className="font-bold">GSRF Ref No:</span> {data.gsrfRefNumber || 'N/A'}</div>
           <div><span className="font-bold">Department:</span> {data.section || data.requesterDepartment}</div>
           <div><span className="font-bold">Required Date:</span> {data.requiredDate ? new Date(data.requiredDate).toLocaleDateString() : 'N/A'}</div>
        </div>

        <table className="w-full border-collapse border border-black mb-8 text-sm">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">No.</th>
              <th className="border border-black p-2 text-left">Description</th>
              <th className="border border-black p-2 w-24">Stock Qty</th>
              <th className="border border-black p-2 w-24">Req Qty</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center">0</td>
                <td className="border border-black p-2 text-center">{item.quantity}</td>
              </tr>
            ))}
          </tbody>
        </table>

         <div className="flex justify-between mt-12 gap-8">
          {renderSignatureBlock('PREPARED BY', 'Stock Keeper', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('AUTHORIZED BY', 'Head of Procurement', data.authorizedBySignature, undefined)}
        </div>
      </div>
     );
  }

  return <div>Document template not found.</div>;
};

export enum UserRole {
  USER = 'User',
  SUPERVISOR = 'Supervisor',
  MANAGER = 'Manager',
  FINANCE_OFFICER = 'Finance Officer',
  ADMIN = 'Administrator',
  STOCK_KEEPER = 'Stock Keeper'
}

export enum ItemCategory {
  STATIONERY = '01',
  IT_EQUIPMENT = '02',
  FURNITURE = '03',
  VEHICLES = '04',
  MAINTENANCE = '05'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  department: string;
}

export interface InventoryItem {
  id: string;
  name: string;
  sku?: string;
  // Gov ID: OfficeNumber | Year | CategoryNumber | ItemTypeNumber | ItemNumber
  govId: string;
  category: ItemCategory;
  quantity: number;
  location: string;
  minStockLevel: number;
  pricePerUnit: number;
  lastUpdated: string;
}

export interface Asset {
  id: string;
  name: string;
  govId: string;
  category: ItemCategory;
  condition: 'New' | 'Good' | 'Fair' | 'Poor' | 'Disposal';
  purchaseDate: string;
  price: number;
  location: string;
  assignedTo?: string;
}

export enum ProcurementStatus {
  DRAFT = 'Draft',
  SUBMITTED = 'Submitted',
  APPROVED = 'Approved',
  REJECTED = 'Rejected',
  ISSUED = 'Issued', // Stock issued locally
  PROCUREMENT_NEEDED = 'Procurement Needed', // Moved to procurement
  PR_CREATED = 'PR Created', // Purchase Request Form generated
  EVALUATION = 'Evaluation', // Price Evaluation Form generated
  PO_ISSUED = 'PO Issued',
  COMPLETED = 'Completed'
}

export enum EvaluationMethod {
  EMAIL = 'Email',
  PHONE = 'Phone',
  VISITING = 'Visiting'
}

export interface ProcurementWorkflow {
  id: string;
  requestType: 'GOODS' | 'SERVICE';
  status: ProcurementStatus;

  // Step 1: Request
  requesterId: string;
  requesterName: string;
  requesterDepartment: string;
  section?: string;
  requestDate: string;
  requiredDate?: string;
  remarks?: string; // Purpose / Use case
  items: {
    itemId?: string; // If existing inventory item
    description: string;
    quantity: number;
    estimatedCost?: number;
  }[];
  requesterSignature?: string;

  // Step 2: Stock Keeper Check / GSRF
  gsrfRefNumber?: string;
  stockKeeperSignature?: string;
  stockCheckDate?: string;

  // Step 2a: Issue Process (If Available)
  issueDetails?: {
    receiverName: string;
    receiverDepartment: string;
    issueDate: string;
    remarks: string;
  };

  // Step 3: Purchase Request (if not in stock)
  prRefNumber?: string;
  authorizedBySignature?: string;

  // Step 4: Price Eval
  evalRefNumber?: string; // Format: (A)263/YYYY/Counter
  evaluationMethod?: EvaluationMethod;
  quotations?: {
    vendorName: string;
    price: number;
    selected: boolean;
  }[];

  // Step 5: PO
  poNumber?: string;
  selectedVendor?: string;

  // Logs
  logs: {
    date: string;
    action: string;
    actor: string;
  }[];
}

