// Service Methods
export const InventoryService = {
  getAll: () => Promise.resolve([...MOCK_INVENTORY]),
  add: (item: Omit<InventoryItem, 'id' | 'lastUpdated'>) => {
    const newItem = { ...item, id: Math.random().toString(36).substr(2, 9), lastUpdated: new Date().toISOString() };
    MOCK_INVENTORY.push(newItem);
    return Promise.resolve(newItem);
  },
  updateStock: (id: string, delta: number) => {
    const item = MOCK_INVENTORY.find(i => i.id === id);
    if (item) {
      item.quantity += delta;
      item.lastUpdated = new Date().toISOString();
    }
    return Promise.resolve(item);
  },
  generateGovId: (year: string, category: string, type: string) => {
    const count = MOCK_INVENTORY.filter(i => i.govId.includes(`${year}|${category}|${type}`)).length + 1;
    const countStr = count.toString().padStart(3, '0');
    return `${OFFICE_CODE}|${year}|${category}|${type}|${countStr}`;
  }
};

export const AssetService = {
  getAll: () => Promise.resolve([...MOCK_ASSETS]),
  add: (asset: Omit<Asset, 'id'>) => {
    const newAsset = { ...asset, id: Math.random().toString(36).substr(2, 9) };
    MOCK_ASSETS.push(newAsset);
    return Promise.resolve(newAsset);
  },
  generateGovId: (year: string, category: string, type: string) => {
    const count = MOCK_ASSETS.filter(i => i.govId.includes(`${year}|${category}|${type}`)).length + 1;
    const countStr = count.toString().padStart(3, '0');
    return `${OFFICE_CODE}|${year}|${category}|${type}|${countStr}`;
  }
};

export const ProcurementService = {
  getAll: () => Promise.resolve([...MOCK_REQUESTS]),
  create: (req: Omit<ProcurementWorkflow, 'id' | 'logs' | 'gsrfRefNumber'>) => {
    const year = new Date().getFullYear();
    const count = MOCK_REQUESTS.length + 407; // Starting counter from user example
    // Format: (RF)/OfficeCode/Year/Count
    const gsrfRefNumber = `(RF)/${OFFICE_CODE}/${year}/${count}`;

    const newReq: ProcurementWorkflow = { 
      ...req, 
      id: Math.random().toString(36).substr(2, 9),
      gsrfRefNumber,
      logs: [{ date: new Date().toISOString(), action: 'Request Submitted', actor: req.requesterName }]
    };
    MOCK_REQUESTS.push(newReq);
    return Promise.resolve(newReq);
  },
  updateStatus: (id: string, status: ProcurementStatus, logEntry: string, actor: string, updates?: Partial<ProcurementWorkflow>) => {
    const req = MOCK_REQUESTS.find(r => r.id === id);
    if (req) {
      // Auto-generate Evaluation ID if moving to EVALUATION status and ID doesn't exist
      if (status === ProcurementStatus.EVALUATION && !req.evalRefNumber) {
         const year = new Date().getFullYear();
         // Simulate finding the next counter. In real app, query DB.
         const count = 45; // Based on prompt example
         req.evalRefNumber = `(A)${OFFICE_CODE}/${year}/${count}`;
      }

      req.status = status;
      req.logs.push({ date: new Date().toISOString(), action: logEntry, actor });
      if (updates) Object.assign(req, updates);
    }
    return Promise.resolve(req);
  }
};

