                    <th key={i} className="border border-black p-2 w-32">
                    <div className="font-bold">{q.vendorName || `Vendor ${i+1}`}</div>
                    <div className="text-[10px] font-normal">Rate (Unit)</div>
                    </th>
                )) || <th className="border border-black p-2">Vendor Details</th>}
                </tr>
            </thead>
            <tbody>
                {data.items.map((item, idx) => (
                <tr key={idx}>
                    <td className="border border-black p-2 text-center">{idx + 1}</td>
                    <td className="border border-black p-2">{item.description}</td>
                    <td className="border border-black p-2 text-center">{item.quantity}</td>
