     // For this template, we will show the total amount at the bottom.

     return (
       <div className="printable-area bg-white p-8 max-w-[210mm] mx-auto min-h-[297mm] shadow-lg text-black">
         {renderHeader('PURCHASE ORDER', data.poNumber || 'PENDING')}

         <div className="flex justify-between mb-8 text-sm">
            <div className="w-1/2">
               <h3 className="font-bold bg-slate-100 p-1 mb-2 border-b border-black">VENDOR:</h3>
               <p className="font-bold">{selectedQuote?.vendorName || 'N/A'}</p>
               <p>Reference Quote: {selectedQuote?.quoteNumber || 'N/A'}</p>
            </div>
            <div className="w-1/2 text-right">
               <h3 className="font-bold bg-slate-100 p-1 mb-2 border-b border-black">ORDER DETAILS:</h3>
               <p><span className="font-bold">Date:</span> {data.budgetVerifiedDate ? new Date(data.budgetVerifiedDate).toLocaleDateString() : new Date().toLocaleDateString()}</p>
               <p><span className="font-bold">Budget Code:</span> {data.budgetCode}</p>
               <p><span className="font-bold">PR Ref:</span> {data.prRefNumber}</p>
            </div>
         </div>

         <table className="w-full border-collapse border border-black mb-8 text-sm">
           <thead>
             <tr className="bg-slate-100">
               <th className="border border-black p-2 w-12">No.</th>
               <th className="border border-black p-2 text-left">Description</th>
               <th className="border border-black p-2 w-24">Quantity</th>
