import React, { useState, useEffect } from 'react';
import { ProcurementWorkflow, ProcurementStatus, User, UserRole, EvaluationMethod, EvaluationType } from '../types';
import { ProcurementService, AuthService } from '../services/mockService';
import { Button, Card, Input, SignaturePad } from './SharedComponents';
import { DocumentTemplate } from './DocumentTemplate';
import { Plus, Check, FileText, Printer, ArrowRight, X, DollarSign, Users, AlertCircle, CreditCard } from 'lucide-react';

export const ProcurementModule: React.FC = () => {
  const [requests, setRequests] = useState<ProcurementWorkflow[]>([]);
  const [currentUser, setCurrentUser] = useState<User>(AuthService.getCurrentUser());
  const [view, setView] = useState<'LIST' | 'CREATE' | 'DETAIL'>('LIST');
  const [selectedRequest, setSelectedRequest] = useState<ProcurementWorkflow | null>(null);
  const [isPrintMode, setIsPrintMode] = useState(false);

  // Form State
  const [section, setSection] = useState(currentUser.department);
  const [requiredDate, setRequiredDate] = useState('');
  const [remarks, setRemarks] = useState('');
  const [newItemDesc, setNewItemDesc] = useState('');
  const [newItemQty, setNewItemQty] = useState(1);
  const [requestItems, setRequestItems] = useState<{description: string, quantity: number}[]>([]);
  const [signature, setSignature] = useState('');

  // Issue Stock Modal State
  const [showIssueModal, setShowIssueModal] = useState(false);
  const [issueDetails, setIssueDetails] = useState({ receiverName: '', receiverDept: '', remarks: '' });

  // Evaluation Modal State
  const [showEvalModal, setShowEvalModal] = useState(false);
  const [evalType, setEvalType] = useState<EvaluationType>('FORM');
  const [evalData, setEvalData] = useState({
    method: EvaluationMethod.EMAIL,
    vendors: [
      { vendorName: '', quoteNumber: '', quoteDate: '', price: 0, selected: false },
      { vendorName: '', quoteNumber: '', quoteDate: '', price: 0, selected: false },
      { vendorName: '', quoteNumber: '', quoteDate: '', price: 0, selected: false }
    ]
  });

  // Single Source Modal State
  const [showSingleSourceModal, setShowSingleSourceModal] = useState(false);
  const [singleSourceData, setSingleSourceData] = useState({ justification: '', vendorName: '', estimatedPrice: 0 });

  // Budget Modal State
  const [showBudgetModal, setShowBudgetModal] = useState(false);
  const [budgetCode, setBudgetCode] = useState('');

  const sections = ['Administration', 'Finance', 'Human Resources', 'IT / Technical', 'Operations', 'Logistics', 'Executive Office'];

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    const data = await ProcurementService.getAll();
    setRequests(data);
  };

  const handleCreateRequest = async () => {
    if (requestItems.length === 0) return;

    await ProcurementService.create({
      requestType: 'GOODS',
      status: ProcurementStatus.SUBMITTED,
      requesterId: currentUser.id,
      requesterName: currentUser.name,
      requesterDepartment: currentUser.department,
      section: section,
      requestDate: new Date().toISOString(),
      requiredDate: requiredDate || new Date().toISOString(),
      remarks: remarks,
      items: requestItems,
      requesterSignature: signature
    });

    setView('LIST');
    resetForm();
    loadData();
  };

  const resetForm = () => {
    setRequestItems([]);
    setSignature('');
    setSection(currentUser.department);
    setRequiredDate('');
    setRemarks('');
    setNewItemDesc('');
    setNewItemQty(1);
  };

  const updateStatus = async (id: string, status: ProcurementStatus, log: string, extraUpdates = {}) => {
    await ProcurementService.updateStatus(id, status, log, currentUser.name, extraUpdates);
    refreshSelection(id);
  };

  const refreshSelection = async (id: string) => {
    const updated = await ProcurementService.getAll();
    const found = updated.find(r => r.id === id);
    setSelectedRequest(found || null);
    loadData();
  };

  const addItemToRequest = () => {
    if(!newItemDesc) return;
    setRequestItems([...requestItems, { description: newItemDesc, quantity: newItemQty }]);
    setNewItemDesc('');
    setNewItemQty(1);
  };

  const handleIssueStock = async () => {
    if (!selectedRequest) return;
    await updateStatus(selectedRequest.id, ProcurementStatus.ISSUED, 'Items Issued from Stock', { 
      stockKeeperSignature: 'signed', 
      stockCheckDate: new Date().toISOString(),
      issueDetails: {
        receiverName: issueDetails.receiverName,
        receiverDepartment: issueDetails.receiverDept,
        issueDate: new Date().toISOString(),
        remarks: issueDetails.remarks
      }
    });
    setShowIssueModal(false);
  };

  const handleSaveEvaluation = async () => {
    if (!selectedRequest) return;

    // Auto-select cheapest
    const sortedVendors = [...evalData.vendors].map(v => ({...v, selected: false}));
    // Filter out empty vendors
    const activeVendors = sortedVendors.filter(v => v.vendorName && v.price > 0);

    if (activeVendors.length > 0) {
       // Find min price
       const minPrice = Math.min(...activeVendors.map(v => v.price));
       const cheapestIndex = sortedVendors.findIndex(v => v.price === minPrice && v.vendorName);
       if (cheapestIndex >= 0) {
         sortedVendors[cheapestIndex].selected = true;
       }
    }

    // Move to BUDGET_CHECK
    await updateStatus(selectedRequest.id, ProcurementStatus.BUDGET_CHECK, 'Price Evaluation Completed - Pending Budget', {
      evaluationMethod: evalData.method,
      evaluationType: evalType,
      quotations: sortedVendors,
    });
    setShowEvalModal(false);
  };

  const handleSingleSourceSubmit = async () => {
    if (!selectedRequest) return;
    // Move to BUDGET_CHECK
    await updateStatus(selectedRequest.id, ProcurementStatus.BUDGET_CHECK, 'Single Source Justification Added - Pending Budget', {
      evaluationType: 'SINGLE_SOURCE',
      singleSourceJustification: singleSourceData.justification,
      selectedVendor: singleSourceData.vendorName,
      quotations: [{ vendorName: singleSourceData.vendorName, price: singleSourceData.estimatedPrice, selected: true }],
    });
    setShowSingleSourceModal(false);
  };

  const handleBudgetApproval = async () => {
    if (!selectedRequest || !budgetCode) return;

    // Generate PO Number and Move to PO_ISSUED
    const poNumber = `PO/${new Date().getFullYear()}/${Math.floor(Math.random()*10000).toString().padStart(4, '0')}`;
    const selectedVendor = selectedRequest.quotations?.find(q => q.selected)?.vendorName || 'Unknown Vendor';

    await updateStatus(selectedRequest.id, ProcurementStatus.PO_ISSUED, 'Budget Confirmed & PO Generated', {
      budgetCode: budgetCode,
      budgetVerifiedDate: new Date().toISOString(),
      poNumber: poNumber,
      selectedVendor: selectedVendor
    });
    setShowBudgetModal(false);
  };

  const renderStatusBadge = (status: ProcurementStatus) => {
    const colors = {
      [ProcurementStatus.DRAFT]: 'bg-slate-100 text-slate-800',
      [ProcurementStatus.SUBMITTED]: 'bg-blue-100 text-blue-800',
      [ProcurementStatus.APPROVED]: 'bg-green-100 text-green-800',
      [ProcurementStatus.REJECTED]: 'bg-red-100 text-red-800',
      [ProcurementStatus.ISSUED]: 'bg-purple-100 text-purple-800',
      [ProcurementStatus.PROCUREMENT_NEEDED]: 'bg-orange-100 text-orange-800',
      [ProcurementStatus.PR_CREATED]: 'bg-indigo-100 text-indigo-800',
      [ProcurementStatus.EVALUATION]: 'bg-pink-100 text-pink-800',
      [ProcurementStatus.BUDGET_CHECK]: 'bg-yellow-100 text-yellow-800',
      [ProcurementStatus.PO_ISSUED]: 'bg-teal-100 text-teal-800',
      [ProcurementStatus.COMPLETED]: 'bg-emerald-100 text-emerald-800',
    };
    return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${colors[status] || 'bg-slate-100'}`}>{status}</span>;
  };

  const getDocumentType = (status: ProcurementStatus) => {
    if (status === ProcurementStatus.PO_ISSUED) return 'PO';
    if (status === ProcurementStatus.EVALUATION || status === ProcurementStatus.BUDGET_CHECK) return 'PEF';
    if (status === ProcurementStatus.PR_CREATED || status === ProcurementStatus.PROCUREMENT_NEEDED) return 'PRF';
    return 'GSRF';
  };

  if (view === 'CREATE') {
    return (
      <Card title="New Goods & Service Requisition Form (GSRF)">
        <div className="space-y-6 max-w-3xl">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Select Section</label>
                <select 
                  className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                  value={section}
                  onChange={e => setSection(e.target.value)}
                >
                  <option value="">-- Select Section --</option>
                  {sections.map(s => <option key={s} value={s}>{s}</option>)}
                </select>
             </div>
             <Input 
               type="date" 
               label="Required Date" 
               value={requiredDate} 
               onChange={e => setRequiredDate(e.target.value)} 
             />
          </div>

          <div>
             <label className="block text-sm font-medium text-slate-700 mb-1">Remarks / Purpose of Use</label>
             <textarea 
               className="flex w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-gov-500 h-24 resize-none"
               placeholder="Enter use case or details..."
               value={remarks}
               onChange={e => setRemarks(e.target.value)}
             />
          </div>

          <div className="bg-slate-50 p-4 rounded-md border border-slate-200">
            <h3 className="text-sm font-medium mb-2">Add Items</h3>
            <div className="flex gap-2 mb-2">
              <Input 
                placeholder="Item Description" 
                value={newItemDesc} 
                onChange={e => setNewItemDesc(e.target.value)} 
                className="flex-1 mb-0"
              />
              <Input 
                type="number" 
                placeholder="Qty" 
                value={newItemQty} 
                onChange={e => setNewItemQty(parseInt(e.target.value) || 1)} 
                className="w-24 mb-0"
                min={1}
              />
              <Button onClick={addItemToRequest} size="sm" icon={Plus} type="button">Add</Button>
            </div>
            <ul className="text-sm space-y-1">
              {requestItems.map((item, idx) => (
                <li key={idx} className="flex justify-between border-b border-slate-200 py-1">
                  <span>{item.description}</span>
                  <span className="font-mono">{item.quantity}</span>
                </li>
              ))}
              {requestItems.length === 0 && <li className="text-slate-400 italic">No items added yet.</li>}
            </ul>
          </div>

          <SignaturePad onChange={setSignature} label="Requester Signature" />

          <div className="flex justify-end gap-2 pt-4">
            <Button variant="outline" onClick={() => { setView('LIST'); resetForm(); }}>Cancel</Button>
            <Button disabled={requestItems.length === 0 || !signature} onClick={handleCreateRequest}>Submit Request</Button>
          </div>
        </div>
      </Card>
    );
  }

  if (view === 'DETAIL' && selectedRequest) {
    const r = selectedRequest;
    return (
      <div className="space-y-6">
        <div className="flex justify-between items-center">
          <Button variant="outline" onClick={() => { setView('LIST'); setIsPrintMode(false); }} icon={ArrowRight} className="rotate-180">Back</Button>
          <div className="flex gap-2">
            {!isPrintMode && <Button variant="secondary" icon={Printer} onClick={() => { setIsPrintMode(true); setTimeout(() => window.print(), 100); }}>Print / Preview</Button>}
            {isPrintMode && <Button variant="outline" onClick={() => setIsPrintMode(false)}>Close Preview</Button>}
          </div>
        </div>

        {isPrintMode ? (
          <div className="border border-slate-300 bg-slate-100 p-8 flex justify-center">
            <DocumentTemplate type={getDocumentType(r.status) as any} data={r} />
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <div className="lg:col-span-2 space-y-6">
              <Card title={`Request #${r.gsrfRefNumber || r.id.toUpperCase()}`}>
                <div className="flex justify-between mb-4">
                  <div>
                    <p className="text-sm text-slate-500">Requester</p>
                    <p className="font-medium">{r.requesterName} ({r.section || r.requesterDepartment})</p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm text-slate-500">Status</p>
                    {renderStatusBadge(r.status)}
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4 mb-4 text-sm">
                   <div>
                     <span className="text-slate-500 block">Date Submitted</span>
                     <span>{new Date(r.requestDate).toLocaleDateString()}</span>
                   </div>
                   <div>
                     <span className="text-slate-500 block">Required By</span>
                     <span>{r.requiredDate ? new Date(r.requiredDate).toLocaleDateString() : 'N/A'}</span>
                   </div>
                   <div className="col-span-2">
                     <span className="text-slate-500 block">Remarks</span>
                     <p className="bg-slate-50 p-2 rounded border border-slate-100">{r.remarks || 'No remarks provided.'}</p>
                   </div>
                </div>

                <div className="mt-4">
                  <h4 className="text-sm font-medium border-b border-slate-100 pb-2 mb-2">Items Requested</h4>
                  {r.items.map((item, i) => (
                    <div key={i} className="flex justify-between py-2 border-b border-slate-50 text-sm">
                      <span>{item.description}</span>
                      <span className="font-mono bg-slate-100 px-2 rounded">{item.quantity}</span>
                    </div>
                  ))}
                </div>
                {r.issueDetails && (
                  <div className="mt-4 bg-purple-50 p-3 rounded border border-purple-100">
                     <h4 className="text-sm font-bold text-purple-800 mb-2">Issue Details</h4>
                     <p className="text-sm">Issued To: {r.issueDetails.receiverName} ({r.issueDetails.receiverDepartment})</p>
                     <p className="text-sm">Date: {new Date(r.issueDetails.issueDate).toLocaleDateString()}</p>
                     <p className="text-sm italic">"{r.issueDetails.remarks}"</p>
                  </div>
                )}

                {/* Single Source Display */}
                {r.evaluationType === 'SINGLE_SOURCE' && r.singleSourceJustification && (
                  <div className="mt-4 bg-teal-50 p-3 rounded border border-teal-100">
                     <h4 className="text-sm font-bold text-teal-800 mb-2">Single Source Procurement</h4>
                     <p className="text-sm"><span className="font-semibold">Selected Vendor:</span> {r.quotations?.[0]?.vendorName}</p>
                     <p className="text-sm mt-1"><span className="font-semibold">Justification:</span> {r.singleSourceJustification}</p>
                  </div>
                )}

                {/* Standard Evaluation Display */}
                {r.evaluationType !== 'SINGLE_SOURCE' && r.evalRefNumber && (
                  <div className="mt-4 bg-pink-50 p-3 rounded border border-pink-100">
                     <h4 className="text-sm font-bold text-pink-800 mb-2">Price Evaluation ({r.evalRefNumber})</h4>
                     <p className="text-sm">Method: {r.evaluationMethod} | Type: {r.evaluationType || 'FORM'}</p>
                     <div className="flex gap-4 mt-2 overflow-x-auto">
                       {r.quotations?.map((q, i) => (
                         <div key={i} className={`p-2 border rounded text-xs min-w-[120px] ${q.selected ? 'bg-green-100 border-green-300 shadow-sm' : 'bg-white'}`}>
                           {q.selected && <div className="text-green-700 font-bold mb-1 text-[10px] uppercase">✓ Best Offer</div>}
                           <p className="font-bold">{q.vendorName}</p>
                           {q.quoteNumber && <p className="text-[10px] text-slate-500">#{q.quoteNumber}</p>}
                           <p className="mt-1 font-mono">${(q.price || 0).toFixed(2)}</p>
                         </div>
                       ))}
                     </div>
                  </div>
                )}

                {/* PO Display */}
                {r.status === ProcurementStatus.PO_ISSUED && (
                   <div className="mt-4 bg-teal-50 p-3 rounded border border-teal-100">
                      <h4 className="text-sm font-bold text-teal-800 mb-2 flex items-center"><Check className="w-4 h-4 mr-1"/> Purchase Order Generated</h4>
                      <p className="text-sm"><span className="font-bold">PO Number:</span> {r.poNumber}</p>
                      <p className="text-sm"><span className="font-bold">Budget Code:</span> {r.budgetCode}</p>
                      <p className="text-sm"><span className="font-bold">Vendor:</span> {r.quotations?.find(q => q.selected)?.vendorName}</p>
                   </div>
                )}
              </Card>

              {/* Workflow Actions */}
              {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.SUBMITTED && (
                <Card title="Stock Keeper Action">
                  <p className="text-sm text-slate-600 mb-4">Check stock availability for requested items.</p>
                  <div className="flex gap-4">
                    <Button 
                      className="flex-1"
                      onClick={() => setShowIssueModal(true)}
                    >
                      <Check className="mr-2 h-4 w-4" /> Available - Issue Stock
                    </Button>
                    <Button 
                      className="flex-1"
                      variant="secondary"
                      onClick={() => updateStatus(r.id, ProcurementStatus.PROCUREMENT_NEEDED, 'Marked for Procurement', { stockKeeperSignature: 'signed', stockCheckDate: new Date().toISOString(), gsrfRefNumber: r.gsrfRefNumber })}
                    >
                      <X className="mr-2 h-4 w-4" /> Not Available - Create PR
                    </Button>
                  </div>
                </Card>
              )}

              {/* Issue Stock Modal */}
              {showIssueModal && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                  <div className="bg-white p-6 rounded-lg w-full max-w-md">
                    <h3 className="text-lg font-bold mb-4">Issue Stock Details</h3>
                    <Input label="Receiver Name" value={issueDetails.receiverName} onChange={e => setIssueDetails({...issueDetails, receiverName: e.target.value})} />
                    <Input label="Receiver Department" value={issueDetails.receiverDept} onChange={e => setIssueDetails({...issueDetails, receiverDept: e.target.value})} />
                    <Input label="Remarks / Purpose" value={issueDetails.remarks} onChange={e => setIssueDetails({...issueDetails, remarks: e.target.value})} />
                    <div className="flex justify-end gap-2 mt-4">
                      <Button variant="outline" onClick={() => setShowIssueModal(false)}>Cancel</Button>
                      <Button onClick={handleIssueStock} disabled={!issueDetails.receiverName}>Confirm Issue</Button>
                    </div>
                  </div>
                </div>
              )}

               {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PROCUREMENT_NEEDED && (
                <Card title="Procurement Processing">
                  <p className="text-sm text-slate-600 mb-4">Convert this request into a formal Purchase Request.</p>
                  <Button 
                    onClick={() => updateStatus(r.id, ProcurementStatus.PR_CREATED, 'Purchase Request Created', { prRefNumber: `PR/${new Date().getFullYear()}/${Math.floor(Math.random()*1000)}` })}
                  >
                    Generate Purchase Request (PR)
                  </Button>
                </Card>
              )}

              {/* PR Created -> Start Evaluation */}
              {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PR_CREATED && (
                <Card title="Procurement Action">
                  <p className="text-sm text-slate-600 mb-4">Choose procurement method.</p>
                  <div className="flex flex-col gap-3">
                    <Button 
                      onClick={() => setShowEvalModal(true)}
                    >
                      <DollarSign className="mr-2 h-4 w-4" /> Start Price Evaluation
                    </Button>
                    <Button 
                      variant="outline"
                      onClick={() => setShowSingleSourceModal(true)}
                    >
                      <AlertCircle className="mr-2 h-4 w-4" /> Single Source Procurement
                    </Button>
                  </div>
                </Card>
              )}

              {/* Budget Verification Action */}
              {(currentUser.role === UserRole.STOCK_KEEPER || currentUser.role === UserRole.FINANCE_OFFICER) && r.status === ProcurementStatus.BUDGET_CHECK && (
                 <Card title="Budget Verification">
                    <p className="text-sm text-slate-600 mb-4">Verify budget availability and assign a Budget Code to generate the Purchase Order (PO).</p>
                    <div className="flex justify-end">
                       <Button onClick={() => setShowBudgetModal(true)} icon={CreditCard}>Verify Budget & Issue PO</Button>
                    </div>
                 </Card>
              )}

              {/* Budget Modal */}
              {showBudgetModal && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                  <div className="bg-white p-6 rounded-lg w-full max-w-sm">
                    <h3 className="text-lg font-bold mb-4">Budget Confirmation</h3>
                    <p className="text-sm text-slate-600 mb-4">Please enter the confirmed Budget Code.</p>
                    <Input label="Budget Code" value={budgetCode} onChange={e => setBudgetCode(e.target.value)} placeholder="e.g. BGT-2024-001" />
                    <div className="flex justify-end gap-2 mt-4">
                      <Button variant="outline" onClick={() => setShowBudgetModal(false)}>Cancel</Button>
                      <Button onClick={handleBudgetApproval} disabled={!budgetCode}>Approve & Generate PO</Button>
                    </div>
                  </div>
                </div>
              )}

              {/* Single Source Modal */}
              {showSingleSourceModal && (
                 <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                  <div className="bg-white p-6 rounded-lg w-full max-w-lg">
                    <h3 className="text-lg font-bold mb-4">Single Source Procurement</h3>
                    <p className="text-sm text-slate-600 mb-4">Skip price evaluation for special cases. This requires justification.</p>

                    <Input 
                      label="Vendor Name" 
                      value={singleSourceData.vendorName} 
                      onChange={e => setSingleSourceData({...singleSourceData, vendorName: e.target.value})} 
                    />
                    <Input 
                      type="number" 
                      label="Total Estimated Price" 
                      value={singleSourceData.estimatedPrice} 
                      onChange={e => setSingleSourceData({...singleSourceData, estimatedPrice: parseFloat(e.target.value) || 0})} 
                    />
                    <div className="mb-4">
                       <label className="block text-sm font-medium text-slate-700 mb-1">Justification</label>
                       <textarea 
                         className="w-full border p-2 rounded text-sm h-24"
                         placeholder="Explain why single source is necessary..."
                         value={singleSourceData.justification}
                         onChange={e => setSingleSourceData({...singleSourceData, justification: e.target.value})}
                       />
                    </div>

                    <div className="flex justify-end gap-2 mt-4">
                      <Button variant="outline" onClick={() => setShowSingleSourceModal(false)}>Cancel</Button>
                      <Button onClick={handleSingleSourceSubmit} disabled={!singleSourceData.justification || !singleSourceData.vendorName}>Confirm</Button>
                    </div>
                  </div>
                </div>
              )}

              {/* Evaluation Modal */}
              {showEvalModal && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                  <div className="bg-white p-6 rounded-lg w-full max-w-4xl max-h-[90vh] overflow-y-auto">
                    <h3 className="text-lg font-bold mb-4">Price Evaluation Form</h3>

                    <div className="grid grid-cols-2 gap-6 mb-6">
                      <div>
                        <label className="block text-sm font-medium mb-1">Evaluation Method</label>
                        <select 
                          className="w-full border p-2 rounded"
                          value={evalData.method}
                          onChange={e => setEvalData({...evalData, method: e.target.value as EvaluationMethod})}
                        >
                          {Object.values(EvaluationMethod).map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                      </div>
                      <div>
                         <label className="block text-sm font-medium mb-1">Evaluation Type</label>
                         <div className="flex gap-2">
                           <button 
                             className={`px-3 py-2 text-sm rounded border ${evalType === 'FORM' ? 'bg-gov-100 border-gov-500 text-gov-800' : 'bg-white'}`}
                             onClick={() => setEvalType('FORM')}
                           >
                             Form Based (Item Matrix)
                           </button>
                           <button 
                             className={`px-3 py-2 text-sm rounded border ${evalType === 'QUOTATION' ? 'bg-gov-100 border-gov-500 text-gov-800' : 'bg-white'}`}
                             onClick={() => setEvalType('QUOTATION')}
                           >
                             Quotation Based (Totals)
                           </button>
                         </div>
                      </div>
                    </div>

                    <div className="grid grid-cols-3 gap-4 mb-4">
                      {evalData.vendors.map((v, idx) => (
                        <div key={idx} className="border p-3 rounded bg-slate-50 relative">
                          <div className="absolute top-2 right-2 text-xs font-bold text-slate-300">#{idx+1}</div>
                          <h4 className="font-bold text-xs mb-2">Vendor Details</h4>
                          <Input 
                            placeholder="Vendor Name" 
                            value={v.vendorName} 
                            onChange={e => {
                                const newVendors = evalData.vendors.map((vend, i) => i === idx ? {...vend, vendorName: e.target.value} : vend);
                                setEvalData({...evalData, vendors: newVendors});
                            }}
                            className="mb-2"
                          />
                          {evalType === 'QUOTATION' && (
                            <>
                              <Input 
                                placeholder="Quote Number" 
                                value={v.quoteNumber} 
                                onChange={e => {
                                  const newVendors = evalData.vendors.map((vend, i) => i === idx ? {...vend, quoteNumber: e.target.value} : vend);
                                  setEvalData({...evalData, vendors: newVendors});
                                }}
                                className="mb-2"
                              />
                              <Input 
                                type="date"
                                placeholder="Quote Date" 
                                value={v.quoteDate} 
                                onChange={e => {
                                  const newVendors = evalData.vendors.map((vend, i) => i === idx ? {...vend, quoteDate: e.target.value} : vend);
                                  setEvalData({...evalData, vendors: newVendors});
                                }}
                                className="mb-2"
                              />
                            </>
                          )}
                          <Input 
                            type="number"
                            label={evalType === 'FORM' ? "Unit/Total Rate" : "Total Quotation Price"}
                            value={v.price} 
                            onChange={e => {
                              const newVendors = evalData.vendors.map((vend, i) => i === idx ? {...vend, price: parseFloat(e.target.value) || 0} : vend);
                              setEvalData({...evalData, vendors: newVendors});
                            }}
                          />
                        </div>
                      ))}
                    </div>

                    <div className="text-xs text-slate-500 mb-4 bg-yellow-50 p-2 rounded">
                      Note: The system will automatically highlight the vendor with the lowest price as the recommended option.
                    </div>

                    <div className="flex justify-end gap-2 mt-4">
                      <Button variant="outline" onClick={() => setShowEvalModal(false)}>Cancel</Button>
                      <Button onClick={handleSaveEvaluation}>Save Evaluation</Button>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="space-y-6">
               <Card title="Signatures">
                 <div className="space-y-4">
                   <div>
                     <p className="text-xs text-slate-500">Requester</p>
                     {r.requesterSignature ? <img src={r.requesterSignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                   </div>
                   <div>
                     <p className="text-xs text-slate-500">Stock Keeper</p>
                     {r.stockKeeperSignature ? <div className="text-sm font-serif italic text-blue-800">Signed Digitally</div> : <span className="text-xs italic">Pending</span>}
                   </div>
                   {r.budgetVerifiedDate && (
                      <div>
                        <p className="text-xs text-slate-500">Finance Officer</p>
                        <div className="text-sm font-serif italic text-blue-800">Signed Digitally</div>
                      </div>
                   )}
                 </div>
               </Card>

               <Card title="History Log">
                 <ul className="space-y-3 relative border-l border-slate-200 ml-2 pl-4">
                   {r.logs.map((log, i) => (
                     <li key={i} className="text-xs">
                       <div className="absolute w-2 h-2 bg-slate-300 rounded-full -left-[5px] mt-1"></div>
                       <p className="font-semibold text-slate-700">{log.action}</p>
                       <p className="text-slate-500">{new Date(log.date).toLocaleString()} by {log.actor}</p>
                     </li>
                   ))}
                 </ul>
               </Card>
            </div>
          </div>
        )}
      </div>
    );
  };

export enum UserRole {
  USER = 'User',
  SUPERVISOR = 'Supervisor',
  MANAGER = 'Manager',
  FINANCE_OFFICER = 'Finance Officer',
  ADMIN = 'Administrator',
  STOCK_KEEPER = 'Stock Keeper'
}

export enum ItemCategory {
  STATIONERY = '01',
  IT_EQUIPMENT = '02',
  FURNITURE = '03',
  VEHICLES = '04',
  MAINTENANCE = '05'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  department: string;
}

export interface Vendor {
  id: string;
  name: string;
  contactPerson: string;
  email: string;
  phone: string;
  address: string;
  taxId?: string;
  status: 'Active' | 'Blacklisted' | 'Pending';
}

export interface InventoryItem {
  id: string;
  name: string;
  sku?: string;
  // Gov ID: OfficeNumber | Year | CategoryNumber | ItemTypeNumber | ItemNumber
  govId: string;
  category: ItemCategory;
  quantity: number;
  location: string;
  minStockLevel: number;
  pricePerUnit: number;
  lastUpdated: string;
}

export interface Asset {
  id: string;
  name: string;
  govId: string;
  category: ItemCategory;
  condition: 'New' | 'Good' | 'Fair' | 'Poor' | 'Disposal';
  purchaseDate: string;
  price: number;
  location: string;
  assignedTo?: string;
}

export enum ProcurementStatus {
  DRAFT = 'Draft',
  SUBMITTED = 'Submitted',
  APPROVED = 'Approved',
  REJECTED = 'Rejected',
  ISSUED = 'Issued', // Stock issued locally
  PROCUREMENT_NEEDED = 'Procurement Needed', // Moved to procurement
  PR_CREATED = 'PR Created', // Purchase Request Form generated
  EVALUATION = 'Evaluation', // Price Evaluation Form generated
  BUDGET_CHECK = 'Budget Check', // Pending Budget Code
  PO_ISSUED = 'PO Issued',
  COMPLETED = 'Completed'
}

export enum EvaluationMethod {
  EMAIL = 'Email',
  PHONE = 'Phone',
  VISITING = 'Visiting'
}

export type EvaluationType = 'FORM' | 'QUOTATION' | 'SINGLE_SOURCE';

export interface ProcurementWorkflow {
  id: string;
  requestType: 'GOODS' | 'SERVICE';
  status: ProcurementStatus;

  // Step 1: Request
  requesterId: string;
  requesterName: string;
  requesterDepartment: string;
  section?: string;
  requestDate: string;
  requiredDate?: string;
  remarks?: string; // Purpose / Use case
  items: {
    itemId?: string; // If existing inventory item
    description: string;
    quantity: number;
    estimatedCost?: number;
  }[];
  requesterSignature?: string;

  // Step 2: Stock Keeper Check / GSRF
  gsrfRefNumber?: string;
  stockKeeperSignature?: string;
  stockCheckDate?: string;

  // Step 2a: Issue Process (If Available)
  issueDetails?: {
    receiverName: string;
    receiverDepartment: string;
    issueDate: string;
    remarks: string;
  };

  // Step 3: Purchase Request (if not in stock)
  prRefNumber?: string;
  authorizedBySignature?: string;

  // Step 4: Price Eval
  evalRefNumber?: string; // Format: (A)263/YYYY/Counter
  evaluationMethod?: EvaluationMethod;
  evaluationType?: EvaluationType;
  singleSourceJustification?: string;
  quotations?: {
    vendorName: string;
    quoteNumber?: string;
    quoteDate?: string;
    price: number;
    selected: boolean;
  }[];

  // Step 4.5: Budget
  budgetCode?: string;
  budgetVerifiedDate?: string;

  // Step 5: PO
  poNumber?: string;
  selectedVendor?: string;

  // Logs
  logs: {
    date: string;
    action: string;
    actor: string;
  }[];
}

export const OFFICE_CODE = "263";

import { InventoryItem, Asset, ProcurementWorkflow, User, UserRole, ItemCategory, OFFICE_CODE, ProcurementStatus, Vendor } from '../types';

// Initial Mock Data
const MOCK_USERS: User[] = [
  { id: 'u1', name: 'John Doe', role: UserRole.USER, department: 'Finance' },
  { id: 'u2', name: 'Jane Smith', role: UserRole.STOCK_KEEPER, department: 'Logistics' },
  { id: 'u3', name: 'Robert Chief', role: UserRole.MANAGER, department: 'Finance' },
  { id: 'u4', name: 'Admin User', role: UserRole.ADMIN, department: 'IT' },
  { id: 'u5', name: 'Sarah Supervisor', role: UserRole.SUPERVISOR, department: 'HR' },
  { id: 'u6', name: 'Frank Finance', role: UserRole.FINANCE_OFFICER, department: 'Finance' },
