export const ProcurementService = {
  getAll: () => Promise.resolve([...MOCK_REQUESTS]),
  create: (req: Omit<ProcurementWorkflow, 'id' | 'logs' | 'gsrfRefNumber'>) => {
    const year = new Date().getFullYear();
    const count = MOCK_REQUESTS.length + 407; // Starting counter from user example
    // Format: (RF)/OfficeCode/Year/Count
    const gsrfRefNumber = `(RF)/${OFFICE_CODE}/${year}/${count}`;

    const newReq: ProcurementWorkflow = { 
      ...req, 
      id: Math.random().toString(36).substr(2, 9),
      gsrfRefNumber,
      logs: [{ date: new Date().toISOString(), action: 'Request Submitted', actor: req.requesterName }]
    };
    MOCK_REQUESTS.push(newReq);
    return Promise.resolve(newReq);
  },
  updateStatus: (id: string, status: ProcurementStatus, logEntry: string, actor: string, updates?: Partial<ProcurementWorkflow>) => {
    const req = MOCK_REQUESTS.find(r => r.id === id);
    if (req) {
      // Auto-generate Evaluation ID if moving to EVALUATION status and ID doesn't exist
      if (status === ProcurementStatus.EVALUATION && !req.evalRefNumber) {
         const year = new Date().getFullYear();
         // Simulate finding the next counter. In real app, query DB.
         const count = 45; // Based on prompt example
         req.evalRefNumber = `(A)${OFFICE_CODE}/${year}/${count}`;
      }

      req.status = status;
      req.logs.push({ date: new Date().toISOString(), action: logEntry, actor });
      if (updates) Object.assign(req, updates);
    }
    return Promise.resolve(req);
  }
};

