      const allLogs = requests.flatMap(r => r.logs.map(log => ({
        ...log,
        requestId: r.id,
        refNumber: r.gsrfRefNumber
      }))).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
      setLogs(allLogs);
