                {/* Single Source Display */}
                {r.evaluationType === 'SINGLE_SOURCE' && r.singleSourceJustification && (
                  <div className="mt-4 bg-teal-50 p-3 rounded border border-teal-100">
                     <h4 className="text-sm font-bold text-teal-800 mb-2">Single Source Procurement</h4>
                     <p className="text-sm"><span className="font-semibold">Selected Vendor:</span> {r.quotations?.[0]?.vendorName}</p>
                     <p className="text-sm mt-1"><span className="font-semibold">Justification:</span> {r.singleSourceJustification}</p>
                  </div>
                )}

                {/* Standard Evaluation Display */}
                {r.evaluationType !== 'SINGLE_SOURCE' && r.evalRefNumber && (
                  <div className="mt-4 bg-pink-50 p-3 rounded border border-pink-100">
                     <h4 className="text-sm font-bold text-pink-800 mb-2">Price Evaluation ({r.evalRefNumber})</h4>
                     <p className="text-sm">Method: {r.evaluationMethod} | Type: {r.evaluationType || 'FORM'}</p>
                     <div className="flex gap-4 mt-2 overflow-x-auto">
                       {r.quotations?.map((q, i) => (
                         <div key={i} className={`p-2 border rounded text-xs min-w-[120px] ${q.selected ? 'bg-green-100 border-green-300 shadow-sm' : 'bg-white'}`}>
                           {q.selected && <div className="text-green-700 font-bold mb-1 text-[10px] uppercase">✓ Best Offer</div>}
                           <p className="font-bold">{q.vendorName}</p>
                           {q.quoteNumber && <p className="text-[10px] text-slate-500">#{q.quoteNumber}</p>}
                           <p className="mt-1 font-mono">${(q.price || 0).toFixed(2)}</p>
                         </div>
                       ))}
                     </div>
                  </div>
                )}

                {/* PO Display */}
                {(r.status === ProcurementStatus.PO_ISSUED || r.status === ProcurementStatus.COMPLETED) && (
                   <div className="mt-4 bg-teal-50 p-3 rounded border border-teal-100">
                      <h4 className="text-sm font-bold text-teal-800 mb-2 flex items-center"><Check className="w-4 h-4 mr-1"/> Purchase Order Generated</h4>
                      <p className="text-sm"><span className="font-bold">PO Number:</span> {r.poNumber}</p>
                      <p className="text-sm"><span className="font-bold">Budget Code:</span> {r.budgetCode}</p>
