                                }}
                                className="mb-2"
                              />
                              <Input 
                                type="date"
                                placeholder="Quote Date" 
                                value={v.quoteDate} 
                                onChange={e => {
                                  const newVendors = evalData.vendors.map((vend, i) => i === idx ? {...vend, quoteDate: e.target.value} : vend);
