        {activeSection === 'TEMPLATE' && (
           <Card title="Template Management">
              <p className="text-sm text-slate-500 mb-6">Configure the standard text appearing on generated documents.</p>

              <div className="space-y-6">
                 <div className="flex items-center gap-2 mb-4">
                    <input 
                      type="checkbox" 
                      id="showLogo"
                      checked={settings.templateConfig.showLogo}
                      onChange={e => setSettings({...settings, templateConfig: {...settings.templateConfig, showLogo: e.target.checked}})}
                      className="w-4 h-4 text-gov-600 rounded border-slate-300 focus:ring-gov-500"
                    />
                    <label htmlFor="showLogo" className="text-sm font-medium text-slate-700">Show Logo on Documents</label>
                 </div>

                 <Input 
                   label="Default Header Text" 
                   value={settings.templateConfig.headerText || ''} 
                   onChange={e => setSettings({...settings, templateConfig: {...settings.templateConfig, headerText: e.target.value}})} 
                   placeholder="e.g. Official Document"
                 />

                 <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">Standard Footer Text / Disclaimer</label>
                    <textarea 
                      className="flex w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500 h-24 resize-none"
                      value={settings.templateConfig.footerText || ''}
                      onChange={e => setSettings({...settings, templateConfig: {...settings.templateConfig, footerText: e.target.value}})}
                    />
                 </div>

                 <div className="bg-slate-50 p-4 border rounded text-xs text-slate-500">
                    <p>Preview of footer:</p>
                    <div className="mt-2 pt-2 border-t border-slate-200 text-center italic">
                       {settings.templateConfig.footerText}
                    </div>
                 </div>

                 <div className="flex justify-end pt-4">
                    <Button onClick={handleSave} icon={Save} disabled={isSaving}>
                       {isSaving ? 'Saving...' : 'Save Template Config'}
                    </Button>
                 </div>
              </div>
           </Card>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { ProcurementWorkflow, SystemSettings } from '../types';

interface DocumentTemplateProps {
