        {showUserModal && editingUser && (
           <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
             <div className="bg-white p-6 rounded-lg w-full max-w-lg">
                <h3 className="text-lg font-bold mb-4">{editingUser.id ? 'Edit User' : 'Add New User'}</h3>

                <div className="space-y-4">
                   <div className="grid grid-cols-2 gap-4">
                      <Input 
                        label="Full Name" 
                        value={editingUser.name} 
                        onChange={e => setEditingUser({...editingUser, name: e.target.value})}
                      />
                      <Input 
                        label="Email Address" 
                        value={editingUser.email} 
                        onChange={e => setEditingUser({...editingUser, email: e.target.value})}
                      />
                   </div>
                   <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">Role</label>
                        <select 
                          className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm"
                          value={editingUser.role}
                          onChange={e => setEditingUser({...editingUser, role: e.target.value as UserRole})}
                        >
                          {Object.values(UserRole).map(r => <option key={r} value={r}>{r}</option>)}
                        </select>
                      </div>
                      <Input 
                        label="Department" 
                        value={editingUser.department} 
                        onChange={e => setEditingUser({...editingUser, department: e.target.value})}
                      />
                   </div>

                   {editingUser.id && (
                     <div className="border-t pt-4 mt-2">
                       <div className="flex items-center gap-2 mb-2">
                          <input 
                            type="checkbox" 
                            id="resetPass"
                            checked={passwordResetMode}
                            onChange={e => setPasswordResetMode(e.target.checked)}
                            className="w-4 h-4 text-gov-600 rounded border-slate-300"
                          />
                          <label htmlFor="resetPass" className="text-sm font-medium text-slate-700 flex items-center gap-1">
                             <Lock className="w-3 h-3" /> Reset Password
                          </label>
                       </div>
                       {passwordResetMode && (
                          <Input 
                             type="password"
                             label="New Password"
                             value={newPassword}
                             onChange={e => setNewPassword(e.target.value)}
                             placeholder="Enter new password"
                          />
                       )}
                     </div>
                   )}
                </div>

                <div className="flex justify-end gap-2 mt-6">
                   <Button variant="outline" onClick={() => setShowUserModal(false)}>Cancel</Button>
                   <Button onClick={handleSaveUser}>Save User</Button>
                </div>
             </div>
           </div>
        )}
      </div>
    </div>
  );
};

export enum UserRole {
  USER = 'User',
  SUPERVISOR = 'Supervisor',
  MANAGER = 'Manager',
  FINANCE_OFFICER = 'Finance Officer',
  ADMIN = 'Administrator',
  STOCK_KEEPER = 'Stock Keeper'
}

export enum ItemCategory {
  STATIONERY = '01',
  IT_EQUIPMENT = '02',
  FURNITURE = '03',
  VEHICLES = '04',
  MAINTENANCE = '05'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  department: string;
}

export interface Vendor {
  id: string;
  name: string;
  contactPerson: string;
  email: string;
  phone: string;
  address: string;
  taxId?: string;
  status: 'Active' | 'Blacklisted' | 'Pending';
}

export interface InventoryItem {
  id: string;
  name: string;
  sku?: string;
  // Gov ID: OfficeNumber | Year | CategoryNumber | ItemTypeNumber | ItemNumber
  govId: string;
  category: ItemCategory;
  quantity: number;
  location: string;
  minStockLevel: number;
  pricePerUnit: number;
  lastUpdated: string;
}

export interface Asset {
  id: string;
  name: string;
  govId: string;
  category: ItemCategory;
  condition: 'New' | 'Good' | 'Fair' | 'Poor' | 'Disposal';
  purchaseDate: string;
  price: number;
  location: string;
  assignedTo?: string;
}

export enum ProcurementStatus {
  DRAFT = 'Draft',
  SUBMITTED = 'Submitted',
  APPROVED = 'Approved',
  REJECTED = 'Rejected',
  ISSUED = 'Issued', // Stock issued locally
  PROCUREMENT_NEEDED = 'Procurement Needed', // Moved to procurement
  PR_CREATED = 'PR Created', // Purchase Request Form generated
  EVALUATION = 'Evaluation', // Price Evaluation Form generated
  BUDGET_CHECK = 'Budget Check', // Pending Budget Code
  PO_ISSUED = 'PO Issued',
  COMPLETED = 'Completed'
}

export enum EvaluationMethod {
  EMAIL = 'Email',
  PHONE = 'Phone',
  VISITING = 'Visiting'
}

export type EvaluationType = 'FORM' | 'QUOTATION' | 'SINGLE_SOURCE';

export interface SystemSettings {
  officeName: string;
  officeAddress: string;
  officeCode: string;
  departmentName: string;
  logoUrl?: string;
  prefixes: {
    gsrf: string;
    pr: string;
    po: string;
    asset: string;
    inventory: string;
  };
  templateConfig: {
    headerText?: string;
    footerText?: string;
    showLogo: boolean;
  }
}

export interface ProcurementWorkflow {
  id: string;
  requestType: 'GOODS' | 'SERVICE';
  status: ProcurementStatus;

  // Step 1: Request
  requesterId: string;
  requesterName: string;
  requesterDepartment: string;
  section?: string;
  requestDate: string;
  requiredDate?: string;
  remarks?: string; // Purpose / Use case
  items: {
    itemId?: string; // If existing inventory item
    description: string;
    quantity: number;
    estimatedCost?: number;
  }[];
  requesterSignature?: string;

  // Step 2: Stock Keeper Check / GSRF
  gsrfRefNumber?: string;
  stockKeeperSignature?: string;
  stockCheckDate?: string;

  // Step 2a: Issue Process (If Available)
  issueDetails?: {
    receiverName: string;
    receiverDepartment: string;
    issueDate: string;
    remarks: string;
  };

  // Step 3: Purchase Request (if not in stock)
  prRefNumber?: string;
  authorizedBySignature?: string;

  // Step 4: Price Eval
  evalRefNumber?: string; // Format: (A)263/YYYY/Counter
  evaluationMethod?: EvaluationMethod;
  evaluationType?: EvaluationType;
  singleSourceJustification?: string;
  quotations?: {
    vendorName: string;
    quoteNumber?: string;
    quoteDate?: string;
    price: number;
    selected: boolean;
  }[];

  // Step 4.5: Budget
  budgetCode?: string;
  budgetVerifiedDate?: string;

  // Step 5: PO
  poNumber?: string;
  selectedVendor?: string;

  // Logs
  logs: {
    date: string;
    action: string;
    actor: string;
  }[];
}

