                                              setItems(newData);
                                          }}
                                      >
                                          {Object.values(ItemCategory).map(c => <option key={c} value={c}>{c}</option>)}
                                      </select>
                                      <input 
                                          placeholder="Location"
                                          className="w-1/2 border rounded p-1 text-xs"
                                          value={item.newLocation}
                                          onChange={(e) => {
                                              const newData = [...items];
                                              newData[idx].newLocation = e.target.value;
