const generateSKU = (category: ItemCategory) => {
  const prefixMap: Record<string, string> = {
    [ItemCategory.STATIONERY]: 'STA',
    [ItemCategory.IT_EQUIPMENT]: 'IT',
    [ItemCategory.FURNITURE]: 'FUR',
    [ItemCategory.VEHICLES]: 'VEH',
    [ItemCategory.MAINTENANCE]: 'MNT'
  };
  const prefix = prefixMap[category] || 'GEN';
  const randomNum = Math.floor(Math.random() * 9000) + 1000;
  return `${prefix}-${randomNum}`;
};

