export const SettingsView = () => {
  const [currentUser, setCurrentUser] = useState(AuthService.getCurrentUser());
  const [settings, setSettings] = useState<SystemSettings | null>(null);
  const [activeSection, setActiveSection] = useState<'PROFILE' | 'ORG' | 'PREFIXES' | 'TEMPLATE' | 'USERS'>('PROFILE');
  const [isSaving, setIsSaving] = useState(false);

  // Profile & Password State
  const [profileForm, setProfileForm] = useState({
    name: '',
    email: '',
    designation: '',
    phone: ''
  });
  const [passForm, setPassForm] = useState({ current: '', new: '', confirm: '' });

  // User Management State
  const [users, setUsers] = useState<User[]>([]);
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> | null>(null);
  const [passwordResetMode, setPasswordResetMode] = useState(false);
  const [newPassword, setNewPassword] = useState('');

  useEffect(() => {
    SettingsService.get().then(setSettings);
    UserService.getAll().then(setUsers);

    // Initialize profile form
    setProfileForm({
      name: currentUser.name,
      email: currentUser.email,
      designation: currentUser.designation || '',
      phone: currentUser.phone || ''
    });
  }, [currentUser]); // Refresh if user switches

  const handleSave = async () => {
    if (settings) {
      setIsSaving(true);
      await SettingsService.update(settings);
      // Simulate network delay
      setTimeout(() => setIsSaving(false), 800);
    }
  };

  const handleProfileUpdate = async () => {
     setIsSaving(true);
     const updatedUser = { 
        ...currentUser, 
        name: profileForm.name,
        email: profileForm.email,
        designation: profileForm.designation,
        phone: profileForm.phone
     };
     await UserService.update(updatedUser);
     setCurrentUser(updatedUser);
     setIsSaving(false);
     alert("Profile updated successfully.");
  };

  const handlePasswordChange = async () => {
     if (!passForm.current || !passForm.new || !passForm.confirm) {
        alert("Please fill all password fields.");
        return;
     }
     if (passForm.new !== passForm.confirm) {
        alert("New passwords do not match.");
        return;
     }
     setIsSaving(true);
     await UserService.changePassword(currentUser.id, passForm.current, passForm.new);
     setPassForm({ current: '', new: '', confirm: '' });
     setIsSaving(false);
     alert("Password changed successfully.");
  };

  const handleUserSwitch = (id: string) => {
    const newUser = AuthService.switchUser(id);
    setCurrentUser(newUser);
