import React, { useState, useEffect } from 'react';
import { AuthService, NotificationService } from './services/mockService';
import { AppNotification, AppTab } from './types';
import { LayoutDashboard, Package, Truck, Files, Settings, Menu, ClipboardList, ShoppingCart, Users, Bell } from 'lucide-react';
import { ProcurementModule } from './components/ProcurementModule';
import { DashboardView } from './components/DashboardView';
import { InventoryView } from './components/InventoryView';
import { AssetView } from './components/AssetView';
import { ReportsView } from './components/ReportsView';
import { SettingsView } from './components/SettingsView';
import { VendorManagement } from './components/VendorManagement';

const SidebarItem = ({ icon: Icon, label, active, onClick }: any) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium transition-colors ${
      active ? 'bg-gov-800 text-white' : 'text-slate-300 hover:bg-gov-800 hover:text-white'
    }`}
  >
    <Icon className="w-5 h-5" />
    {label}
  </button>
);

export default function App() {
  const [activeTab, setActiveTab] = useState<AppTab>('DASHBOARD');
  const [targetId, setTargetId] = useState<string | null>(null);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const user = AuthService.getCurrentUser();

  useEffect(() => {
    // Poll for notifications or load on mount
    const loadNotifications = async () => {
      const data = await NotificationService.getAll();
      setNotifications(data);
    };
    loadNotifications();

    // Simple interval to mock real-time updates check (for demo)
    const interval = setInterval(loadNotifications, 5000);
    return () => clearInterval(interval);
  }, [activeTab]); // Also reload when tab changes as actions might have happened

  const markRead = async (e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    await NotificationService.markAllRead();
    setNotifications(await NotificationService.getAll());
  };

  const handleTabChange = (tab: AppTab) => {
    setActiveTab(tab);
    setTargetId(null); // Clear deep link when manually navigating
    setMobileMenuOpen(false);
  };

  const handleNotificationClick = (notification: AppNotification) => {
    if (notification.link) {
        setActiveTab(notification.link.tab);
        if (notification.link.itemId) {
            setTargetId(notification.link.itemId);
        }
    }
    setShowNotifications(false);
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  const renderContent = () => {
    switch (activeTab) {
      case 'DASHBOARD': return <DashboardView />;
      case 'INVENTORY': return <InventoryView />;
      case 'PROCUREMENT': return <ProcurementModule initialRequestId={activeTab === 'PROCUREMENT' ? targetId : null} />;
      case 'ASSETS': return <AssetView />;
      case 'VENDORS': return <VendorManagement />;
      case 'REPORTS': return <ReportsView />;
      case 'SETTINGS': return <SettingsView />;
      default: return <DashboardView />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex font-sans text-slate-900">
      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-gov-900 text-white transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0 ${mobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-6 border-b border-gov-800">
          <h1 className="text-xl font-bold tracking-tight">GovTrack <span className="text-gov-500">System</span></h1>
          <p className="text-xs text-gov-500 mt-1">Entity Inventory & Procurement</p>
        </div>
        <nav className="mt-6 space-y-1">
          <SidebarItem icon={LayoutDashboard} label="Dashboard" active={activeTab === 'DASHBOARD'} onClick={() => handleTabChange('DASHBOARD')} />
          <SidebarItem icon={Package} label="Inventory" active={activeTab === 'INVENTORY'} onClick={() => handleTabChange('INVENTORY')} />
          <SidebarItem icon={Truck} label="Assets" active={activeTab === 'ASSETS'} onClick={() => handleTabChange('ASSETS')} />
          <SidebarItem icon={ShoppingCart} label="Procurement" active={activeTab === 'PROCUREMENT'} onClick={() => handleTabChange('PROCUREMENT')} />
          <SidebarItem icon={Users} label="Vendors" active={activeTab === 'VENDORS'} onClick={() => handleTabChange('VENDORS')} />
          <SidebarItem icon={ClipboardList} label="Audit Reports" active={activeTab === 'REPORTS'} onClick={() => handleTabChange('REPORTS')} />
          <SidebarItem icon={Settings} label="Settings" active={activeTab === 'SETTINGS'} onClick={() => handleTabChange('SETTINGS')} />
        </nav>
        <div className="absolute bottom-0 w-full p-4 bg-gov-950">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-full bg-gov-700 flex items-center justify-center text-xs font-bold">
              {user.name.charAt(0)}
            </div>
            <div>
              <p className="text-sm font-medium">{user.name}</p>
              <p className="text-xs text-gov-400">{user.role}</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Header - Increased z-index to 40 to sit above the notification overlay (30) but below sidebar (50) */}
        <header className="bg-white shadow-sm z-40 p-4 flex items-center justify-between sticky top-0">
           <div className="flex items-center">
             <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2 text-slate-600 md:hidden mr-2">
               <Menu className="w-6 h-6" />
             </button>
             <span className="font-bold text-gov-900 md:hidden">GovTrack</span>
             <h2 className="hidden md:block text-lg font-semibold text-slate-700 capitalize">
                {activeTab.toLowerCase().replace('_', ' ')}
             </h2>
           </div>

           <div className="flex items-center gap-4">
              {/* Notification Bell */}
              <div className="relative">
                <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-slate-500 hover:text-gov-600 relative outline-none focus:ring-2 focus:ring-gov-200 rounded-full">
                   <Bell className="w-6 h-6" />
                   {unreadCount > 0 && <span className="absolute top-1 right-1 h-3 w-3 bg-red-500 rounded-full border-2 border-white"></span>}
                </button>
                {/* Notification Dropdown */}
                {showNotifications && (
                    <div className="absolute right-0 mt-2 w-80 bg-white rounded-lg shadow-xl border border-slate-200 z-50 overflow-hidden">
                        <div className="p-3 border-b bg-slate-50 flex justify-between items-center">
                            <h3 className="font-bold text-sm text-slate-700">Notifications</h3>
                            {unreadCount > 0 && (
                                <button onClick={markRead} className="text-xs text-gov-600 hover:underline">Mark all read</button>
                            )}
                        </div>
                        <div className="max-h-80 overflow-y-auto">
                            {notifications.length === 0 ? (
                                <p className="p-4 text-sm text-slate-500 text-center">No notifications</p>
                            ) : (
                                notifications.map(n => (
                                    <div 
                                      key={n.id} 
                                      onClick={() => handleNotificationClick(n)}
                                      className={`p-3 border-b hover:bg-slate-50 last:border-0 cursor-pointer ${!n.read ? 'bg-blue-50/50' : ''}`}
                                    >
                                        <div className="flex justify-between items-start mb-1">
                                            <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wide ${
                                                n.type === 'warning' ? 'bg-amber-100 text-amber-800' : 
                                                n.type === 'success' ? 'bg-green-100 text-green-800' : 
                                                'bg-blue-100 text-blue-800'
                                            }`}>
                                                {n.type === 'error' ? 'Alert' : n.type}
                                            </span>
                                            <span className="text-[10px] text-slate-400">{n.time}</span>
                                        </div>
                                        <p className="text-sm font-medium text-slate-800 leading-tight">{n.title}</p>
                                        <p className="text-xs text-slate-600 mt-1">{n.message}</p>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                )}
              </div>
           </div>
        </header>

        <main className="flex-1 overflow-auto p-4 md:p-8 relative">
          {renderContent()}
        </main>
      </div>

      {mobileMenuOpen && <div className="fixed inset-0 bg-black bg-opacity-50 z-40 md:hidden" onClick={() => setMobileMenuOpen(false)}></div>}

      {/* Click outside to close notifications - Reduced z-index to 30 so Header (40) is interactive */}
      {showNotifications && <div className="fixed inset-0 z-30" onClick={() => setShowNotifications(false)}></div>}
    </div>
  );
}

