export const InventoryService = {
  getAll: () => Promise.resolve([...MOCK_INVENTORY]),
  add: (item: Omit<InventoryItem, 'id' | 'lastUpdated' | 'sku'> & { sku?: string }) => {
    // Generate SKU if not provided
    const sku = item.sku || generateSKU(item.category);

    const newItem = { 
      ...item, 
      sku,
      id: Math.random().toString(36).substr(2, 9), 
      lastUpdated: new Date().toISOString() 
    };
    MOCK_INVENTORY.push(newItem);

    LogService.add({
        action: 'Create Inventory Item',
        category: 'INVENTORY',
        details: `Created item '${newItem.name}' (Qty: ${newItem.quantity}) in ${newItem.location}`,
        actor: getCurrentActor(),
        referenceId: newItem.id
    });

    // Check for low stock immediately on creation
    if (newItem.quantity < newItem.minStockLevel) {
       NotificationService.add({
         title: 'Low Stock Warning',
         message: `New item '${newItem.name}' added with stock (${newItem.quantity}) below reorder level (${newItem.minStockLevel}).`,
         type: 'warning',
         link: { tab: 'INVENTORY' }
       });
    }

    return Promise.resolve(newItem);
  },
  update: (item: InventoryItem) => {
    const idx = MOCK_INVENTORY.findIndex(i => i.id === item.id);
    if (idx !== -1) {
      const oldItem = MOCK_INVENTORY[idx];
      MOCK_INVENTORY[idx] = { ...item, lastUpdated: new Date().toISOString() };

      LogService.add({
        action: 'Update Inventory Item',
        category: 'INVENTORY',
        details: `Updated details for '${item.name}'. Qty: ${oldItem.quantity} -> ${item.quantity}`,
        actor: getCurrentActor(),
        referenceId: item.id
      });

      // Check for low stock on update
      if (item.quantity < item.minStockLevel) {
         NotificationService.add({
             title: 'Low Stock Alert',
             message: `Item '${item.name}' updated. Stock (${item.quantity}) is below reorder level (${item.minStockLevel}).`,
             type: 'warning',
             link: { tab: 'INVENTORY' }
         });
      }
    }
    return Promise.resolve(MOCK_INVENTORY[idx]);
  },
  updateStock: (id: string, delta: number) => {
    const item = MOCK_INVENTORY.find(i => i.id === id);
    if (item) {
      const oldQty = item.quantity;
      item.quantity += delta;
      item.lastUpdated = new Date().toISOString();

      LogService.add({
        action: 'Update Stock Level',
        category: 'INVENTORY',
        details: `Adjusted stock for '${item.name}' by ${delta}. New Quantity: ${item.quantity}`,
        actor: getCurrentActor(),
        referenceId: item.id
      });

      // Check for low stock alert
      if (item.quantity < item.minStockLevel) {
         NotificationService.add({
             title: 'Low Stock Alert',
             message: `Item '${item.name}' has dropped below reorder level. Current Stock: ${item.quantity}`,
             type: 'warning',
             link: { tab: 'INVENTORY' }
         });
      }
    }
    return Promise.resolve(item);
  },
  generateGovId: (year: string, category: string, type: string) => {
    const count = MOCK_INVENTORY.filter(i => i.govId.includes(`${year}|${category}|${type}`)).length + 1;
    const countStr = count.toString().padStart(3, '0');
    return `${OFFICE_CODE}|${year}|${category}|${type}|${countStr}`;
  }
};

