      </div>

      {/* Global Filters */}
      <Card className="bg-slate-50 border-slate-200 p-4">
         <div className="flex flex-col md:flex-row items-end gap-4">
            <div className="flex-1 w-full grid grid-cols-1 md:grid-cols-3 gap-4">
