                     value={deptFilter}
                     onChange={e => setDeptFilter(e.target.value)}
                  >
                     {getUniqueDepartments().map(d => <option key={d} value={d}>{d}</option>)}
                  </select>
               </div>
            </div>
            <div className="text-xs text-slate-400 pb-3">
               Applies to Financial & Audit reports
            </div>
         </div>
      </Card>

      {/* Report Tabs */}
      <div className="border-b border-slate-200">
         <nav className="-mb-px flex space-x-8">
            <button
               onClick={() => setActiveTab('FINANCIAL')}
               className={`whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm flex items-center gap-2 ${
                  activeTab === 'FINANCIAL' 
                  ? 'border-gov-500 text-gov-600' 
                  : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
               }`}
            >
               <BarChart3 className="w-4 h-4" /> Financial & Consumption
            </button>
            <button
               onClick={() => setActiveTab('INVENTORY')}
               className={`whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm flex items-center gap-2 ${
                  activeTab === 'INVENTORY' 
                  ? 'border-gov-500 text-gov-600' 
                  : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
               }`}
            >
               <PieChartIcon className="w-4 h-4" /> Inventory Status
            </button>
            <button
               onClick={() => setActiveTab('AUDIT')}
               className={`whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm flex items-center gap-2 ${
                  activeTab === 'AUDIT' 
                  ? 'border-gov-500 text-gov-600' 
                  : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'
               }`}
            >
               <Activity className="w-4 h-4" /> System Audit
            </button>
         </nav>
      </div>

      {/* Tab Content */}
      <div className="mt-4">
         {activeTab === 'FINANCIAL' && renderFinancialTab()}
         {activeTab === 'INVENTORY' && renderInventoryTab()}
         {activeTab === 'AUDIT' && renderAuditTab()}
      </div>
    </div>
  );
};

export enum UserRole {
  USER = 'User',
  SUPERVISOR = 'Supervisor',
  MANAGER = 'Manager',
  FINANCE_OFFICER = 'Finance Officer',
  ADMIN = 'Administrator',
  STOCK_KEEPER = 'Stock Keeper'
}

export enum ItemCategory {
  STATIONERY = '01',
  IT_EQUIPMENT = '02',
  FURNITURE = '03',
  VEHICLES = '04',
  MAINTENANCE = '05'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  department: string;
  designation?: string;
  phone?: string;
}

export interface Vendor {
  id: string;
  name: string;
  contactPerson: string;
  email: string;
  phone: string;
  address: string;
  taxId?: string;
  status: 'Active' | 'Blacklisted' | 'Pending';
}

export interface InventoryItem {
  id: string;
  name: string;
  sku: string; // Made required
  barcode?: string; // New field
  // Gov ID: OfficeNumber | Year | CategoryNumber | ItemTypeNumber | ItemNumber
  govId: string;
  category: ItemCategory;
  quantity: number;
  location: string;
  minStockLevel: number;
  pricePerUnit: number;
  lastUpdated: string;
}

export interface Asset {
  id: string;
  name: string;
  govId: string;
  category: ItemCategory;
  condition: 'New' | 'Good' | 'Fair' | 'Poor' | 'Disposal';
  purchaseDate: string;
  price: number;
  location: string;
  assignedTo?: string;
}

export enum ProcurementStatus {
  DRAFT = 'Draft',
  SUBMITTED = 'Submitted',
  APPROVED = 'Approved',
  REJECTED = 'Rejected',
  ISSUED = 'Issued', // Stock issued locally
  PROCUREMENT_NEEDED = 'Procurement Needed', // Moved to procurement
  PR_CREATED = 'PR Created', // Purchase Request Form generated
  EVALUATION = 'Evaluation', // Price Evaluation Form generated
  PENDING_APPROVAL = 'Pending Approval', // Manager Approval Needed
  BUDGET_CHECK = 'Budget Check', // Pending Budget Code
  PO_ISSUED = 'PO Issued',
  COMPLETED = 'Completed'
}

export enum EvaluationMethod {
  EMAIL = 'Email',
  PHONE = 'Phone',
  VISITING = 'Visiting'
}

export type EvaluationType = 'FORM' | 'QUOTATION' | 'SINGLE_SOURCE';

export interface SystemSettings {
  officeName: string;
  officeAddress: string;
  officeCode: string;
  departmentName: string;
  logoUrl?: string;
  prefixes: {
    gsrf: string;
    pr: string;
    po: string;
    asset: string;
    inventory: string;
  };
  templateConfig: {
    headerText?: string;
    footerText?: string;
    showLogo: boolean;
  }
}

export interface ProcurementWorkflow {
  id: string;
  requestType: 'GOODS' | 'SERVICE';
  status: ProcurementStatus;

  // Step 1: Request
  requesterId: string;
  requesterName: string;
  requesterDepartment: string;
  section?: string;
  requestDate: string;
  requiredDate?: string;
  remarks?: string; // Purpose / Use case
  items: {
    itemId?: string; // If existing inventory item
    description: string;
    quantity: number;
    estimatedCost?: number;
  }[];
  requesterSignature?: string;

  // Step 2: Stock Keeper Check / GSRF
  gsrfRefNumber?: string;
  stockKeeperSignature?: string;
  stockCheckDate?: string;

  // Step 2a: Issue Process (If Available)
  issueDetails?: {
    receiverName: string;
    receiverDepartment: string;
    issueDate: string;
    remarks: string;
  };

  // Step 3: Purchase Request (if not in stock)
  prRefNumber?: string;
  authorizedBySignature?: string;

  // Step 4: Price Eval
  evalRefNumber?: string; // Format: (A)263/YYYY/Counter
  evaluationMethod?: EvaluationMethod;
  evaluationType?: EvaluationType;
  singleSourceJustification?: string;
  quotations?: {
    vendorName: string;
    quoteNumber?: string;
    quoteDate?: string;
    price: number;
    selected: boolean;
  }[];

  // Step 4.5: Budget
  budgetCode?: string;
  budgetVerifiedDate?: string;

  // Step 5: PO
  poNumber?: string;
  selectedVendor?: string;

  // Logs
  logs: {
    date: string;
    action: string;
    actor: string;
  }[];
}

