  const handleProfileUpdate = async () => {
     setIsSaving(true);
     const updatedUser = { 
        ...currentUser, 
        name: profileForm.name,
        email: profileForm.email,
        designation: profileForm.designation,
        phone: profileForm.phone,
        signatureUrl: signature
     };
     await UserService.update(updatedUser);
     setCurrentUser(updatedUser);
     setIsSaving(false);
     alert("Profile updated successfully.");
  };

  const handlePasswordChange = async () => {
     if (!passForm.current || !passForm.new || !passForm.confirm) {
        alert("Please fill all password fields.");
        return;
     }
     if (passForm.new !== passForm.confirm) {
        alert("New passwords do not match.");
        return;
     }
     setIsSaving(true);
     await UserService.changePassword(currentUser.id, passForm.current, passForm.new);
     setPassForm({ current: '', new: '', confirm: '' });
     setIsSaving(false);
     alert("Password changed successfully.");
  };

  const handleUserSwitch = (id: string) => {
    const newUser = AuthService.switchUser(id);
    setCurrentUser(newUser);
    window.location.reload(); // Simple reload to refresh app state with new user
  };

  const openEditUser = (user: User) => {
    setEditingUser({...user});
    setPasswordResetMode(false);
    setNewPassword('');
    setShowUserModal(true);
