            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center text-slate-500">0</td>
                <td className="border border-black p-2 text-center font-bold">{item.quantity}</td>
              </tr>
            ))}
            {[...Array(Math.max(0, 8 - data.items.length))].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

         <div className="flex justify-between mt-12 gap-8">
          {renderSignatureBlock('PREPARED BY', 'Stock Keeper', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('VERIFIED BY', 'Finance Officer', undefined, undefined)}
          {renderSignatureBlock('AUTHORIZED BY', 'Head of Procurement', data.authorizedBySignature, undefined)}
        </div>
        {renderFooter()}
      </div>
     );
  }

  // --- Price Evaluation Form (PEF) ---
  if (type === 'PEF') {
    // Single Source
    if (data.evaluationType === 'SINGLE_SOURCE') {
        return (
          <div className="printable-area flex flex-col text-black font-sans">
             {renderHeader('SINGLE SOURCE JUSTIFICATION', data.poNumber || 'PENDING')}

             <div className="mb-6 space-y-4 text-xs">
                <div className="flex justify-between">
                    <div><span className="font-bold">Requesting Section:</span> {data.section || data.requesterDepartment}</div>
                    <div><span className="font-bold">PR Ref No:</span> {data.prRefNumber}</div>
                </div>

                <div className="border border-black p-4 bg-slate-50 min-h-[100px]">
                    <p className="font-bold mb-2 uppercase text-[10px] text-slate-600">Justification for Single Source Procurement:</p>
                    <p className="italic text-sm">{data.singleSourceJustification}</p>
                </div>

                <div className="grid grid-cols-2 gap-6 pt-4">
                    <div className="border border-black p-3">
                        <p className="font-bold text-[10px] uppercase text-slate-500">Selected Vendor</p>
                        <p className="font-bold text-lg">{data.selectedVendor}</p>
                    </div>
                    <div className="border border-black p-3">
                        <p className="font-bold text-[10px] uppercase text-slate-500">Total Estimated Cost</p>
                        <p className="font-bold text-lg">${(data.quotations?.[0]?.price || 0).toFixed(2)}</p>
                    </div>
                </div>
             </div>

             <div className="flex justify-between mt-12 gap-4">
                {renderSignatureBlock('REQUESTED BY', 'Procurement Officer', data.stockKeeperSignature, undefined)}
                {renderSignatureBlock('APPROVED BY', 'Director General', data.authorizedBySignature, undefined)}
            </div>
            {renderFooter()}
          </div>
        );
    }

    // Matrix Evaluation
    return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader('PRICE EVALUATION FORM', data.evalRefNumber || 'PENDING')}

        <div className="mb-4 grid grid-cols-3 gap-4 text-xs">
          <div><span className="font-bold">Dept:</span> {data.section || data.requesterDepartment}</div>
          <div><span className="font-bold">Method:</span> {data.evaluationMethod}</div>
          <div><span className="font-bold">PR Ref:</span> {data.prRefNumber}</div>
        </div>

        {data.evaluationType === 'QUOTATION' ? (
           // Quotation Based Table
           <table className="w-full border-collapse border border-black mb-6 text-xs">
             <thead>
               <tr className="bg-slate-100">
                 <th className="border border-black p-2 w-10">#</th>
                 <th className="border border-black p-2 text-left">Vendor Name</th>
                 <th className="border border-black p-2 w-24">Quote No</th>
                 <th className="border border-black p-2 w-24">Date</th>
                 <th className="border border-black p-2 w-28 text-right">Total Price</th>
               </tr>
             </thead>
             <tbody>
                {data.quotations?.map((q, idx) => (
                    <tr key={idx} className={q.selected ? "bg-green-50" : ""}>
                        <td className="border border-black p-2 text-center">{idx + 1}</td>
                        <td className="border border-black p-2 font-medium">
                            {q.vendorName}
                            {q.selected && <span className="block text-[9px] font-bold text-green-700 mt-1">[RECOMMENDED]</span>}
                        </td>
                        <td className="border border-black p-2 text-center">{q.quoteNumber || '-'}</td>
                        <td className="border border-black p-2 text-center">{q.quoteDate ? new Date(q.quoteDate).toLocaleDateString() : '-'}</td>
                        <td className="border border-black p-2 text-right font-mono font-bold">${(q.price || 0).toFixed(2)}</td>
                    </tr>
                ))}
             </tbody>
           </table>
        ) : (
           // Form Based Table (Item Matrix)
           <table className="w-full border-collapse border border-black mb-6 text-[10px]">
            <thead>
                <tr className="bg-slate-100">
                <th className="border border-black p-1 w-8">#</th>
                <th className="border border-black p-1 text-left">Description</th>
                <th className="border border-black p-1 w-12">Qty</th>
                {data.quotations?.map((q, i) => (
                    <th key={i} className="border border-black p-1 w-24">
                        <div className="font-bold truncate">{q.vendorName || `Vendor ${i+1}`}</div>
                        <div className="font-normal text-[9px]">Unit Price</div>
                    </th>
                )) || <th className="border border-black p-1">Vendor Details</th>}
                </tr>
            </thead>
            <tbody>
                {data.items.map((item, idx) => (
                <tr key={idx}>
                    <td className="border border-black p-1 text-center">{idx + 1}</td>
                    <td className="border border-black p-1">{item.description}</td>
                    <td className="border border-black p-1 text-center">{item.quantity}</td>
                    {data.quotations?.map((q, i) => (
                    <td key={i} className="border border-black p-1 text-center">
                        {q.price > 0 ? `$${q.price.toFixed(2)}` : '-'}
                    </td>
                    ))}
                </tr>
                ))}
                <tr className="font-bold bg-slate-50 border-t-2 border-black">
                    <td colSpan={3} className="border border-black p-1 text-right">TOTAL</td>
                    {data.quotations?.map((q, i) => (
                    <td key={i} className={`border border-black p-2 text-center ${q.selected ? 'bg-green-100' : ''}`}>
                        {q.price > 0 ? `$${(q.price * (data.items[0]?.quantity || 1)).toFixed(2)}` : '-'}
                        {q.selected && <div className="text-[9px] text-green-800">RECOMMENDED</div>}
                    </td>
                    ))}
                </tr>
            </tbody>
            </table>
        )}

        <div className="mt-4 mb-4 text-xs border border-black p-3">
          <p className="font-bold mb-1 uppercase text-slate-500 text-[10px]">Recommendation / Committee Notes:</p>
          <p>
             Based on the evaluation above, it is recommended to award the contract to 
             <span className="font-bold underline mx-1">{data.quotations?.find(q => q.selected)?.vendorName}</span> 
             as they meet the technical requirements at the most competitive price.
          </p>
        </div>

        <div className="flex justify-between mt-auto pt-8 gap-4">
          {renderSignatureBlock('PREPARED BY', 'Procurement Officer', data.stockKeeperSignature, undefined)}
          {renderSignatureBlock('CHECKED BY', 'Finance Officer', undefined, undefined)}
          {renderSignatureBlock('APPROVED BY', 'Director', data.authorizedBySignature, undefined)}
        </div>
        {renderFooter()}
      </div>
    );
  }

  // --- Purchase Order (PO) ---
  if (type === 'PO') {
     const selectedQuote = data.quotations?.find(q => q.selected);
     const totalAmount = selectedQuote ? selectedQuote.price : 0;

     return (
       <div className="printable-area flex flex-col text-black font-sans">
         {renderHeader('PURCHASE ORDER', data.poNumber || 'PENDING')}

         <div className="flex justify-between mb-8 text-xs gap-8">
            <div className="w-1/2 border border-black p-3">
               <h3 className="font-bold uppercase mb-2 border-b border-black pb-1">Vendor Details</h3>
               <p className="font-bold text-sm">{selectedQuote?.vendorName || 'N/A'}</p>
               <p className="text-slate-600">Quote Ref: {selectedQuote?.quoteNumber || 'N/A'}</p>
               {selectedQuote?.quoteDate && <p className="text-slate-600">Date: {new Date(selectedQuote.quoteDate).toLocaleDateString()}</p>}
            </div>
            <div className="w-1/2 border border-black p-3 bg-slate-50">
               <h3 className="font-bold uppercase mb-2 border-b border-black pb-1">Order Details</h3>
               <p><span className="font-bold w-24 inline-block">PO Date:</span> {data.budgetVerifiedDate ? new Date(data.budgetVerifiedDate).toLocaleDateString() : new Date().toLocaleDateString()}</p>
               <p><span className="font-bold w-24 inline-block">Budget Code:</span> {data.budgetCode}</p>
               <p><span className="font-bold w-24 inline-block">PR Ref:</span> {data.prRefNumber}</p>
               <p><span className="font-bold w-24 inline-block">Currency:</span> USD</p>
            </div>
         </div>

         <table className="w-full border-collapse border border-black mb-4 text-xs">
           <thead>
             <tr className="bg-slate-100">
               <th className="border border-black p-2 w-12">#</th>
               <th className="border border-black p-2 text-left">Description</th>
               <th className="border border-black p-2 w-24">Qty</th>
             </tr>
           </thead>
           <tbody>
             {data.items.map((item, idx) => (
               <tr key={idx}>
                 <td className="border border-black p-2 text-center">{idx + 1}</td>
                 <td className="border border-black p-2">{item.description}</td>
                 <td className="border border-black p-2 text-center">{item.quantity}</td>
               </tr>
             ))}
             {/* Total Row */}
             <tr className="font-bold text-base">
                <td colSpan={2} className="border border-black p-3 text-right uppercase">Total Amount</td>
                <td className="border border-black p-3 text-right bg-slate-50">${(totalAmount || 0).toFixed(2)}</td>
             </tr>
           </tbody>
         </table>

         <div className="text-xs border-t border-black pt-4 mt-4">
            <p className="font-bold uppercase text-[10px] text-slate-500 mb-2">Terms & Conditions:</p>
            <ol className="list-decimal ml-4 space-y-1 text-[10px] text-slate-700">
               <li>This Purchase Order number must appear on all invoices, packing slips, and correspondence.</li>
               <li>Delivery must be made within the specified timeline. Late delivery may result in penalties.</li>
               <li>Goods must meet the quality standards specified in the solicitation documents.</li>
               <li>Payment will be processed within 30 days of receipt of invoice and satisfactory goods acceptance.</li>
            </ol>
         </div>

         <div className="flex justify-between mt-auto pt-12 gap-8">
           {renderSignatureBlock('PREPARED BY', 'Procurement Officer', data.stockKeeperSignature, undefined)}
           {renderSignatureBlock('AUTHORIZED BY', 'Finance Director', data.authorizedBySignature, data.budgetVerifiedDate)}
         </div>
         {renderFooter()}
       </div>
     );
  }

  return <div>Document template not found.</div>;
};

import React, { useState, useEffect } from 'react';
import { ProcurementWorkflow, ProcurementStatus, User, UserRole, SystemSettings, InventoryItem, Vendor, ItemCategory } from '../../types';
import { Button, Card } from '../SharedComponents';
import { DocumentTemplate } from '../DocumentTemplate';
import { Printer, ArrowRight, Check, X, DollarSign, AlertCircle, CreditCard, PackageCheck, ShieldCheck, ThumbsUp, ThumbsDown, FileText, Download } from 'lucide-react';
import { IssueStockModal, BudgetModal, SingleSourceModal, EvaluationModal, ReceiveGoodsModal } from './ProcurementModals';

interface ProcurementDetailProps {
  request: ProcurementWorkflow;
  currentUser: User;
  settings: SystemSettings | null;
  inventory: InventoryItem[];
  vendors: Vendor[];
  onBack: () => void;
  onUpdateStatus: (id: string, status: ProcurementStatus, log: string, extraUpdates?: any) => Promise<void>;
  onReceiveGoods: (id: string, items: any[], actor: string) => Promise<void>;
}

export const ProcurementDetail: React.FC<ProcurementDetailProps> = ({ request: r, currentUser, settings, inventory, vendors, onBack, onUpdateStatus, onReceiveGoods }) => {
  const [isPrintMode, setIsPrintMode] = useState(false);
  const [activeDocType, setActiveDocType] = useState<'GSRF' | 'PRF' | 'PEF' | 'PO'>('GSRF');
  const [modalOpen, setModalOpen] = useState<'ISSUE' | 'EVAL' | 'SINGLE' | 'BUDGET' | 'RECEIVE' | null>(null);

  // Determine available documents based on status
  const getAvailableDocuments = () => {
    const docs: { type: 'GSRF' | 'PRF' | 'PEF' | 'PO'; label: string }[] = [
        { type: 'GSRF', label: 'Requisition Form (GSRF)' }
    ];

    const s = r.status;

    // PRF Available if PR Created or later
    if ([
        ProcurementStatus.PR_CREATED, 
        ProcurementStatus.EVALUATION, 
        ProcurementStatus.PENDING_APPROVAL,
        ProcurementStatus.BUDGET_CHECK, 
        ProcurementStatus.PO_ISSUED, 
        ProcurementStatus.COMPLETED
    ].includes(s)) {
        docs.push({ type: 'PRF', label: 'Purchase Request (PR)' });
    }

    // PEF Available if Evaluation started or later
    if ([
        ProcurementStatus.EVALUATION, 
        ProcurementStatus.PENDING_APPROVAL,
        ProcurementStatus.BUDGET_CHECK, 
        ProcurementStatus.PO_ISSUED, 
        ProcurementStatus.COMPLETED
    ].includes(s)) {
        docs.push({ type: 'PEF', label: 'Price Evaluation (PEF)' });
    }

    // PO Available if PO Issued or later
    if ([
        ProcurementStatus.PO_ISSUED, 
        ProcurementStatus.COMPLETED
    ].includes(s)) {
        docs.push({ type: 'PO', label: 'Purchase Order (PO)' });
    }

    return docs;
  };

  // Determine default doc when opening print view
  useEffect(() => {
      if (isPrintMode) {
        const available = getAvailableDocuments();
        // Default to the latest document generated
        setActiveDocType(available[available.length - 1].type);
      }
  }, [isPrintMode, r.status]);

  const renderStatusBadge = (status: ProcurementStatus) => {
    const colors: Record<string, string> = {
      [ProcurementStatus.DRAFT]: 'bg-slate-100 text-slate-800',
      [ProcurementStatus.SUBMITTED]: 'bg-blue-100 text-blue-800',
      [ProcurementStatus.APPROVED]: 'bg-green-100 text-green-800',
      [ProcurementStatus.REJECTED]: 'bg-red-100 text-red-800',
      [ProcurementStatus.ISSUED]: 'bg-purple-100 text-purple-800',
      [ProcurementStatus.PROCUREMENT_NEEDED]: 'bg-orange-100 text-orange-800',
      [ProcurementStatus.PR_CREATED]: 'bg-indigo-100 text-indigo-800',
      [ProcurementStatus.EVALUATION]: 'bg-pink-100 text-pink-800',
      [ProcurementStatus.PENDING_APPROVAL]: 'bg-amber-100 text-amber-800',
      [ProcurementStatus.BUDGET_CHECK]: 'bg-yellow-100 text-yellow-800',
      [ProcurementStatus.PO_ISSUED]: 'bg-teal-100 text-teal-800',
      [ProcurementStatus.COMPLETED]: 'bg-emerald-100 text-emerald-800',
    };
    return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${colors[status] || 'bg-slate-100'}`}>{status}</span>;
  };

  // --- Handlers ---
  const handleIssueConfirm = async (details: any) => {
    await onUpdateStatus(r.id, ProcurementStatus.ISSUED, 'Items Issued from Stock', { 
      stockKeeperSignature: currentUser.signatureUrl || 'signed', // Use stored signature
      stockCheckDate: new Date().toISOString(),
      issueDetails: {
        receiverName: details.receiverName,
        receiverDepartment: details.receiverDept,
        issueDate: new Date().toISOString(),
        remarks: details.remarks
      }
    });
    setModalOpen(null);
  };

  const handleEvaluationConfirm = async (data: any) => {
    // Auto-select cheapest
    const sortedVendors = [...data.vendors].map((v: any) => ({...v, selected: false}));
    const activeVendors = sortedVendors.filter((v: any) => v.vendorName && v.price > 0);

    if (activeVendors.length > 0) {
       const minPrice = Math.min(...activeVendors.map((v: any) => v.price));
       const cheapestIndex = sortedVendors.findIndex((v: any) => v.price === minPrice && v.vendorName);
       if (cheapestIndex >= 0) sortedVendors[cheapestIndex].selected = true;
    }

    // Move to PENDING_APPROVAL instead of BUDGET_CHECK
    await onUpdateStatus(r.id, ProcurementStatus.PENDING_APPROVAL, 'Price Evaluation Submitted - Awaiting Manager Approval', {
      evaluationMethod: data.method,
      evaluationType: data.type,
      quotations: sortedVendors,
      stockKeeperSignature: currentUser.signatureUrl // Signer of Evaluation
    });
    setModalOpen(null);
  };

  const handleSingleSourceConfirm = async (data: any) => {
    // Move to PENDING_APPROVAL instead of BUDGET_CHECK
    await onUpdateStatus(r.id, ProcurementStatus.PENDING_APPROVAL, 'Single Source Justification Added - Awaiting Manager Approval', {
      evaluationType: 'SINGLE_SOURCE',
      singleSourceJustification: data.justification,
      selectedVendor: data.vendorName,
      quotations: [{ vendorName: data.vendorName, price: data.estimatedPrice, selected: true }],
      stockKeeperSignature: currentUser.signatureUrl // Signer
    });
    setModalOpen(null);
  };

  const handleManagerDecision = async (approved: boolean) => {
    if (approved) {
      await onUpdateStatus(r.id, ProcurementStatus.BUDGET_CHECK, 'Evaluation Approved by Manager', {
        authorizedBySignature: currentUser.signatureUrl // Manager Signature
      });
    } else {
      // Reject back to PR_CREATED to restart evaluation
      await onUpdateStatus(r.id, ProcurementStatus.PR_CREATED, 'Evaluation Rejected by Manager - Re-evaluation Required', {});
    }
  };

  const handleBudgetConfirm = async (code: string) => {
    const poNumber = `PO/${new Date().getFullYear()}/${Math.floor(Math.random()*10000).toString().padStart(4, '0')}`;
    const selectedVendor = r.quotations?.find(q => q.selected)?.vendorName || 'Unknown Vendor';

    await onUpdateStatus(r.id, ProcurementStatus.PO_ISSUED, 'Budget Confirmed & PO Generated', {
      budgetCode: code,
      budgetVerifiedDate: new Date().toISOString(),
      poNumber: poNumber,
      selectedVendor: selectedVendor,
      // For PO, authorizedBy often refers to Finance Director signature on the PO doc
      authorizedBySignature: currentUser.signatureUrl
    });
    setModalOpen(null);
  };

  const handleReceiveConfirm = async (items: any[]) => {
    await onReceiveGoods(r.id, items, currentUser.name);
    setModalOpen(null);
  };

  // Prepare Receive Data
  const initialReceiveData = r.items.map(item => ({
      description: item.description,
      orderedQty: item.quantity,
      receivedQty: item.quantity,
      addToInventory: true,
      inventoryAction: item.itemId || 'NEW',
      newCategory: ItemCategory.STATIONERY,
      newLocation: 'Main Store',
      price: r.quotations?.find(q => q.selected)?.price || 0
  }));

  const availableDocs = getAvailableDocuments();

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <Button variant="outline" onClick={() => { onBack(); setIsPrintMode(false); }} icon={ArrowRight} className="rotate-180">Back</Button>
        <div className="flex gap-2">
          {!isPrintMode && <Button variant="secondary" icon={Printer} onClick={() => setIsPrintMode(true)}>Print / Download Documents</Button>}
          {isPrintMode && <Button variant="outline" onClick={() => setIsPrintMode(false)}>Close Preview</Button>}
        </div>
      </div>

      {isPrintMode ? (
        <div className="space-y-4">
             {/* Document Type Selector */}
             <div className="bg-white p-4 rounded-lg shadow-sm border border-slate-200 flex flex-wrap gap-2 no-print">
                <div className="text-sm font-bold text-slate-500 flex items-center mr-2">Available Documents:</div>
                {availableDocs.map(doc => (
                    <button
                        key={doc.type}
                        onClick={() => setActiveDocType(doc.type)}
                        className={`px-4 py-2 rounded-full text-sm font-medium transition-colors flex items-center gap-2 ${
                            activeDocType === doc.type 
                            ? 'bg-gov-600 text-white shadow-md' 
                            : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                        }`}
                    >
                        <FileText className="w-4 h-4" /> {doc.label}
                    </button>
                ))}
                <div className="ml-auto">
                    <Button icon={Download} onClick={() => window.print()}>Download PDF / Print</Button>
                </div>
             </div>

            <div className="document-preview-wrapper rounded border border-slate-300">
              <DocumentTemplate type={activeDocType} data={r} settings={settings} />
            </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 space-y-6">
            <Card title={`Request #${r.gsrfRefNumber || r.id.toUpperCase()}`}>
              <div className="flex justify-between mb-4">
                <div>
                  <p className="text-sm text-slate-500">Requester</p>
                  <p className="font-medium">{r.requesterName} ({r.section || r.requesterDepartment})</p>
                </div>
                <div className="text-right">
                  <p className="text-sm text-slate-500">Status</p>
                  {renderStatusBadge(r.status)}
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 mb-4 text-sm">
                 <div>
                   <span className="text-slate-500 block">Date Submitted</span>
                   <span>{new Date(r.requestDate).toLocaleDateString()}</span>
                 </div>
                 <div>
                   <span className="text-slate-500 block">Required By</span>
                   <span>{r.requiredDate ? new Date(r.requiredDate).toLocaleDateString() : 'N/A'}</span>
                 </div>
                 <div className="col-span-2">
                   <span className="text-slate-500 block">Remarks</span>
                   <p className="bg-slate-50 p-2 rounded border border-slate-100">{r.remarks || 'No remarks provided.'}</p>
                 </div>
              </div>

              <div className="mt-4">
                <h4 className="text-sm font-medium border-b border-slate-100 pb-2 mb-2">Items Requested</h4>
                {r.items.map((item, i) => (
                  <div key={i} className="flex justify-between py-2 border-b border-slate-50 text-sm">
                    <div className="flex items-center gap-2">
                       {item.itemId ? <span className="bg-blue-100 text-blue-800 text-[10px] font-bold px-1.5 py-0.5 rounded" title="Inventory Linked">INV</span> : null}
                       <span>{item.description}</span>
                    </div>
                    <span className="font-mono bg-slate-100 px-2 rounded">{item.quantity}</span>
                  </div>
                ))}
              </div>

              {/* Detail Sections */}
              {r.issueDetails && (
                <div className="mt-4 bg-purple-50 p-3 rounded border border-purple-100">
                   <h4 className="text-sm font-bold text-purple-800 mb-2">Issue Details</h4>
                   <p className="text-sm">Issued To: {r.issueDetails.receiverName} ({r.issueDetails.receiverDepartment})</p>
                   <p className="text-sm">Date: {new Date(r.issueDetails.issueDate).toLocaleDateString()}</p>
                   <p className="text-sm italic">"{r.issueDetails.remarks}"</p>
                </div>
              )}
              {r.evaluationType === 'SINGLE_SOURCE' && r.singleSourceJustification && (
                <div className="mt-4 bg-teal-50 p-3 rounded border border-teal-100">
                   <h4 className="text-sm font-bold text-teal-800 mb-2">Single Source Procurement</h4>
                   <p className="text-sm"><span className="font-semibold">Selected Vendor:</span> {r.quotations?.[0]?.vendorName}</p>
                   <p className="text-sm mt-1"><span className="font-semibold">Justification:</span> {r.singleSourceJustification}</p>
                </div>
              )}
              {r.evaluationType !== 'SINGLE_SOURCE' && r.evalRefNumber && (
                <div className="mt-4 bg-pink-50 p-3 rounded border border-pink-100">
                   <h4 className="text-sm font-bold text-pink-800 mb-2">Price Evaluation ({r.evalRefNumber})</h4>
                   <p className="text-sm">Method: {r.evaluationMethod} | Type: {r.evaluationType || 'FORM'}</p>
                   <div className="flex gap-4 mt-2 overflow-x-auto">
                     {r.quotations?.map((q, i) => (
                       <div key={i} className={`p-2 border rounded text-xs min-w-[120px] ${q.selected ? 'bg-green-100 border-green-300 shadow-sm' : 'bg-white'}`}>
                         {q.selected && <div className="text-green-700 font-bold mb-1 text-[10px] uppercase">✓ Best Offer</div>}
                         <p className="font-bold">{q.vendorName}</p>
                         {q.quoteNumber && <p className="text-[10px] text-slate-500">#{q.quoteNumber}</p>}
                         <p className="mt-1 font-mono">${(q.price || 0).toFixed(2)}</p>
                       </div>
                     ))}
                   </div>
                </div>
              )}
              {(r.status === ProcurementStatus.PO_ISSUED || r.status === ProcurementStatus.COMPLETED) && (
                 <div className="mt-4 bg-teal-50 p-3 rounded border border-teal-100">
                    <h4 className="text-sm font-bold text-teal-800 mb-2 flex items-center"><Check className="w-4 h-4 mr-1"/> Purchase Order Generated</h4>
                    <p className="text-sm"><span className="font-bold">PO Number:</span> {r.poNumber}</p>
                    <p className="text-sm"><span className="font-bold">Budget Code:</span> {r.budgetCode}</p>
                    <p className="text-sm"><span className="font-bold">Vendor:</span> {r.quotations?.find(q => q.selected)?.vendorName}</p>
                 </div>
              )}
              {r.status === ProcurementStatus.COMPLETED && (
                  <div className="mt-4 bg-emerald-50 p-3 rounded border border-emerald-100">
                      <h4 className="text-sm font-bold text-emerald-800 mb-2 flex items-center"><PackageCheck className="w-4 h-4 mr-1"/> Goods Received & Process Completed</h4>
                      <p className="text-sm text-emerald-700">Inventory has been updated with received items.</p>
                  </div>
              )}
            </Card>

            {/* Workflow Actions */}
            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.SUBMITTED && (
              <Card title="Stock Keeper Action">
                <p className="text-sm text-slate-600 mb-4">Check stock availability for requested items.</p>
                <div className="flex gap-4">
                  <Button className="flex-1" onClick={() => setModalOpen('ISSUE')}>
                    <Check className="mr-2 h-4 w-4" /> Available - Issue Stock
                  </Button>
                  <Button className="flex-1" variant="secondary" onClick={() => onUpdateStatus(r.id, ProcurementStatus.PROCUREMENT_NEEDED, 'Marked for Procurement', { stockKeeperSignature: currentUser.signatureUrl || 'signed', stockCheckDate: new Date().toISOString(), gsrfRefNumber: r.gsrfRefNumber })}>
                    <X className="mr-2 h-4 w-4" /> Not Available - Create PR
                  </Button>
                </div>
              </Card>
            )}

            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PROCUREMENT_NEEDED && (
              <Card title="Procurement Processing">
                <p className="text-sm text-slate-600 mb-4">Convert this request into a formal Purchase Request.</p>
                <Button onClick={() => onUpdateStatus(r.id, ProcurementStatus.PR_CREATED, 'Purchase Request Created', { prRefNumber: `PR/${new Date().getFullYear()}/${Math.floor(Math.random()*1000)}`, stockKeeperSignature: currentUser.signatureUrl })}>
                  Generate Purchase Request (PR)
                </Button>
              </Card>
            )}

            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PR_CREATED && (
              <Card title="Procurement Action">
                <p className="text-sm text-slate-600 mb-4">Choose procurement method.</p>
                <div className="flex flex-col gap-3">
                  <Button onClick={() => setModalOpen('EVAL')}>
                    <DollarSign className="mr-2 h-4 w-4" /> Start Price Evaluation
                  </Button>
                  <Button variant="outline" onClick={() => setModalOpen('SINGLE')}>
                    <AlertCircle className="mr-2 h-4 w-4" /> Single Source Procurement
                  </Button>
                </div>
              </Card>
            )}

            {/* MANAGER APPROVAL STEP */}
            {r.status === ProcurementStatus.PENDING_APPROVAL && (
              <Card title="Approval Required">
                {(currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN) ? (
                  <>
                    <p className="text-sm text-slate-600 mb-4">Review the price evaluation and approve to proceed to budgeting.</p>
                    <div className="flex gap-4">
                      <Button className="flex-1" onClick={() => handleManagerDecision(true)}>
                        <ThumbsUp className="mr-2 h-4 w-4" /> Approve Evaluation
                      </Button>
                      <Button className="flex-1" variant="danger" onClick={() => handleManagerDecision(false)}>
                        <ThumbsDown className="mr-2 h-4 w-4" /> Reject (Re-do)
                      </Button>
                    </div>
                    {!currentUser.signatureUrl && <p className="text-xs text-red-500 mt-2">Note: You do not have a digital signature saved in your profile.</p>}
                  </>
                ) : (
                  <div className="flex flex-col items-center justify-center py-6 text-slate-500">
                    <ShieldCheck className="w-12 h-12 text-amber-400 mb-2" />
                    <p className="text-center font-medium">Pending Manager Approval</p>
                    <p className="text-xs text-center mt-1">This request must be approved by a Manager before proceeding.</p>
                  </div>
                )}
              </Card>
            )}

            {(currentUser.role === UserRole.STOCK_KEEPER || currentUser.role === UserRole.FINANCE_OFFICER) && r.status === ProcurementStatus.BUDGET_CHECK && (
               <Card title="Budget Verification">
                  <p className="text-sm text-slate-600 mb-4">Verify budget availability and assign a Budget Code to generate the Purchase Order (PO).</p>
                  <div className="flex justify-end">
                     <Button onClick={() => setModalOpen('BUDGET')} icon={CreditCard}>Verify Budget & Issue PO</Button>
                  </div>
               </Card>
            )}

            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PO_ISSUED && (
              <Card title="Goods Receipt (GRN)">
                  <p className="text-sm text-slate-600 mb-4">Confirm receipt of items from the vendor and update inventory.</p>
                  <Button onClick={() => setModalOpen('RECEIVE')} icon={PackageCheck}>Receive Items & Update Inventory</Button>
              </Card>
            )}

          </div>

          <div className="space-y-6">
             <Card title="Signatures">
               <div className="space-y-4">
                 <div>
                   <p className="text-xs text-slate-500">Requester</p>
                   {r.requesterSignature ? <img src={r.requesterSignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                 </div>
                 <div>
                   <p className="text-xs text-slate-500">Stock Keeper / Officer</p>
                   {r.stockKeeperSignature ? <img src={r.stockKeeperSignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                 </div>
                 {r.status !== ProcurementStatus.PENDING_APPROVAL && r.status !== ProcurementStatus.EVALUATION && r.status !== ProcurementStatus.PR_CREATED && r.status !== ProcurementStatus.PROCUREMENT_NEEDED && r.status !== ProcurementStatus.ISSUED && r.status !== ProcurementStatus.SUBMITTED && (
                    <div>
                      <p className="text-xs text-slate-500">Authorized By (Manager/Finance)</p>
                      {r.authorizedBySignature ? <img src={r.authorizedBySignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                    </div>
                 )}
               </div>
             </Card>

             <Card title="History Log">
               <ul className="space-y-3 relative border-l border-slate-200 ml-2 pl-4">
                 {r.logs.map((log, i) => (
                   <li key={i} className="text-xs">
                     <div className="absolute w-2 h-2 bg-slate-300 rounded-full -left-[5px] mt-1"></div>
                     <p className="font-semibold text-slate-700">{log.action}</p>
                     <p className="text-slate-500">{new Date(log.date).toLocaleString()} by {log.actor}</p>
                   </li>
                 ))}
               </ul>
             </Card>
          </div>
        </div>
      )}

      {/* Modals */}
      {modalOpen === 'ISSUE' && <IssueStockModal onClose={() => setModalOpen(null)} onConfirm={handleIssueConfirm} />}
      {modalOpen === 'BUDGET' && <BudgetModal onClose={() => setModalOpen(null)} onConfirm={handleBudgetConfirm} />}
      {modalOpen === 'SINGLE' && <SingleSourceModal onClose={() => setModalOpen(null)} onConfirm={handleSingleSourceConfirm} />}
      {modalOpen === 'EVAL' && <EvaluationModal vendors={vendors} onClose={() => setModalOpen(null)} onConfirm={handleEvaluationConfirm} />}
      {modalOpen === 'RECEIVE' && <ReceiveGoodsModal initialItems={initialReceiveData} inventory={inventory} onClose={() => setModalOpen(null)} onConfirm={handleReceiveConfirm} />}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { LogService, ProcurementService, InventoryService, AssetService, SettingsService } from '../services/mockService';
import { LogEntry, ProcurementWorkflow, InventoryItem, Asset, ProcurementStatus, ItemCategory, SystemSettings } from '../types';
import { Card, Button, Input } from './SharedComponents';
import { RefreshCw, Filter, Download, PieChart as PieChartIcon, BarChart3, AlertTriangle, FileText, Activity, Printer, ArrowLeft, FileSpreadsheet } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, LineChart, Line, Legend } from 'recharts';

type ReportTab = 'FINANCIAL' | 'INVENTORY' | 'AUDIT';

export const ReportsView = () => {
  const [activeTab, setActiveTab] = useState<ReportTab>('FINANCIAL');
  const [isLoading, setIsLoading] = useState(false);
  const [isPrintMode, setIsPrintMode] = useState(false);

  // Data State
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [requests, setRequests] = useState<ProcurementWorkflow[]>([]);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [settings, setSettings] = useState<SystemSettings | null>(null);

  // Filter State
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().getFullYear(), 0, 1).toISOString().split('T')[0], // Start of current year
    end: new Date().toISOString().split('T')[0]
  });
  const [deptFilter, setDeptFilter] = useState('ALL');
  const [auditCategory, setAuditCategory] = useState('ALL');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setIsLoading(true);
    const [l, r, i, a, s] = await Promise.all([
      LogService.getAll(),
      ProcurementService.getAll(),
      InventoryService.getAll(),
      AssetService.getAll(),
      SettingsService.get()
    ]);
    setLogs(l);
    setRequests(r);
    setInventory(i);
    setAssets(a);
    setSettings(s);
    setIsLoading(false);
  };

  // --- Helpers for Filtering ---
  const filterByDate = (dateStr: string) => {
    return dateStr >= dateRange.start && dateStr <= dateRange.end;
  };

  const getUniqueDepartments = () => {
    const depts = new Set(requests.map(r => r.requesterDepartment));
    return ['ALL', ...Array.from(depts)];
  };

  // --- Aggregation Logic ---

  // 1. Cost & Consumption Data
  const financialData = useMemo(() => {
    let filtered = requests.filter(r => filterByDate(r.requestDate));
    if (deptFilter !== 'ALL') filtered = filtered.filter(r => r.requesterDepartment === deptFilter);

    // Filter for completed/approved spend
    const spendRequests = filtered.filter(r => 
      r.status === ProcurementStatus.PO_ISSUED || 
      r.status === ProcurementStatus.COMPLETED
    );

    // Calculate Total Spend
    const totalSpend = spendRequests.reduce((acc, r) => {
        const quotePrice = r.quotations?.find(q => q.selected)?.price || 0;
        return acc + quotePrice;
    }, 0);

    // Chart: Spend by Month
    const spendByMonth = spendRequests.reduce((acc, r) => {
        const month = new Date(r.requestDate).toLocaleString('default', { month: 'short' });
        const cost = r.quotations?.find(q => q.selected)?.price || 0;
        acc[month] = (acc[month] || 0) + cost;
        return acc;
    }, {} as Record<string, number>);

    const spendChartData = Object.entries(spendByMonth).map(([name, value]) => ({ name, value }));

    // Chart: Consumption by Department (Count of requests)
    const reqByDept = filtered.reduce((acc, r) => {
        acc[r.requesterDepartment] = (acc[r.requesterDepartment] || 0) + 1;
        return acc;
    }, {} as Record<string, number>);

    const deptChartData = Object.entries(reqByDept).map(([name, value]) => ({ name, value }));

    return { totalSpend, spendChartData, deptChartData, transactionCount: filtered.length, filteredRequests: filtered, spendRequests };
  }, [requests, dateRange, deptFilter]);

  // 2. Inventory Reports
  const inventoryReport = useMemo(() => {
    // Current Valuation (Qty * Price)
    const valuation = inventory.reduce((acc, item) => acc + (item.quantity * item.pricePerUnit), 0);
    const assetValuation = assets.reduce((acc, a) => acc + a.price, 0);

    // Low Stock Items
    const lowStockItems = inventory.filter(i => i.quantity <= i.minStockLevel);

    // Category Distribution
    const catDist = inventory.reduce((acc, item) => {
        acc[item.category] = (acc[item.category] || 0) + item.quantity;
        return acc;
    }, {} as Record<string, number>);

    const pieData = Object.entries(catDist).map(([name, value]) => ({ name, value }));

    return { valuation, assetValuation, lowStockItems, pieData };
  }, [inventory, assets]);

  // 3. Audit Filter (Memoized for Export)
  const filteredLogs = useMemo(() => {
    return logs.filter(l => {
        const dateMatch = filterByDate(l.date.split('T')[0]);
        const catMatch = auditCategory === 'ALL' || l.category === auditCategory;
        return dateMatch && catMatch;
    });
  }, [logs, dateRange, auditCategory]);

  // --- Export Logic ---

  const escapeCsv = (str: string | number | undefined | null) => {
    if (str === null || str === undefined) return '';
    const stringValue = String(str);
    if (stringValue.includes(',') || stringValue.includes('"') || stringValue.includes('\n')) {
      return `"${stringValue.replace(/"/g, '""')}"`;
    }
    return stringValue;
  };

  const downloadCSV = (headers: string[], data: any[], filename: string) => {
    const csvContent = [
      headers.join(','),
      ...data.map(row => row.map(escapeCsv).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    if (link.download !== undefined) {
      const url = URL.createObjectURL(blob);
      link.setAttribute('href', url);
      link.setAttribute('download', filename);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  const handleExportCSV = () => {
    const dateStr = new Date().toISOString().split('T')[0];

    if (activeTab === 'FINANCIAL') {
       // Export Financial Data
       const headers = ['Ref Number', 'Request Date', 'Status', 'Department', 'Requester', 'Selected Vendor', 'Total Amount', 'Items Summary'];
       const rows = financialData.spendRequests.map(r => [
          r.poNumber || r.gsrfRefNumber,
          new Date(r.requestDate).toLocaleDateString(),
          r.status,
          r.requesterDepartment,
          r.requesterName,
          r.selectedVendor || 'N/A',
          (r.quotations?.find(q => q.selected)?.price || 0).toFixed(2),
          r.items.map(i => `${i.description} (${i.quantity})`).join('; ')
       ]);
       downloadCSV(headers, rows, `financial_report_${dateStr}.csv`);
    } else if (activeTab === 'INVENTORY') {
       // Export Inventory
       const headers = ['SKU', 'Gov ID', 'Item Name', 'Category', 'Location', 'Quantity', 'Unit Price', 'Total Value', 'Last Updated'];
       const rows = inventory.map(i => [
          i.sku,
          i.govId,
          i.name,
          i.category,
          i.location,
          i.quantity,
          i.pricePerUnit.toFixed(2),
          (i.quantity * i.pricePerUnit).toFixed(2),
          new Date(i.lastUpdated).toLocaleDateString()
       ]);
       downloadCSV(headers, rows, `inventory_snapshot_${dateStr}.csv`);
    } else if (activeTab === 'AUDIT') {
       // Export Logs
       const headers = ['Timestamp', 'Category', 'Action', 'Actor', 'Details', 'Reference ID'];
       const rows = filteredLogs.map(l => [
          l.date,
          l.category,
          l.action,
          l.actor,
          l.details,
          l.referenceId || ''
       ]);
       downloadCSV(headers, rows, `audit_logs_${dateStr}.csv`);
    }
  };

  const handlePrint = () => {
      setTimeout(() => window.print(), 100);
  };

  const renderPrintHeader = (title: string) => (
      <div className="flex flex-col items-center mb-6 border-b-2 border-black pb-4 text-center">
          {settings?.templateConfig?.showLogo && settings?.logoUrl && (
             <img src={settings.logoUrl} alt="Logo" className="h-16 object-contain mb-2" />
          )}
          <h1 className="text-xl font-bold uppercase tracking-wider mb-1 font-serif">
              {settings?.officeName || 'Government Entity'}
          </h1>
          <h2 className="text-sm uppercase text-slate-600 mb-2 font-serif">
              {settings?.departmentName}
          </h2>
          <p className="text-[10px] text-slate-500 mb-4 whitespace-pre-line">
              {settings?.officeAddress}
          </p>
          <div className="w-full flex justify-between items-end mt-4 border-t pt-2">
            <div>
              <p className="text-sm font-bold uppercase">Report: {title}</p>
              <p className="text-xs text-slate-500">Filters: {dateRange.start} to {dateRange.end} | Dept: {deptFilter}</p>
            </div>
            <div className="text-right">
              <p className="text-xs text-slate-500">Generated On: {new Date().toLocaleString()}</p>
            </div>
          </div>
      </div>
  );

  const renderPrintFooter = () => (
      <div className="mt-8 pt-4 border-t border-slate-300 text-center text-[10px] text-slate-500">
          <p>{settings?.templateConfig?.footerText || 'System Generated Report'}</p>
      </div>
  );


  // --- Renderers ---

  const renderFinancialTab = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 print:grid-cols-3">
        <Card className="bg-white border-l-4 border-l-green-500 print:border">
           <div className="text-slate-500 text-sm font-medium uppercase">Total Procurement Cost</div>
           <div className="text-2xl font-bold text-slate-800 mt-1">${financialData.totalSpend.toLocaleString()}</div>
           <div className="text-xs text-slate-400 mt-2">Based on issued POs in period</div>
        </Card>
        <Card className="bg-white border-l-4 border-l-blue-500 print:border">
           <div className="text-slate-500 text-sm font-medium uppercase">Total Requisitions</div>
           <div className="text-2xl font-bold text-slate-800 mt-1">{financialData.transactionCount}</div>
           <div className="text-xs text-slate-400 mt-2">Requests processed in period</div>
        </Card>
        <Card className="bg-white border-l-4 border-l-purple-500 print:border">
           <div className="text-slate-500 text-sm font-medium uppercase">Avg Cost per Request</div>
           <div className="text-2xl font-bold text-slate-800 mt-1">
             ${financialData.transactionCount > 0 ? (financialData.totalSpend / financialData.transactionCount).toFixed(2) : '0.00'}
           </div>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 print:grid-cols-2 print:gap-4">
         <Card title="Monthly Procurement Spend" className="print:break-inside-avoid">
            <div className="h-64 w-full">
               <ResponsiveContainer width="100%" height="100%">
                 <LineChart data={financialData.spendChartData}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="name" />
                    <YAxis />
                    <Tooltip formatter={(val: number) => `$${val}`} />
                    <Legend />
                    <Line type="monotone" dataKey="value" name="Spend ($)" stroke="#0ea5e9" strokeWidth={2} />
                 </LineChart>
               </ResponsiveContainer>
            </div>
         </Card>
         <Card title="Requisitions by Department" className="print:break-inside-avoid">
            <div className="h-64 w-full">
               <ResponsiveContainer width="100%" height="100%">
                 <BarChart data={financialData.deptChartData} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis type="number" />
                    <YAxis dataKey="name" type="category" width={100} style={{fontSize: '10px'}} />
                    <Tooltip />
                    <Bar dataKey="value" name="Requests" fill="#8884d8" barSize={20} />
                 </BarChart>
               </ResponsiveContainer>
            </div>
         </Card>
      </div>

      <Card title="Detailed Cost Report" className="print:shadow-none print:border-none">
         <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-slate-200 text-sm print:text-xs">
               <thead className="bg-slate-50">
                  <tr>
                     <th className="px-4 py-2 text-left text-slate-500">Ref No</th>
                     <th className="px-4 py-2 text-left text-slate-500">Date</th>
                     <th className="px-4 py-2 text-left text-slate-500">Department</th>
                     <th className="px-4 py-2 text-left text-slate-500">Vendor</th>
                     <th className="px-4 py-2 text-right text-slate-500">Amount</th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-slate-200">
                  {financialData.spendRequests.map(r => (
                       <tr key={r.id}>
                          <td className="px-4 py-2 font-mono text-xs">{r.poNumber || r.gsrfRefNumber}</td>
                          <td className="px-4 py-2">{new Date(r.requestDate).toLocaleDateString()}</td>
                          <td className="px-4 py-2">{r.requesterDepartment}</td>
                          <td className="px-4 py-2">{r.selectedVendor || 'N/A'}</td>
                          <td className="px-4 py-2 text-right font-medium">${(r.quotations?.find(q => q.selected)?.price || 0).toLocaleString()}</td>
                       </tr>
                  ))}
                  <tr className="bg-slate-50 font-bold">
                      <td colSpan={4} className="px-4 py-2 text-right">TOTAL</td>
                      <td className="px-4 py-2 text-right">${financialData.totalSpend.toLocaleString()}</td>
                  </tr>
               </tbody>
            </table>
         </div>
      </Card>
    </div>
  );

  const renderInventoryTab = () => {
    const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];
    return (
      <div className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 print:grid-cols-2">
           <Card title="Inventory Distribution" className="print:break-inside-avoid">
              <div className="h-64 flex items-center justify-center">
                 <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={inventoryReport.pieData}
                        cx="50%"
                        cy="50%"
                        labelLine={false}
                        outerRadius={80}
                        fill="#8884d8"
                        dataKey="value"
                        label={({ name, percent }) => `${(percent * 100).toFixed(0)}%`}
                      >
                        {inventoryReport.pieData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip />
                      <Legend />
                    </PieChart>
                 </ResponsiveContainer>
              </div>
           </Card>

           <div className="space-y-6">
              <Card className="bg-slate-50 print:break-inside-avoid">
                 <h3 className="text-sm font-bold text-slate-500 uppercase mb-2">Total Valuation</h3>
                 <div className="space-y-2">
                    <div className="flex justify-between items-center border-b pb-2">
                       <span>Consumables Stock</span>
                       <span className="font-bold text-lg">${inventoryReport.valuation.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center border-b pb-2">
                       <span>Fixed Assets Registry</span>
                       <span className="font-bold text-lg">${inventoryReport.assetValuation.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between items-center pt-1">
                       <span className="font-bold text-slate-800">Total Holdings</span>
                       <span className="font-bold text-xl text-green-700">${(inventoryReport.valuation + inventoryReport.assetValuation).toLocaleString()}</span>
                    </div>
                 </div>
              </Card>

              {inventoryReport.lowStockItems.length > 0 && (
                 <div className="bg-red-50 border border-red-200 rounded-lg p-4 print:break-inside-avoid">
