import React, { useState, useRef } from 'react';
import { User, InventoryItem } from '../../types';
import { Button, Card, Input, SignaturePad } from '../SharedComponents';
import { Plus, List, FileText, Barcode } from 'lucide-react';

interface ProcurementCreateProps {
  user: User;
  inventory: InventoryItem[];
  onCancel: () => void;
  onSubmit: (data: any) => void;
}

export const ProcurementCreate: React.FC<ProcurementCreateProps> = ({ user, inventory, onCancel, onSubmit }) => {
  const [section, setSection] = useState(user.department);
  const [requiredDate, setRequiredDate] = useState('');
  const [remarks, setRemarks] = useState('');

  // Item Entry State
  const [itemEntryMode, setItemEntryMode] = useState<'INVENTORY' | 'CUSTOM' | 'BARCODE'>('INVENTORY');
  const [selectedInventoryId, setSelectedInventoryId] = useState('');
  const [newItemDesc, setNewItemDesc] = useState('');
  const [newItemQty, setNewItemQty] = useState(1);
  const [barcodeInput, setBarcodeInput] = useState('');
  const [scanStatus, setScanStatus] = useState<{msg: string, type: 'success' | 'error' | 'neutral'}>({msg: '', type: 'neutral'});

  const [requestItems, setRequestItems] = useState<{itemId?: string, description: string, quantity: number}[]>([]);
  const [signature, setSignature] = useState(user.signatureUrl || '');

  const sections = ['Administration', 'Finance', 'Human Resources', 'IT / Technical', 'Operations', 'Logistics', 'Executive Office'];

  const handleBarcodeScan = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      const code = barcodeInput.trim();
      if (!code) return;

      // Search by Barcode or SKU
      const foundItem = inventory.find(i => 
        (i.barcode && i.barcode === code) || 
        (i.sku && i.sku.toLowerCase() === code.toLowerCase())
      );

      if (foundItem) {
        setSelectedInventoryId(foundItem.id);
        setNewItemDesc(foundItem.name);
        setNewItemQty(1); // Reset to 1 default
        setScanStatus({ msg: `Found: ${foundItem.name} (Stock: ${foundItem.quantity})`, type: 'success' });
        setBarcodeInput(''); // Clear for next scan if needed, though usually we want to add first
      } else {
        setScanStatus({ msg: `Item not found for code: ${code}`, type: 'error' });
        setSelectedInventoryId('');
        setNewItemDesc('');
      }
    }
  };

  const addItemToRequest = () => {
    if(!newItemDesc) return;

    setRequestItems([...requestItems, { 
        description: newItemDesc, 
        quantity: newItemQty,
        itemId: (itemEntryMode === 'INVENTORY' || itemEntryMode === 'BARCODE') ? selectedInventoryId : undefined
    }]);

    // Reset fields
    setNewItemDesc('');
    setNewItemQty(1);
    setSelectedInventoryId('');
    setBarcodeInput('');
    setScanStatus({ msg: '', type: 'neutral' });

    // If in barcode mode, focus might need to go back to input (handled by autoFocus usually)
  };

  const handleSubmit = () => {
    onSubmit({
      section,
      requiredDate,
      remarks,
      items: requestItems,
      requesterSignature: signature
    });
  };

  return (
    <Card title="New Goods & Service Requisition Form (GSRF)">
      <div className="space-y-6 max-w-3xl">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
           <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Select Section</label>
              <select 
                className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                value={section}
                onChange={e => setSection(e.target.value)}
              >
                <option value="">-- Select Section --</option>
                {sections.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
           </div>
           <Input 
             type="date" 
             label="Required Date" 
             value={requiredDate} 
             onChange={e => setRequiredDate(e.target.value)} 
           />
        </div>

        <div>
           <label className="block text-sm font-medium text-slate-700 mb-1">Remarks / Purpose of Use</label>
           <textarea 
             className="flex w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-gov-500 h-24 resize-none"
             placeholder="Enter use case or details..."
             value={remarks}
             onChange={e => setRemarks(e.target.value)}
           />
        </div>

        <div className="bg-slate-50 p-4 rounded-md border border-slate-200">
          <h3 className="text-sm font-medium mb-3">Add Items</h3>

          <div className="flex flex-wrap gap-4 mb-4 text-sm">
              <label className="flex items-center gap-2 cursor-pointer">
                  <input 
                      type="radio" 
                      name="itemMode"
                      checked={itemEntryMode === 'INVENTORY'}
                      onChange={() => {
                          setItemEntryMode('INVENTORY');
                          setNewItemDesc('');
                          setScanStatus({ msg: '', type: 'neutral' });
                      }}
                      className="text-gov-600 focus:ring-gov-500"
                  />
                  <span className="font-medium text-slate-700 flex items-center gap-1"><List className="w-4 h-4"/> Select from Inventory</span>
              </label>
              <label className="flex items-center gap-2 cursor-pointer">
                  <input 
                      type="radio" 
                      name="itemMode"
                      checked={itemEntryMode === 'BARCODE'}
                      onChange={() => {
                          setItemEntryMode('BARCODE');
                          setNewItemDesc('');
                          setSelectedInventoryId('');
                      }}
                      className="text-gov-600 focus:ring-gov-500"
                  />
                  <span className="font-medium text-slate-700 flex items-center gap-1"><Barcode className="w-4 h-4"/> Scan Barcode</span>
              </label>
              <label className="flex items-center gap-2 cursor-pointer">
                  <input 
                      type="radio" 
                      name="itemMode"
                      checked={itemEntryMode === 'CUSTOM'}
                      onChange={() => {
                          setItemEntryMode('CUSTOM');
                          setSelectedInventoryId('');
                          setNewItemDesc('');
                          setScanStatus({ msg: '', type: 'neutral' });
                      }}
                      className="text-gov-600 focus:ring-gov-500"
                  />
                  <span className="font-medium text-slate-700 flex items-center gap-1"><FileText className="w-4 h-4"/> Custom / Ad-hoc Item</span>
              </label>
          </div>

          <div className="flex gap-2 mb-2 items-start">
            <div className="flex-1">
               {itemEntryMode === 'INVENTORY' && (
                   <select
                      className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                      value={selectedInventoryId}
                      onChange={(e) => {
                          const selected = inventory.find(i => i.id === e.target.value);
                          if (selected) {
                              setSelectedInventoryId(selected.id);
                              setNewItemDesc(selected.name);
                          } else {
                              setSelectedInventoryId('');
                              setNewItemDesc('');
                          }
                      }}
                   >
                      <option value="">-- Search/Select Inventory Item --</option>
                      {inventory.map(item => (
                          <option key={item.id} value={item.id}>
                              {item.name} (Stock: {item.quantity}) - SKU: {item.sku}
                          </option>
                      ))}
                   </select>
               )}

               {itemEntryMode === 'BARCODE' && (
                  <div>
                    <input 
                        className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500 mb-2"
                        placeholder="Click here and scan barcode or type SKU + Enter"
                        value={barcodeInput}
                        onChange={(e) => setBarcodeInput(e.target.value)}
                        onKeyDown={handleBarcodeScan}
                        autoFocus
                    />
                    {scanStatus.msg && (
                        <div className={`text-xs p-2 rounded mb-2 font-bold ${scanStatus.type === 'success' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                           {scanStatus.msg}
                        </div>
                    )}
                    {newItemDesc && (
                        <div className="text-sm font-medium p-2 bg-slate-100 rounded border border-slate-200 text-slate-700">
                           Selected: {newItemDesc}
                        </div>
                    )}
                  </div>
               )}

               {itemEntryMode === 'CUSTOM' && (
                  <Input 
                      placeholder="Item Description" 
                      value={newItemDesc} 
                      onChange={e => setNewItemDesc(e.target.value)} 
                      className="mb-0"
                  />
               )}
            </div>
            <Input 
              type="number" 
              placeholder="Qty" 
              value={newItemQty} 
              onChange={e => setNewItemQty(parseInt(e.target.value) || 1)} 
              className="w-24 mb-0"
              min={1}
            />
            <Button onClick={addItemToRequest} size="sm" icon={Plus} type="button" className="h-10 mt-0" disabled={!newItemDesc}>Add</Button>
          </div>

          <ul className="text-sm space-y-1 mt-3">
            {requestItems.map((item, idx) => (
              <li key={idx} className="flex justify-between border-b border-slate-200 py-2 items-center">
                <div className="flex items-center gap-2">
                   {item.itemId ? <span className="bg-blue-100 text-blue-800 text-[10px] font-bold px-1.5 py-0.5 rounded">INV</span> : <span className="bg-slate-100 text-slate-600 text-[10px] font-bold px-1.5 py-0.5 rounded">ADHOC</span>}
                   <span>{item.description}</span>
                </div>
                <span className="font-mono bg-slate-100 px-2 rounded">{item.quantity}</span>
              </li>
            ))}
            {requestItems.length === 0 && <li className="text-slate-400 italic text-center py-2">No items added yet.</li>}
          </ul>
        </div>

        <SignaturePad 
            onChange={setSignature} 
            label="Requester Signature" 
            initialValue={user.signatureUrl} 
        />

        <div className="flex justify-end gap-2 pt-4">
          <Button variant="outline" onClick={onCancel}>Cancel</Button>
          <Button disabled={requestItems.length === 0 || !signature} onClick={handleSubmit}>Submit Request</Button>
        </div>
      </div>
    </Card>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { LogService, ProcurementService, InventoryService, AssetService, SettingsService } from '../services/mockService';
import { LogEntry, ProcurementWorkflow, InventoryItem, Asset, ProcurementStatus, ItemCategory, SystemSettings } from '../types';
import { Card, Button, Input } from './SharedComponents';
import { RefreshCw, Filter, Download, PieChart as PieChartIcon, BarChart3, AlertTriangle, FileText, Activity, Printer, ArrowLeft, FileSpreadsheet } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, LineChart, Line, Legend } from 'recharts';

type ReportTab = 'FINANCIAL' | 'INVENTORY' | 'AUDIT';

export const ReportsView = () => {
  const [activeTab, setActiveTab] = useState<ReportTab>('FINANCIAL');
  const [isLoading, setIsLoading] = useState(false);
  const [isPrintMode, setIsPrintMode] = useState(false);

  // Data State
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [requests, setRequests] = useState<ProcurementWorkflow[]>([]);
  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [settings, setSettings] = useState<SystemSettings | null>(null);

  // Filter State
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().getFullYear(), 0, 1).toISOString().split('T')[0], // Start of current year
    end: new Date().toISOString().split('T')[0]
  });
  const [deptFilter, setDeptFilter] = useState('ALL');
  const [auditCategory, setAuditCategory] = useState('ALL');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setIsLoading(true);
    const [l, r, i, a, s] = await Promise.all([
      LogService.getAll(),
      ProcurementService.getAll(),
      InventoryService.getAll(),
      AssetService.getAll(),
      SettingsService.get()
    ]);
    setLogs(l);
    setRequests(r);
    setInventory(i);
    setAssets(a);
    setSettings(s);
    setIsLoading(false);
  };

  // --- Helpers for Filtering ---
  const filterByDate = (dateStr: string) => {
    return dateStr >= dateRange.start && dateStr <= dateRange.end;
  };

  const getUniqueDepartments = () => {
    const depts = new Set(requests.map(r => r.requesterDepartment));
    return ['ALL', ...Array.from(depts)];
  };

  // --- Aggregation Logic ---

  // 1. Cost & Consumption Data
  const financialData = useMemo(() => {
    let filtered = requests.filter(r => filterByDate(r.requestDate));
    if (deptFilter !== 'ALL') filtered = filtered.filter(r => r.requesterDepartment === deptFilter);

    // Filter for completed/approved spend
    const spendRequests = filtered.filter(r => 
      r.status === ProcurementStatus.PO_ISSUED || 
      r.status === ProcurementStatus.COMPLETED
    );

    // Calculate Total Spend
    const totalSpend = spendRequests.reduce((acc, r) => {
        const quotePrice = r.quotations?.find(q => q.selected)?.price || 0;
        return acc + quotePrice;
    }, 0);

    // Chart: Spend by Month
    const spendByMonth = spendRequests.reduce((acc, r) => {
        const month = new Date(r.requestDate).toLocaleString('default', { month: 'short' });
        const cost = r.quotations?.find(q => q.selected)?.price || 0;
        acc[month] = (acc[month] || 0) + cost;
        return acc;
    }, {} as Record<string, number>);

    const spendChartData = Object.entries(spendByMonth).map(([name, value]) => ({ name, value }));

    // Chart: Consumption by Department (Count of requests)
    const reqByDept = filtered.reduce((acc, r) => {
        acc[r.requesterDepartment] = (acc[r.requesterDepartment] || 0) + 1;
        return acc;
    }, {} as Record<string, number>);

    const deptChartData = Object.entries(reqByDept).map(([name, value]) => ({ name, value }));

    return { totalSpend, spendChartData, deptChartData, transactionCount: filtered.length, filteredRequests: filtered, spendRequests };
  }, [requests, dateRange, deptFilter]);

  // 2. Inventory Reports
  const inventoryReport = useMemo(() => {
    // Current Valuation (Qty * Price)
    const valuation = inventory.reduce((acc, item) => acc + (item.quantity * item.pricePerUnit), 0);
    const assetValuation = assets.reduce((acc, a) => acc + a.price, 0);

    // Low Stock Items
    const lowStockItems = inventory.filter(i => i.quantity <= i.minStockLevel);

    // Category Distribution
    const catDist = inventory.reduce((acc, item) => {
        acc[item.category] = (acc[item.category] || 0) + item.quantity;
        return acc;
    }, {} as Record<string, number>);

    const pieData = Object.entries(catDist).map(([name, value]) => ({ name, value }));

    return { valuation, assetValuation, lowStockItems, pieData };
  }, [inventory, assets]);

  // 3. Audit Filter (Memoized for Export)
  const filteredLogs = useMemo(() => {
    return logs.filter(l => {
        const dateMatch = filterByDate(l.date.split('T')[0]);
        const catMatch = auditCategory === 'ALL' || l.category === auditCategory;
        return dateMatch && catMatch;
    });
  }, [logs, dateRange, auditCategory]);

  // --- Export Logic ---

  const escapeCsv = (str: string | number | undefined | null) => {
    if (str === null || str === undefined) return '';
    const stringValue = String(str);
    if (stringValue.includes(',') || stringValue.includes('"') || stringValue.includes('\n')) {
      return `"${stringValue.replace(/"/g, '""')}"`;
    }
    return stringValue;
  };

  const downloadCSV = (headers: string[], data: any[], filename: string) => {
    const csvContent = [
      headers.join(','),
      ...data.map(row => row.map(escapeCsv).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    if (link.download !== undefined) {
      const url = URL.createObjectURL(blob);
      link.setAttribute('href', url);
      link.setAttribute('download', filename);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  const handleExportCSV = () => {
