            <div className="p-8 flex justify-center bg-slate-100">
               {/* Printable Area */}
               <div className="printable-area bg-white border-2 border-black w-[400px] h-[250px] p-4 flex flex-col justify-between relative shadow-sm">
                  <div className="text-center border-b-2 border-black pb-2 mb-2">
                     <h2 className="font-bold text-xl uppercase tracking-wider">{settings?.officeName || 'GOV PROPERTY'}</h2>
                     <p className="text-xs uppercase text-slate-600">Fixed Asset Management Registry</p>
                  </div>

                  <div className="flex gap-4 items-center flex-1">
                     <div className="bg-white p-1">
                        <QRCode 
                          value={JSON.stringify({
                            id: selectedAssetForLabel.govId,
                            name: selectedAssetForLabel.name,
                            date: selectedAssetForLabel.purchaseDate,
                            price: selectedAssetForLabel.price
                          })} 
                          size={100}
                          level="M"
                        />
                     </div>
                     <div className="flex-1 text-sm space-y-1">
                        <div>
                          <span className="block text-[10px] font-bold text-slate-500 uppercase">Gov Asset ID</span>
                          <span className="font-mono font-bold text-lg leading-none">{selectedAssetForLabel.govId}</span>
                        </div>
                        <div>
                          <span className="block text-[10px] font-bold text-slate-500 uppercase">Item Description</span>
                          <span className="font-semibold leading-tight block">{selectedAssetForLabel.name}</span>
                        </div>
                        <div className="flex justify-between pt-1">
                           <div>
                              <span className="block text-[10px] font-bold text-slate-500 uppercase">Purchased</span>
