export const OFFICE_CODE = "263";

import React, { useState, useEffect } from 'react';
import { AuthService, SettingsService, UserService } from '../services/mockService';
import { SystemSettings, UserRole, User, TemplateBlock } from '../types';
import { Card, Button, Input, SignaturePad } from './SharedComponents';
import { Save, Building, FileText, LayoutTemplate, User as UserIcon, Users, Lock, Edit2, RefreshCw, Plus, Mail, Phone, Briefcase, BadgeCheck, PenTool, Type, AlignLeft, Minus, Image as ImageIcon, Trash2, GripVertical } from 'lucide-react';

export const SettingsView = () => {
  const [currentUser, setCurrentUser] = useState(AuthService.getCurrentUser());
  const [settings, setSettings] = useState<SystemSettings | null>(null);
  const [activeSection, setActiveSection] = useState<'PROFILE' | 'ORG' | 'PREFIXES' | 'TEMPLATE' | 'USERS'>('PROFILE');
  const [isSaving, setIsSaving] = useState(false);

  // Profile & Password State
  const [profileForm, setProfileForm] = useState({
    name: '',
    email: '',
    designation: '',
    phone: ''
  });
  const [signature, setSignature] = useState('');
  const [passForm, setPassForm] = useState({ current: '', new: '', confirm: '' });

  // User Management State
  const [users, setUsers] = useState<User[]>([]);
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> | null>(null);
  const [passwordResetMode, setPasswordResetMode] = useState(false);
  const [newPassword, setNewPassword] = useState('');

  // Template Builder State
  const [builderTab, setBuilderTab] = useState<'CONTENT' | 'SETTINGS'>('CONTENT');

  useEffect(() => {
    SettingsService.get().then(setSettings);
    UserService.getAll().then(setUsers);

    // Initialize profile form
    setProfileForm({
      name: currentUser.name,
      email: currentUser.email,
      designation: currentUser.designation || '',
      phone: currentUser.phone || ''
    });
    setSignature(currentUser.signatureUrl || '');
  }, [currentUser]); // Refresh if user switches

  const handleSave = async () => {
    if (settings) {
      setIsSaving(true);
      await SettingsService.update(settings);
      // Simulate network delay
      setTimeout(() => setIsSaving(false), 800);
    }
  };

  const handleProfileUpdate = async () => {
     setIsSaving(true);
     const updatedUser = { 
        ...currentUser, 
        name: profileForm.name,
        email: profileForm.email,
        designation: profileForm.designation,
        phone: profileForm.phone,
        signatureUrl: signature
     };
     await UserService.update(updatedUser);
     setCurrentUser(updatedUser);
     setIsSaving(false);
     alert("Profile updated successfully.");
  };

  const handlePasswordChange = async () => {
     if (!passForm.current || !passForm.new || !passForm.confirm) {
        alert("Please fill all password fields.");
        return;
     }
     if (passForm.new !== passForm.confirm) {
        alert("New passwords do not match.");
        return;
     }
     setIsSaving(true);
     await UserService.changePassword(currentUser.id, passForm.current, passForm.new);
     setPassForm({ current: '', new: '', confirm: '' });
     setIsSaving(false);
     alert("Password changed successfully.");
  };

  const handleUserSwitch = (id: string) => {
    const newUser = AuthService.switchUser(id);
    setCurrentUser(newUser);
    window.location.reload(); // Simple reload to refresh app state with new user
  };

  const openEditUser = (user: User) => {
    setEditingUser({...user});
    setPasswordResetMode(false);
    setNewPassword('');
    setShowUserModal(true);
  };

  const handleSaveUser = async () => {
    if (editingUser && editingUser.id && editingUser.name) {
      if (passwordResetMode && newPassword) {
        await UserService.resetPassword(editingUser.id, newPassword);
      }
      await UserService.update(editingUser as User);
      setUsers(await UserService.getAll());
      setShowUserModal(false);
    }
  };

  // --- Builder Logic ---
  const addBlock = (type: TemplateBlock['type']) => {
    if (!settings) return;
    const newBlock: TemplateBlock = {
        id: Math.random().toString(36).substr(2, 9),
        type,
        content: type === 'title' ? 'New Title Here' : type === 'text' ? 'Enter your text content here...' : '',
    };
    const currentBlocks = settings.templateConfig.customBlocks || [];
    setSettings({
        ...settings,
        templateConfig: {
            ...settings.templateConfig,
            customBlocks: [...currentBlocks, newBlock]
        }
    });
  };

  const updateBlock = (id: string, content: string) => {
      if (!settings) return;
      const blocks = settings.templateConfig.customBlocks?.map(b => b.id === id ? { ...b, content } : b) || [];
      setSettings({
          ...settings,
          templateConfig: { ...settings.templateConfig, customBlocks: blocks }
      });
  };

  const removeBlock = (id: string) => {
      if (!settings) return;
      const blocks = settings.templateConfig.customBlocks?.filter(b => b.id !== id) || [];
      setSettings({
          ...settings,
          templateConfig: { ...settings.templateConfig, customBlocks: blocks }
      });
  };

  if (!settings) return <div>Loading settings...</div>;

  const NavItem = ({ id, label, icon: Icon }: any) => (
    <button
      onClick={() => setActiveSection(id)}
      className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-lg transition-colors mb-1 ${
        activeSection === id ? 'bg-gov-100 text-gov-800' : 'text-slate-600 hover:bg-slate-50'
      }`}
    >
      <Icon className="w-4 h-4" />
      {label}
    </button>
  );

  return (
    <div className="flex flex-col md:flex-row gap-6 max-w-7xl h-[calc(100vh-100px)]">
      {/* Settings Navigation */}
      <div className="w-full md:w-64 flex-shrink-0">
         <Card className="h-full">
            <h3 className="font-bold text-slate-800 mb-4 px-2">Settings</h3>
            <nav>
               <NavItem id="PROFILE" label="User Profile" icon={UserIcon} />
               <NavItem id="ORG" label="Organization Details" icon={Building} />
               <NavItem id="PREFIXES" label="Document Prefixes" icon={FileText} />
               <NavItem id="TEMPLATE" label="Template Builder" icon={LayoutTemplate} />
               {currentUser.role === UserRole.ADMIN && (
                 <NavItem id="USERS" label="User Management" icon={Users} />
               )}
            </nav>
         </Card>
      </div>

      {/* Settings Content */}
      <div className="flex-1 overflow-hidden flex flex-col">
        {activeSection === 'TEMPLATE' ? (
            // --- VISUAL BUILDER UI ---
            <div className="flex h-full border border-slate-300 rounded-lg overflow-hidden bg-slate-100">
                {/* Left: Canvas / Preview */}
                <div className="flex-1 overflow-auto p-8 flex justify-center bg-[#525659]">
                    <div className="w-[210mm] min-h-[297mm] bg-white shadow-lg p-[15mm] flex flex-col relative transition-all">
                        {/* Static Header Preview */}
                        <div className="border-b-2 border-black pb-4 mb-6 opacity-50 pointer-events-none grayscale">
                            <div className="flex justify-between items-center">
                                <div>
                                    <h1 className="text-xl font-bold uppercase">{settings.officeName}</h1>
                                    <p className="text-xs">{settings.officeAddress}</p>
                                </div>
                                <div className="w-16 h-16 bg-slate-200 flex items-center justify-center text-[10px]">LOGO</div>
                            </div>
                            <div className="mt-8">
                                <div className="h-4 w-1/3 bg-slate-200 mb-2"></div>
                                <div className="h-32 bg-slate-100 border border-slate-300 flex items-center justify-center text-slate-400">
                                    STANDARD DOCUMENT CONTENT (Read Only)
                                </div>
                            </div>
                        </div>

                        {/* Dynamic Custom Blocks Area */}
                        <div className="flex-1 border-2 border-dashed border-blue-200 rounded p-4 min-h-[200px] relative group">
                            <div className="absolute top-0 left-0 bg-blue-100 text-blue-800 text-[10px] font-bold px-2 py-1 rounded-br opacity-0 group-hover:opacity-100 transition-opacity">
                                Custom Content Area
                            </div>

                            {settings.templateConfig.customBlocks?.length === 0 && (
                                <div className="flex flex-col items-center justify-center h-full text-slate-400">
                                    <p>Drag or Click blocks from the right panel to add content here.</p>
                                </div>
                            )}

                            <div className="space-y-4 mt-2">
                                {settings.templateConfig.customBlocks?.map((block, index) => (
                                    <div key={block.id} className="relative group/block hover:ring-2 hover:ring-blue-400 hover:ring-offset-2 rounded p-2 transition-all">
                                        <div className="absolute -right-3 -top-3 hidden group-hover/block:flex gap-1">
                                            <button onClick={() => removeBlock(block.id)} className="bg-red-500 text-white p-1 rounded-full shadow hover:bg-red-600" title="Remove">
                                                <Trash2 className="w-3 h-3" />
                                            </button>
                                        </div>

                                        {block.type === 'title' && (
                                            <input 
                                                className="w-full text-lg font-bold border-none focus:ring-0 bg-transparent placeholder:text-slate-300"
                                                value={block.content}
                                                onChange={(e) => updateBlock(block.id, e.target.value)}
                                                placeholder="Enter Title"
                                            />
                                        )}
                                        {block.type === 'text' && (
                                            <textarea 
                                                className="w-full text-sm resize-none border-none focus:ring-0 bg-transparent placeholder:text-slate-300"
                                                value={block.content}
                                                onChange={(e) => updateBlock(block.id, e.target.value)}
                                                placeholder="Enter text paragraph..."
                                                rows={3}
                                            />
                                        )}
                                        {block.type === 'divider' && (
                                            <hr className="border-black my-2" />
                                        )}
                                        {block.type === 'signature' && (
                                            <div className="mt-4 pt-8 border-t border-black w-48">
                                                <input 
                                                    className="w-full text-xs font-bold uppercase border-none focus:ring-0 bg-transparent p-0"
                                                    value={block.content || 'Authorized Signature'}
                                                    onChange={(e) => updateBlock(block.id, e.target.value)}
