                                            </div>
                                        )}
                                        {block.type === 'image' && (
                                            <div className="h-24 bg-slate-100 flex items-center justify-center text-slate-400 border border-slate-300 rounded">
                                                <ImageIcon className="w-8 h-8 opacity-50" />
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Footer Preview */}
                        <div className="mt-auto pt-8 border-t text-center text-[10px] text-slate-500">
                            {settings.templateConfig.footerText}
