                    </div>
                </div>

                {/* Right: Sidebar / Tools */}
                <div className="w-80 bg-white border-l border-slate-200 flex flex-col shadow-xl z-10">
                    <div className="flex border-b border-slate-200">
                        <button 
                            onClick={() => setBuilderTab('CONTENT')}
                            className={`flex-1 py-3 text-sm font-medium ${builderTab === 'CONTENT' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}
                        >
                            CONTENT
                        </button>
                        <button 
                            onClick={() => setBuilderTab('SETTINGS')}
                            className={`flex-1 py-3 text-sm font-medium ${builderTab === 'SETTINGS' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-slate-600 hover:bg-slate-50'}`}
                        >
                            SETTINGS
                        </button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 bg-slate-50/50">
                        {builderTab === 'CONTENT' && (
