                                <button onClick={() => addBlock('divider')} className="flex flex-col items-center justify-center p-4 bg-white border border-slate-200 rounded hover:shadow-md hover:border-blue-300 transition-all group">
                                    <Minus className="w-8 h-8 text-slate-400 group-hover:text-blue-500 mb-2" />
                                    <span className="text-xs font-semibold text-slate-600">Divider</span>
