                        {builderTab === 'SETTINGS' && (
                            <div className="space-y-4">
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Header Options</label>
                                    <div className="bg-white p-3 rounded border border-slate-200">
                                        <div className="flex items-center gap-2 mb-2">
                                            <input 
                                                type="checkbox" 
                                                checked={settings.templateConfig.showLogo}
                                                onChange={e => setSettings({...settings, templateConfig: {...settings.templateConfig, showLogo: e.target.checked}})}
                                                className="rounded text-blue-600"
                                            />
                                            <span className="text-sm">Show Logo</span>
                                        </div>
                                        <Input 
                                            label="Header Text" 
                                            value={settings.templateConfig.headerText || ''} 
                                            onChange={e => setSettings({...settings, templateConfig: {...settings.templateConfig, headerText: e.target.value}})} 
                                            className="mb-0 text-xs"
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Footer Options</label>
                                    <div className="bg-white p-3 rounded border border-slate-200">
