export const ProcurementService = {
  getAll: () => Promise.resolve([...MOCK_REQUESTS]),
  create: (req: Omit<ProcurementWorkflow, 'id' | 'logs' | 'gsrfRefNumber'>) => {
    const year = new Date().getFullYear();
    const count = MOCK_REQUESTS.length + 407; 
    const prefix = MOCK_SETTINGS.prefixes.gsrf;
    const gsrfRefNumber = `${prefix}/${MOCK_SETTINGS.officeCode}/${year}/${count}`;

    const newReq: ProcurementWorkflow = { 
      ...req, 
      id: Math.random().toString(36).substr(2, 9),
      gsrfRefNumber,
      logs: [{ date: new Date().toISOString(), action: 'Request Submitted', actor: req.requesterName }]
    };

    NotificationService.add({
      title: 'New Procurement Request',
      message: `${req.requesterName} submitted a new request.`,
      type: 'info',
      link: { tab: 'PROCUREMENT', itemId: newReq.id }
    });

    MOCK_REQUESTS.push(newReq);
    return Promise.resolve(newReq);
  },
  updateStatus: async (id: string, status: ProcurementStatus, logEntry: string, actor: string, updates?: Partial<ProcurementWorkflow>) => {
    const req = MOCK_REQUESTS.find(r => r.id === id);
    if (req) {
      if (status === ProcurementStatus.EVALUATION && !req.evalRefNumber) {
         const year = new Date().getFullYear();
         req.evalRefNumber = `(A)${OFFICE_CODE}/${year}/45`;
      }

      // HANDLE INVENTORY UPDATE ON ISSUE
      if (status === ProcurementStatus.ISSUED) {
          for (const item of req.items) {
              if (item.itemId) {
                  await InventoryService.updateStock(item.itemId, -item.quantity);
              }
          }
      }

      req.status = status;
      req.logs.push({ date: new Date().toISOString(), action: logEntry, actor });
      if (updates) Object.assign(req, updates);

      NotificationService.add({
          title: `Status Updated`,
          message: `Request ${req.gsrfRefNumber} moved to ${status}.`,
          type: 'info',
          link: { tab: 'PROCUREMENT', itemId: req.id }
      });
    }
    return Promise.resolve(req);
  },
  receiveGoods: async (id: string, receivedItems: any[], actor: string) => {
      const req = MOCK_REQUESTS.find(r => r.id === id);
      if (req) {
          for (const item of receivedItems) {
              if (item.inventoryAction === 'NEW') {
                  const govId = InventoryService.generateGovId(new Date().getFullYear().toString(), item.newCategory, '001');
                  await InventoryService.add({
                      name: item.description,
                      category: item.newCategory,
                      quantity: item.receivedQty,
                      location: item.newLocation || 'Main Store',
                      minStockLevel: 5,
                      pricePerUnit: item.price || 0,
                      govId
                  });
              } else {
                  await InventoryService.updateStock(item.inventoryAction, item.receivedQty);
              }
          }

          req.status = ProcurementStatus.COMPLETED;
          req.logs.push({ date: new Date().toISOString(), action: 'Goods Received & Inventory Updated', actor });
      }
      return Promise.resolve(req);
  }
};

export const AuthService = {
  getCurrentUser: () => currentUserIndex !== null ? MOCK_USERS[currentUserIndex] : null,
  login: (email: string) => {
    const idx = MOCK_USERS.findIndex(u => u.email === email);
    if (idx !== -1) {
        currentUserIndex = idx;
        return Promise.resolve(MOCK_USERS[idx]);
    }
    return Promise.reject("Invalid credentials");
  },
  logout: () => {
      currentUserIndex = null;
      return Promise.resolve();
  },
  switchUser: (id: string) => {
    const idx = MOCK_USERS.findIndex(u => u.id === id);
    if (idx !== -1) currentUserIndex = idx;
    return MOCK_USERS[currentUserIndex!];
  },
  getAllUsers: () => MOCK_USERS
};

import React from 'react';
import { ProcurementWorkflow, SystemSettings, ProcurementStatus } from '../types';

interface DocumentTemplateProps {
  type: 'GSRF' | 'PRF' | 'PO' | 'PEF';
  data: ProcurementWorkflow;
  settings?: SystemSettings | null;
}

export const DocumentTemplate: React.FC<DocumentTemplateProps> = ({ type, data, settings }) => {
  const currentYear = new Date().getFullYear();

  const renderHeader = (title: string, refNo: string) => (
    <div className="flex flex-col items-center mb-6 border-b-2 border-black pb-4">
      <div className="text-center w-full relative">
        {settings?.templateConfig?.showLogo && settings?.logoUrl && (
           <img src={settings.logoUrl} alt="Logo" className="h-16 absolute left-0 top-0 object-contain" />
        )}
        <h1 className="text-xl font-bold uppercase tracking-wider mb-1 font-serif">
            {settings?.officeName || 'Government Entity of State'}
        </h1>
        <h2 className="text-sm uppercase text-slate-700 mb-2 font-serif">
            {settings?.departmentName || 'Department of Administration & Finance'}
        </h2>
        <p className="text-[10px] text-slate-600 mb-4 whitespace-pre-line">
            {settings?.officeAddress || 'Address Not Configured'}
        </p>
      </div>
      <div className="w-full flex justify-between items-end mt-2">
        <div>
          <p className="text-xs font-bold uppercase tracking-wide">Document: {title}</p>
        </div>
        <div className="text-right">
          <p className="text-sm"><span className="font-bold">Ref No:</span> {refNo}</p>
          <p className="text-xs text-slate-600">{new Date().toLocaleDateString()}</p>
        </div>
      </div>
    </div>
  );

  const renderCustomBlocks = () => {
      if (!settings?.templateConfig?.customBlocks || settings.templateConfig.customBlocks.length === 0) return null;

      return (
          <div className="mt-8 pt-4 border-t-2 border-dashed border-slate-300">
              {settings.templateConfig.customBlocks.map(block => (
                  <div key={block.id} className="mb-4">
                      {block.type === 'title' && <h3 className="text-lg font-bold uppercase mb-2">{block.content}</h3>}
                      {block.type === 'text' && <p className="text-xs text-slate-700 whitespace-pre-wrap">{block.content}</p>}
                      {block.type === 'divider' && <hr className="border-black my-4" />}
                      {block.type === 'signature' && (
                          <div className="mt-8 pt-2 border-t border-black w-48">
                              <p className="text-xs font-bold uppercase">{block.content || 'Authorized Signature'}</p>
                          </div>
                      )}
                      {block.type === 'image' && (
                          <div className="h-24 w-24 bg-slate-100 flex items-center justify-center text-slate-400 border border-slate-300">
                              IMG
                          </div>
                      )}
                  </div>
              ))}
          </div>
      );
  };

  const renderFooter = () => (
      <div className="mt-auto pt-8 border-t border-slate-300 text-center text-[9px] text-slate-500">
          <p>{settings?.templateConfig?.footerText || 'System Generated Document'}</p>
          <p className="mt-1">Generated by GovTrack System • {new Date().toLocaleString()}</p>
      </div>
  );

  const renderSignatureBlock = (role: string, name: string | undefined, signature: string | undefined, date: string | undefined) => (
    <div className="flex-1 flex flex-col items-center">
      <div className="h-16 w-32 mb-1 flex items-end justify-center">
        {signature ? <img src={signature} alt="Signed" className="max-h-16 object-contain" /> : <div className="h-8"></div>}
      </div>
      <div className="w-32 border-t border-black pt-1 text-center">
        <p className="text-[10px] font-bold uppercase">{role}</p>
        <p className="text-[10px] truncate max-w-full">{name || '________________'}</p>
        <p className="text-[9px] text-slate-500">{date ? new Date(date).toLocaleDateString() : ''}</p>
      </div>
    </div>
  );

  // --- Goods & Services Requisition Form (GSRF) ---
  if (type === 'GSRF') {
    const isIssued = data.status === ProcurementStatus.ISSUED || data.status === ProcurementStatus.COMPLETED || data.status === ProcurementStatus.PO_ISSUED;
    return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader('GOODS & SERVICES REQUISITION FORM', data.gsrfRefNumber || `GSRF/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-x-8 gap-y-2 text-xs">
          <div><span className="font-bold block">Requesting Section:</span> {data.section || data.requesterDepartment}</div>
          <div><span className="font-bold block">Required By Date:</span> {data.requiredDate ? new Date(data.requiredDate).toLocaleDateString() : 'N/A'}</div>
          <div className="col-span-2 mt-2">
              <span className="font-bold block">Purpose / Remarks:</span> 
              <div className="border border-slate-300 p-2 min-h-[40px] rounded bg-slate-50">{data.remarks || 'N/A'}</div>
          </div>
          {data.issueDetails && (
            <div className="col-span-2 border-t border-slate-300 pt-2 mt-2">
                <span className="font-bold">Issue Status:</span> <span className="text-green-800 font-semibold">ISSUED</span> to {data.issueDetails.receiverName} on {new Date(data.issueDetails.issueDate).toLocaleDateString()}
            </div>
          )}
        </div>

        <table className="w-full border-collapse border border-black mb-6 text-xs">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">#</th>
              <th className="border border-black p-2 text-left">Description</th>
              <th className="border border-black p-2 w-20">Req Qty</th>
              <th className="border border-black p-2 w-20">Issued</th>
              <th className="border border-black p-2">Notes</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center font-bold">{item.quantity}</td>
                <td className="border border-black p-2 text-center">{isIssued ? item.quantity : ''}</td>
                <td className="border border-black p-2"></td>
              </tr>
            ))}
            {/* Fill empty rows to maintain layout consistency */}
            {[...Array(Math.max(0, 8 - data.items.length))].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

        <div className="flex justify-between mt-8 gap-2">
          {renderSignatureBlock('REQUESTED BY', data.requesterName, data.requesterSignature, data.requestDate)}
          {renderSignatureBlock('SECTION HEAD', 'Supervisor', undefined, undefined)}
          {renderSignatureBlock('STOCK KEEPER', 'Stores Officer', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('RECEIVED BY', data.issueDetails?.receiverName || 'Receiver', undefined, data.issueDetails?.issueDate)}
        </div>

        {renderCustomBlocks()}
        {renderFooter()}
      </div>
    );
  }

  // --- Purchase Request Form (PRF) ---
  if (type === 'PRF') {
     return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader('PURCHASE REQUEST FORM', data.prRefNumber || `PR/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-x-8 gap-y-2 text-xs">
           <div><span className="font-bold">GSRF Reference:</span> {data.gsrfRefNumber || 'N/A'}</div>
           <div><span className="font-bold">Date Raised:</span> {new Date().toLocaleDateString()}</div>
           <div className="col-span-2 border-b border-black pb-2 mb-2"></div>
           <div><span className="font-bold">Department:</span> {data.section || data.requesterDepartment}</div>
           <div><span className="font-bold">Required Date:</span> {data.requiredDate ? new Date(data.requiredDate).toLocaleDateString() : 'N/A'}</div>
        </div>

        <table className="w-full border-collapse border border-black mb-8 text-xs">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">#</th>
              <th className="border border-black p-2 text-left">Description</th>
              <th className="border border-black p-2 w-24">In Stock</th>
              <th className="border border-black p-2 w-24">Purchase Qty</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center text-slate-500">0</td>
                <td className="border border-black p-2 text-center font-bold">{item.quantity}</td>
              </tr>
            ))}
            {[...Array(Math.max(0, 8 - data.items.length))].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

         <div className="flex justify-between mt-12 gap-8">
          {renderSignatureBlock('PREPARED BY', 'Stock Keeper', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('VERIFIED BY', 'Finance Officer', undefined, undefined)}
          {renderSignatureBlock('AUTHORIZED BY', 'Head of Procurement', data.authorizedBySignature, undefined)}
        </div>

        {renderCustomBlocks()}
        {renderFooter()}
      </div>
     );
  }

  // --- Price Evaluation Form (PEF) ---
  if (type === 'PEF') {
    // Single Source
    if (data.evaluationType === 'SINGLE_SOURCE') {
        return (
          <div className="printable-area flex flex-col text-black font-sans">
             {renderHeader('SINGLE SOURCE JUSTIFICATION', data.poNumber || 'PENDING')}

             <div className="mb-6 space-y-4 text-xs">
                <div className="flex justify-between">
                    <div><span className="font-bold">Requesting Section:</span> {data.section || data.requesterDepartment}</div>
                    <div><span className="font-bold">PR Ref No:</span> {data.prRefNumber}</div>
                </div>

                <div className="border border-black p-4 bg-slate-50 min-h-[100px]">
                    <p className="font-bold mb-2 uppercase text-[10px] text-slate-600">Justification for Single Source Procurement:</p>
                    <p className="italic text-sm">{data.singleSourceJustification}</p>
                </div>

                <div className="grid grid-cols-2 gap-6 pt-4">
                    <div className="border border-black p-3">
                        <p className="font-bold text-[10px] uppercase text-slate-500">Selected Vendor</p>
                        <p className="font-bold text-lg">{data.selectedVendor}</p>
                    </div>
                    <div className="border border-black p-3">
                        <p className="font-bold text-[10px] uppercase text-slate-500">Total Estimated Cost</p>
                        <p className="font-bold text-lg">MVR {(data.quotations?.[0]?.price || 0).toFixed(2)}</p>
                    </div>
                </div>
             </div>

             <div className="flex justify-between mt-12 gap-4">
                {renderSignatureBlock('REQUESTED BY', 'Procurement Officer', data.stockKeeperSignature, undefined)}
                {renderSignatureBlock('APPROVED BY', 'Director General', data.authorizedBySignature, undefined)}
            </div>

            {renderCustomBlocks()}
            {renderFooter()}
          </div>
        );
    }

    // Matrix Evaluation
    return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader('PRICE EVALUATION FORM', data.evalRefNumber || 'PENDING')}

        <div className="mb-4 grid grid-cols-3 gap-4 text-xs">
          <div><span className="font-bold">Dept:</span> {data.section || data.requesterDepartment}</div>
          <div><span className="font-bold">Method:</span> {data.evaluationMethod}</div>
          <div><span className="font-bold">PR Ref:</span> {data.prRefNumber}</div>
        </div>

        {data.evaluationType === 'QUOTATION' ? (
           // Quotation Based Table
           <table className="w-full border-collapse border border-black mb-6 text-xs">
             <thead>
               <tr className="bg-slate-100">
                 <th className="border border-black p-2 w-10">#</th>
                 <th className="border border-black p-2 text-left">Vendor Name</th>
                 <th className="border border-black p-2 w-24">Quote No</th>
                 <th className="border border-black p-2 w-24">Date</th>
                 <th className="border border-black p-2 w-28 text-right">Total (MVR)</th>
               </tr>
             </thead>
             <tbody>
                {data.quotations?.map((q, idx) => (
                    <tr key={idx} className={q.selected ? "bg-green-50" : ""}>
                        <td className="border border-black p-2 text-center">{idx + 1}</td>
                        <td className="border border-black p-2 font-medium">
                            {q.vendorName}
                            {q.selected && <span className="block text-[9px] font-bold text-green-700 mt-1">[RECOMMENDED]</span>}
                        </td>
                        <td className="border border-black p-2 text-center">{q.quoteNumber || '-'}</td>
                        <td className="border border-black p-2 text-center">{q.quoteDate ? new Date(q.quoteDate).toLocaleDateString() : '-'}</td>
                        <td className="border border-black p-2 text-right font-mono font-bold">{(q.price || 0).toFixed(2)}</td>
                    </tr>
                ))}
             </tbody>
           </table>
        ) : (
           // Form Based Table (Item Matrix)
           <table className="w-full border-collapse border border-black mb-6 text-[10px]">
            <thead>
                <tr className="bg-slate-100">
                <th className="border border-black p-1 w-8">#</th>
                <th className="border border-black p-1 text-left">Description</th>
                <th className="border border-black p-1 w-12">Qty</th>
                {data.quotations?.map((q, i) => (
                    <th key={i} className="border border-black p-1 w-24">
                        <div className="font-bold truncate">{q.vendorName || `Vendor ${i+1}`}</div>
                        <div className="font-normal text-[9px]">Unit Price</div>
                    </th>
                )) || <th className="border border-black p-1">Vendor Details</th>}
                </tr>
            </thead>
            <tbody>
                {data.items.map((item, idx) => (
                <tr key={idx}>
                    <td className="border border-black p-1 text-center">{idx + 1}</td>
                    <td className="border border-black p-1">{item.description}</td>
                    <td className="border border-black p-1 text-center">{item.quantity}</td>
                    {data.quotations?.map((q, i) => (
                    <td key={i} className="border border-black p-1 text-center">
                        {q.price > 0 ? `${q.price.toFixed(2)}` : '-'}
                    </td>
                    ))}
                </tr>
                ))}
                <tr className="font-bold bg-slate-50 border-t-2 border-black">
                    <td colSpan={3} className="border border-black p-1 text-right">TOTAL (MVR)</td>
                    {data.quotations?.map((q, i) => (
                    <td key={i} className={`border border-black p-2 text-center ${q.selected ? 'bg-green-100' : ''}`}>
                        {q.price > 0 ? `${(q.price * (data.items[0]?.quantity || 1)).toFixed(2)}` : '-'}
                        {q.selected && <div className="text-[9px] text-green-800">RECOMMENDED</div>}
                    </td>
                    ))}
                </tr>
            </tbody>
            </table>
        )}

        <div className="mt-4 mb-4 text-xs border border-black p-3">
          <p className="font-bold mb-1 uppercase text-slate-500 text-[10px]">Recommendation / Committee Notes:</p>
          <p>
             Based on the evaluation above, it is recommended to award the contract to 
             <span className="font-bold underline mx-1">{data.quotations?.find(q => q.selected)?.vendorName}</span> 
             as they meet the technical requirements at the most competitive price.
          </p>
        </div>

        <div className="flex justify-between mt-auto pt-8 gap-4">
          {renderSignatureBlock('PREPARED BY', 'Procurement Officer', data.stockKeeperSignature, undefined)}
          {renderSignatureBlock('CHECKED BY', 'Finance Officer', undefined, undefined)}
          {renderSignatureBlock('APPROVED BY', 'Director', data.authorizedBySignature, undefined)}
        </div>

        {renderCustomBlocks()}
        {renderFooter()}
      </div>
    );
  }

  // --- Purchase Order (PO) ---
  if (type === 'PO') {
     const selectedQuote = data.quotations?.find(q => q.selected);
     const totalAmount = selectedQuote ? selectedQuote.price : 0;

     return (
       <div className="printable-area flex flex-col text-black font-sans">
         {renderHeader('PURCHASE ORDER', data.poNumber || 'PENDING')}

         <div className="flex justify-between mb-8 text-xs gap-8">
            <div className="w-1/2 border border-black p-3">
               <h3 className="font-bold uppercase mb-2 border-b border-black pb-1">Vendor Details</h3>
               <p className="font-bold text-sm">{selectedQuote?.vendorName || 'N/A'}</p>
               <p className="text-slate-600">Quote Ref: {selectedQuote?.quoteNumber || 'N/A'}</p>
               {selectedQuote?.quoteDate && <p className="text-slate-600">Date: {new Date(selectedQuote.quoteDate).toLocaleDateString()}</p>}
            </div>
            <div className="w-1/2 border border-black p-3 bg-slate-50">
               <h3 className="font-bold uppercase mb-2 border-b border-black pb-1">Order Details</h3>
               <p><span className="font-bold w-24 inline-block">PO Date:</span> {data.budgetVerifiedDate ? new Date(data.budgetVerifiedDate).toLocaleDateString() : new Date().toLocaleDateString()}</p>
               <p><span className="font-bold w-24 inline-block">Budget Code:</span> {data.budgetCode}</p>
               <p><span className="font-bold w-24 inline-block">PR Ref:</span> {data.prRefNumber}</p>
               <p><span className="font-bold w-24 inline-block">Currency:</span> MVR</p>
            </div>
         </div>

         <table className="w-full border-collapse border border-black mb-4 text-xs">
           <thead>
             <tr className="bg-slate-100">
               <th className="border border-black p-2 w-12">#</th>
               <th className="border border-black p-2 text-left">Description</th>
               <th className="border border-black p-2 w-24">Qty</th>
             </tr>
           </thead>
           <tbody>
             {data.items.map((item, idx) => (
               <tr key={idx}>
                 <td className="border border-black p-2 text-center">{idx + 1}</td>
                 <td className="border border-black p-2">{item.description}</td>
                 <td className="border border-black p-2 text-center">{item.quantity}</td>
               </tr>
             ))}
             {/* Total Row */}
             <tr className="font-bold text-base">
                <td colSpan={2} className="border border-black p-3 text-right uppercase">Total Amount</td>
                <td className="border border-black p-3 text-right bg-slate-50">MVR {(totalAmount || 0).toFixed(2)}</td>
             </tr>
           </tbody>
         </table>

         <div className="text-xs border-t border-black pt-4 mt-4">
            <p className="font-bold uppercase text-[10px] text-slate-500 mb-2">Terms & Conditions:</p>
            <ol className="list-decimal ml-4 space-y-1 text-[10px] text-slate-700">
               <li>This Purchase Order number must appear on all invoices, packing slips, and correspondence.</li>
               <li>Delivery must be made within the specified timeline. Late delivery may result in penalties.</li>
               <li>Goods must meet the quality standards specified in the solicitation documents.</li>
               <li>Payment will be processed within 30 days of receipt of invoice and satisfactory goods acceptance.</li>
            </ol>
         </div>

         <div className="flex justify-between mt-auto pt-12 gap-8">
           {renderSignatureBlock('PREPARED BY', 'Procurement Officer', data.stockKeeperSignature, undefined)}
           {renderSignatureBlock('AUTHORIZED BY', 'Finance Director', data.authorizedBySignature, data.budgetVerifiedDate)}
         </div>

         {renderCustomBlocks()}
         {renderFooter()}
       </div>
     );
  }

  return <div>Document template not found.</div>;
};

import React, { useState, useEffect } from 'react';
import { InventoryService } from '../services/mockService';
import { InventoryItem, ItemCategory } from '../types';
import { Plus, Edit2, Barcode as BarcodeIcon, Printer, X } from 'lucide-react';
import { Card, Button, Input } from './SharedComponents';
import Barcode from 'react-barcode';

export const InventoryView = () => {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Printing State
  const [itemToPrint, setItemToPrint] = useState<InventoryItem | null>(null);
  const [printQty, setPrintQty] = useState(1);

  // Form state
  const [formData, setFormData] = useState({ name: '', category: ItemCategory.STATIONERY, qty: 0, loc: '', price: 0, minStockLevel: 5, barcode: '', sku: '' });

  useEffect(() => {
    InventoryService.getAll().then(setItems);
  }, []);

  const handleSave = async () => {
    if (editingId) {
      // Update existing item
      const itemToUpdate = items.find(i => i.id === editingId);
      if (itemToUpdate) {
        await InventoryService.update({
          ...itemToUpdate,
          name: formData.name,
          category: formData.category,
          quantity: formData.qty,
          location: formData.loc,
          pricePerUnit: formData.price,
          minStockLevel: formData.minStockLevel,
          barcode: formData.barcode
        });
      }
    } else {
      // Create new item
      const govId = InventoryService.generateGovId(
        new Date().getFullYear().toString(), 
        formData.category, 
        '001'
      );
      await InventoryService.add({
        name: formData.name,
        category: formData.category,
        quantity: formData.qty,
        location: formData.loc,
        pricePerUnit: formData.price,
        minStockLevel: formData.minStockLevel,
        govId: govId,
        barcode: formData.barcode
      });
    }

    setItems(await InventoryService.getAll());
    resetForm();
  };

  const handleEdit = (item: InventoryItem) => {
    setEditingId(item.id);
    setFormData({
      name: item.name,
      category: item.category,
      qty: item.quantity,
      loc: item.location,
      price: item.pricePerUnit,
      minStockLevel: item.minStockLevel,
      barcode: item.barcode || '',
      sku: item.sku
    });
    setShowForm(true);
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ name: '', category: ItemCategory.STATIONERY, qty: 0, loc: '', price: 0, minStockLevel: 5, barcode: '', sku: '' });
  };

  const openPrintModal = (item: InventoryItem) => {
    setItemToPrint(item);
    setPrintQty(item.quantity > 0 ? item.quantity : 1);
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Inventory Management</h2>
        <Button onClick={() => setShowForm(!showForm)} icon={Plus}>Add Item</Button>
      </div>

      {showForm && (
        <Card className="mb-6 bg-slate-50 border-slate-200">
          <h3 className="font-bold mb-4">{editingId ? 'Edit Item' : 'New Item Entry'}</h3>
          <div className="grid grid-cols-2 gap-4">
             {editingId && (
                <div className="mb-4">
                  <label className="block text-sm font-medium text-slate-700 mb-1">SKU (Auto-Generated)</label>
                  <div className="flex h-10 w-full items-center rounded-md border border-slate-200 bg-slate-100 px-3 text-sm font-mono text-slate-600">
                    {formData.sku}
                  </div>
                </div>
             )}
             <Input label="Item Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
             <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                <select 
                  className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                  value={formData.category}
                  onChange={e => setFormData({...formData, category: e.target.value as ItemCategory})}
                >
                  {Object.values(ItemCategory).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
             </div>
             <Input label="Barcode" value={formData.barcode} onChange={e => setFormData({...formData, barcode: e.target.value})} placeholder="Scan or enter barcode" />
             <Input type="number" label="Quantity" value={formData.qty} onChange={e => setFormData({...formData, qty: parseInt(e.target.value)})} />
             <Input type="number" label="Reorder Point (Low Stock Alert)" value={formData.minStockLevel} onChange={e => setFormData({...formData, minStockLevel: parseInt(e.target.value)})} />
             <Input label="Location" value={formData.loc} onChange={e => setFormData({...formData, loc: e.target.value})} />
             <Input type="number" label="Price per Unit (MVR)" value={formData.price} onChange={e => setFormData({...formData, price: parseFloat(e.target.value)})} />
          </div>
          <div className="mt-4 flex justify-end gap-2">
            <Button variant="outline" onClick={resetForm}>Cancel</Button>
            <Button onClick={handleSave}>{editingId ? 'Update Item' : 'Save to Inventory'}</Button>
          </div>
        </Card>
      )}

      {/* Barcode Print Modal */}
      {itemToPrint && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl max-w-4xl w-full max-h-[90vh] flex flex-col">
            <div className="p-4 border-b flex justify-between items-center no-print">
              <h3 className="font-bold text-lg">Print Inventory Labels</h3>
              <button onClick={() => setItemToPrint(null)} className="text-slate-500 hover:text-slate-800">
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="p-4 bg-slate-50 border-b no-print">
               <div className="flex items-end gap-4">
                  <div className="flex-1">
                      <p className="text-sm font-bold text-slate-700">{itemToPrint.name}</p>
                      <p className="text-xs text-slate-500">Current Stock: {itemToPrint.quantity}</p>
                  </div>
                  <div>
                      <Input 
                        label="Quantity of Labels" 
                        type="number" 
                        value={printQty} 
                        onChange={e => setPrintQty(parseInt(e.target.value) || 0)} 
                        className="mb-0 w-32"
                      />
                  </div>
               </div>
            </div>

            <div className="flex-1 overflow-y-auto p-8 bg-slate-100 flex justify-center">
               {/* Printable Area - Set to 80mm for label printer paper */}
               <div className="printable-area label-print label-grid bg-white shadow-sm w-[80mm] p-4">
                  {Array.from({ length: printQty }).map((_, i) => (
                    <div key={i} className="label-item flex flex-col items-center justify-center p-2 border border-slate-200 rounded text-center h-[120px] overflow-hidden">
                       <p className="text-[10px] font-bold truncate w-full mb-1">{itemToPrint.name}</p>

                       <div className="flex flex-col gap-1 items-center justify-center w-full transform scale-75 origin-center">
                          {/* If Barcode exists, show it */}
                          {itemToPrint.barcode && (
                             <div className="mb-1">
                               <Barcode value={itemToPrint.barcode} height={20} width={1} fontSize={10} displayValue={true} />
                             </div>
                          )}
                          {/* Always show SKU */}
                          <Barcode value={itemToPrint.sku} height={25} width={1.2} fontSize={10} displayValue={true} format="CODE128" />
                       </div>
                    </div>
                  ))}
               </div>
            </div>

            <div className="p-4 border-t flex justify-end gap-2 no-print bg-white">
               <Button variant="outline" onClick={() => setItemToPrint(null)}>Close</Button>
               <Button onClick={handlePrint} icon={Printer}>Print Labels</Button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-lg shadow overflow-hidden border border-slate-200">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">SKU</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Gov ID</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Item Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Category</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Barcode</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Stock</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Location</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Action</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-200">
              {items.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50">
                  <td className="px-6 py-4 whitespace-nowrap text-xs font-mono font-bold text-slate-700">{item.sku}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-xs font-mono text-slate-500">{item.govId}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900">{item.name}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{item.category}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-xs font-mono text-slate-500 flex items-center gap-1">
                     {item.barcode && <BarcodeIcon className="w-3 h-3 text-slate-400"/>}
                     {item.barcode || '-'}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${item.quantity < item.minStockLevel ? 'bg-red-100 text-red-800' : 'bg-green-100 text-green-800'}`}>
                      {item.quantity}
                    </span>
                    {item.quantity < item.minStockLevel && <span className="ml-2 text-xs text-red-600 font-bold">Low</span>}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{item.location}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium flex justify-end gap-2">
                    <button onClick={() => openPrintModal(item)} className="text-slate-600 hover:text-slate-900 flex items-center" title="Print Labels">
                      <Printer className="w-4 h-4" />
                    </button>
                    <button onClick={() => handleEdit(item)} className="text-gov-600 hover:text-gov-900 flex items-center gap-1">
                      <Edit2 className="w-4 h-4" /> Edit
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AssetService, SettingsService } from '../services/mockService';
import { Asset, ItemCategory, SystemSettings } from '../types';
import { Plus, Printer, X } from 'lucide-react';
import { Card, Button, Input } from './SharedComponents';
import QRCode from 'react-qr-code';

export const AssetView = () => {
  const [assets, setAssets] = useState<Asset[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [selectedAssetForLabel, setSelectedAssetForLabel] = useState<Asset | null>(null);
  const [settings, setSettings] = useState<SystemSettings | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    category: ItemCategory.IT_EQUIPMENT,
    condition: 'New' as Asset['condition'],
    purchaseDate: new Date().toISOString().split('T')[0],
    price: 0,
    location: '',
    assignedTo: ''
  });

  useEffect(() => {
    loadAssets();
    SettingsService.get().then(setSettings);
  }, []);

  const loadAssets = async () => {
    const data = await AssetService.getAll();
    setAssets(data);
  };

  const handleAdd = async () => {
    const govId = AssetService.generateGovId(
      new Date().getFullYear().toString(),
      formData.category,
      '001'
    );
    await AssetService.add({
      name: formData.name,
      category: formData.category,
      condition: formData.condition,
      purchaseDate: formData.purchaseDate,
      price: formData.price,
      location: formData.location,
      assignedTo: formData.assignedTo || undefined,
      govId: govId
    });
    loadAssets();
    setShowAdd(false);
    // Reset form mostly
    setFormData({ ...formData, name: '', price: 0, location: '', assignedTo: '' });
  };

  const handlePrint = () => {
    window.print();
  };

  const conditions = ['New', 'Good', 'Fair', 'Poor', 'Disposal'];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Asset Management</h2>
        <Button onClick={() => setShowAdd(!showAdd)} icon={Plus}>New Asset</Button>
      </div>

      {showAdd && (
        <Card className="mb-6 bg-slate-50 border-slate-200">
          <h3 className="font-bold mb-4">Register New Asset</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Input label="Asset Name" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
              <select
                className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                value={formData.category}
                onChange={e => setFormData({ ...formData, category: e.target.value as ItemCategory })}
              >
                {Object.values(ItemCategory).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Condition</label>
              <select
                className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                value={formData.condition}
                onChange={e => setFormData({ ...formData, condition: e.target.value as Asset['condition'] })}
              >
                {conditions.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>

            <Input type="date" label="Purchase Date" value={formData.purchaseDate} onChange={e => setFormData({ ...formData, purchaseDate: e.target.value })} />
            <Input type="number" label="Price (MVR)" value={formData.price} onChange={e => setFormData({ ...formData, price: parseFloat(e.target.value) })} />
            <Input label="Location" value={formData.location} onChange={e => setFormData({ ...formData, location: e.target.value })} />
            <Input label="Assigned To (Optional)" value={formData.assignedTo} onChange={e => setFormData({ ...formData, assignedTo: e.target.value })} />
          </div>
          <div className="mt-4 flex justify-end gap-2">
            <Button variant="outline" onClick={() => setShowAdd(false)}>Cancel</Button>
            <Button onClick={handleAdd}>Register Asset</Button>
          </div>
        </Card>
      )}

      {/* Asset Label Modal */}
      {selectedAssetForLabel && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl max-w-lg w-full overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center no-print">
              <h3 className="font-bold text-lg">Print Asset Label</h3>
              <button onClick={() => setSelectedAssetForLabel(null)} className="text-slate-500 hover:text-slate-800">
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="p-8 flex justify-center bg-slate-100">
               {/* Printable Area - Set to 80mm width for thermal printers */}
               <div className="printable-area label-print bg-white border-2 border-black w-[80mm] h-auto min-h-[50mm] p-4 flex flex-col justify-between relative shadow-sm">
                  <div className="text-center border-b-2 border-black pb-2 mb-2">
                     <h2 className="font-bold text-sm uppercase tracking-wider leading-tight">{settings?.officeName || 'GOV PROPERTY'}</h2>
                     <p className="text-[8px] uppercase text-slate-600">Fixed Asset Registry</p>
                  </div>

                  <div className="flex flex-col gap-2 items-center flex-1">
                     <div className="bg-white p-1">
                        <QRCode 
                          value={JSON.stringify({
                            id: selectedAssetForLabel.govId,
                            name: selectedAssetForLabel.name,
                            date: selectedAssetForLabel.purchaseDate,
                            price: selectedAssetForLabel.price
                          })} 
                          size={80}
                          level="M"
                        />
                     </div>
                     <div className="w-full text-center space-y-1">
                        <div>
                          <span className="block text-[8px] font-bold text-slate-500 uppercase">Gov Asset ID</span>
                          <span className="font-mono font-bold text-base leading-none">{selectedAssetForLabel.govId}</span>
                        </div>
                        <div>
                          <span className="block text-[8px] font-bold text-slate-500 uppercase">Item Description</span>
                          <span className="font-semibold text-xs leading-tight block truncate">{selectedAssetForLabel.name}</span>
                        </div>
                        <div className="flex justify-between pt-1 text-[10px]">
                           <div>
                              <span className="block text-[8px] font-bold text-slate-500 uppercase">Purchased</span>
                              <span>{new Date(selectedAssetForLabel.purchaseDate).toLocaleDateString()}</span>
                           </div>
                           <div className="text-right">
                              <span className="block text-[8px] font-bold text-slate-500 uppercase">Value</span>
                              <span>MVR {selectedAssetForLabel.price.toFixed(2)}</span>
                           </div>
                        </div>
                     </div>
                  </div>

                  <div className="mt-2 text-center">
                     <p className="text-[8px] font-bold text-slate-400 uppercase">Security Tag - Do not remove</p>
                  </div>
               </div>
            </div>

            <div className="p-4 border-t flex justify-end gap-2 no-print bg-slate-50">
               <Button variant="outline" onClick={() => setSelectedAssetForLabel(null)}>Close</Button>
               <Button onClick={handlePrint} icon={Printer}>Print Label</Button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-lg shadow overflow-hidden border border-slate-200">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Gov ID</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Asset Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Category</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Condition</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Price (MVR)</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Location</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Action</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-200">
              {assets.map((asset) => (
                <tr key={asset.id} className="hover:bg-slate-50">
                  <td className="px-6 py-4 whitespace-nowrap text-xs font-mono text-slate-600">{asset.govId}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900">{asset.name}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{asset.category}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full 
                      ${asset.condition === 'New' ? 'bg-green-100 text-green-800' : 
                        asset.condition === 'Good' ? 'bg-blue-100 text-blue-800' : 
                        asset.condition === 'Fair' ? 'bg-yellow-100 text-yellow-800' : 
                        'bg-red-100 text-red-800'}`}>
                      {asset.condition}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">{asset.price.toFixed(2)}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">
                    {asset.location}
                    {asset.assignedTo && <div className="text-xs text-slate-400">({asset.assignedTo})</div>}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                     <button 
                       onClick={() => setSelectedAssetForLabel(asset)}
                       className="text-gov-600 hover:text-gov-900 flex items-center ml-auto gap-1"
                     >
                       <Printer className="w-4 h-4" /> Label
