                </tr>
              ))}
              {assets.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-8 text-center text-slate-500 text-sm">No assets found in the registry.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export enum UserRole {
  USER = 'User',
  SUPERVISOR = 'Supervisor',
  MANAGER = 'Manager',
  FINANCE_OFFICER = 'Finance Officer',
  ADMIN = 'Administrator',
  STOCK_KEEPER = 'Stock Keeper'
}

export enum ItemCategory {
  STATIONERY = '01',
  IT_EQUIPMENT = '02',
  FURNITURE = '03',
  VEHICLES = '04',
  MAINTENANCE = '05'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  department: string;
  designation?: string;
  phone?: string;
  signatureUrl?: string; // Digital signature base64
}

export interface Department {
  id: string;
  name: string;
  managerId?: string;    // User ID of the Manager
  supervisorId?: string; // User ID of the Supervisor
  code: string;
}

export interface Vendor {
  id: string;
