  contactPerson: string;
  email: string;
  phone: string;
  address: string;
  taxId?: string;
  status: 'Active' | 'Blacklisted' | 'Pending';
}

export interface InventoryItem {
  id: string;
  name: string;
  sku: string; // Made required
  barcode?: string; // New field
  // Gov ID: OfficeNumber | Year | CategoryNumber | ItemTypeNumber | ItemNumber
  govId: string;
  category: ItemCategory;
  quantity: number;
  location: string;
  minStockLevel: number;
  pricePerUnit: number;
  lastUpdated: string;
}

export interface Asset {
  id: string;
  name: string;
  govId: string;
  category: ItemCategory;
  condition: 'New' | 'Good' | 'Fair' | 'Poor' | 'Disposal';
  purchaseDate: string;
  price: number;
  location: string;
  assignedTo?: string;
}

export enum ProcurementStatus {
  DRAFT = 'Draft',
  SUBMITTED = 'Submitted',
  APPROVED = 'Approved',
  REJECTED = 'Rejected',
  ISSUED = 'Issued', // Stock issued locally
  PROCUREMENT_NEEDED = 'Procurement Needed', // Moved to procurement
  PR_CREATED = 'PR Created', // Purchase Request Form generated
  EVALUATION = 'Evaluation', // Price Evaluation Form generated
  PENDING_APPROVAL = 'Pending Approval', // Manager Approval Needed
  BUDGET_CHECK = 'Budget Check', // Pending Budget Code
  PO_ISSUED = 'PO Issued',
  COMPLETED = 'Completed'
}

export enum EvaluationMethod {
  EMAIL = 'Email',
  PHONE = 'Phone',
  VISITING = 'Visiting'
}

export type EvaluationType = 'FORM' | 'QUOTATION' | 'SINGLE_SOURCE';

export interface TemplateBlock {
  id: string;
  type: 'title' | 'text' | 'divider' | 'image' | 'signature';
  content?: string;
  style?: Record<string, string>;
}

export interface SystemSettings {
  officeName: string;
  officeAddress: string;
  officeCode: string;
  departmentName: string;
  logoUrl?: string;
  phone?: string;
  email?: string;
  website?: string;
  taxId?: string;
  prefixes: {
    gsrf: string;
    pr: string;
    po: string;
    asset: string;
    inventory: string;
  };
  templateConfig: {
    headerText?: string;
    footerText?: string;
    showLogo: boolean;
    customBlocks?: TemplateBlock[]; 
  }
}

export interface ProcurementWorkflow {
  id: string;
  requestType: 'GOODS' | 'SERVICE';
  status: ProcurementStatus;

  // Step 1: Request
  requesterId: string;
  requesterName: string;
  requesterDepartment: string;
  section?: string;
  requestDate: string;
  requiredDate?: string;
  remarks?: string; // Purpose / Use case
  items: {
    itemId?: string; // If existing inventory item
    description: string;
    quantity: number;
    estimatedCost?: number;
  }[];
  requesterSignature?: string;

  // Step 2: Stock Keeper Check / GSRF
  gsrfRefNumber?: string;
  stockKeeperSignature?: string;
  stockCheckDate?: string;

  // Step 2a: Issue Process (If Available)
  issueDetails?: {
    receiverName: string;
    receiverDepartment: string;
    issueDate: string;
    remarks: string;
  };

  // Step 3: Purchase Request (if not in stock)
  prRefNumber?: string;
  authorizedBySignature?: string;

  // Step 4: Price Eval
  evalRefNumber?: string; // Format: (A)263/YYYY/Counter
  evaluationMethod?: EvaluationMethod;
  evaluationType?: EvaluationType;
  singleSourceJustification?: string;
  quotations?: {
    vendorName: string;
    quoteNumber?: string;
    quoteDate?: string;
    price: number;
    selected: boolean;
  }[];

  // Step 4.5: Budget
  budgetCode?: string;
  budgetVerifiedDate?: string;

  // Step 5: PO
  poNumber?: string;
  selectedVendor?: string;

  // Logs
  logs: {
    date: string;
    action: string;
    actor: string;
  }[];
}

