               <Card title="Department Management">
                  <div className="flex justify-between items-center mb-6">
                      <p className="text-sm text-slate-500">Configure departments and assign Managers/Supervisors.</p>
                      <Button size="sm" icon={Plus} onClick={() => { setEditingDept({ name: '', code: '' }); setShowDeptModal(true); }}>New Department</Button>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {departments.map(dept => {
                          const manager = users.find(u => u.id === dept.managerId);
                          const supervisor = users.find(u => u.id === dept.supervisorId);
                          return (
                              <div key={dept.id} className="p-4 border rounded-lg bg-white shadow-sm hover:border-gov-300 transition-all flex flex-col">
                                  <div className="flex justify-between items-start mb-4">
                                      <div>
                                          <h4 className="font-bold text-slate-800">{dept.name}</h4>
                                          <span className="text-[10px] font-mono font-bold bg-slate-100 px-1.5 py-0.5 rounded text-slate-500">{dept.code}</span>
                                      </div>
                                      <button onClick={() => openEditDept(dept)} className="text-slate-400 hover:text-gov-600"><Edit2 className="w-4 h-4"/></button>
                                  </div>
                                  <div className="space-y-3 mt-auto border-t pt-4">
                                      <div className="flex items-center gap-3">
                                          <div className="w-8 h-8 rounded-full bg-purple-100 flex items-center justify-center text-purple-600 flex-shrink-0"><UserCheck className="w-4 h-4"/></div>
                                          <div className="truncate">
                                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Manager</p>
                                              <p className="text-xs font-medium text-slate-700 truncate">{manager?.name || 'Unassigned'}</p>
                                          </div>
                                      </div>
                                      <div className="flex items-center gap-3">
                                          <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 flex-shrink-0"><Briefcase className="w-4 h-4"/></div>
                                          <div className="truncate">
                                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Supervisor</p>
                                              <p className="text-xs font-medium text-slate-700 truncate">{supervisor?.name || 'Unassigned'}</p>
                                          </div>
                                      </div>
                                  </div>
                              </div>
                          );
                      })}
                  </div>
               </Card>
            )}

            {isAdmin && activeSection === 'ORG' && (
               <div className="space-y-6">
                 <Card title="Organization Branding">
                    <div className="flex flex-col md:flex-row gap-8 items-start">
                       <div className="w-32 h-32 rounded-lg border-2 border-dashed border-slate-300 flex flex-col items-center justify-center bg-slate-50 overflow-hidden relative group">
                          {settings.logoUrl ? (
                            <>
                               <img src={settings.logoUrl} alt="Logo Preview" className="w-full h-full object-contain p-2" />
                               <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity cursor-pointer" onClick={() => logoInputRef.current?.click()}>
                                  <RefreshCw className="w-6 h-6 text-white" />
                               </div>
                            </>
                          ) : (
                            <div className="flex flex-col items-center gap-1 text-slate-400 cursor-pointer" onClick={() => logoInputRef.current?.click()}>
                               <Upload className="w-6 h-6" />
                               <span className="text-[10px] font-bold">UPLOAD LOGO</span>
                            </div>
                          )}
                          <input 
                            type="file" 
                            ref={logoInputRef} 
                            onChange={handleLogoUpload} 
                            accept="image/*" 
                            className="hidden" 
                          />
                       </div>
                       <div className="flex-1 space-y-4">
                          <p className="text-sm text-slate-600">Official logo of the Government Entity. This will appear on all system-generated documents and reports.</p>
                          <Button size="sm" variant="outline" onClick={() => logoInputRef.current?.click()}>Change Image</Button>
                          <label className="flex items-center gap-2 text-sm text-slate-700 cursor-pointer">
                             <input 
                               type="checkbox" 
                               checked={settings.templateConfig.showLogo} 
                               onChange={e => setSettings({...settings, templateConfig: {...settings.templateConfig, showLogo: e.target.checked}})}
                               className="rounded text-gov-600 focus:ring-gov-500"
                             />
                             Show logo on official document headers
                          </label>
                       </div>
                    </div>
                 </Card>

                 <Card title="Detailed Information">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-4">
                       <div className="md:col-span-2">
                          <Input label="Entity Legal Name" value={settings.officeName} onChange={e => setSettings({...settings, officeName: e.target.value})} className="mb-0" />
                          <p className="text-[10px] text-slate-400 mt-1 uppercase font-bold tracking-wider">Example: Ministry of Finance, Department of Education</p>
                       </div>

                       <div className="md:col-span-2">
                          <label className="block text-sm font-medium text-slate-700 mb-1">Official Address</label>
                          <textarea 
                             className="flex w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500 h-20 resize-none"
                             value={settings.officeAddress}
                             onChange={e => setSettings({...settings, officeAddress: e.target.value})}
                          />
                       </div>

                       <div className="space-y-4">
                          <Input label="Office Phone" icon={Phone} value={settings.phone || ''} onChange={e => setSettings({...settings, phone: e.target.value})} className="mb-0 pl-10" />
                          <Input label="Website" icon={Globe} value={settings.website || ''} onChange={e => setSettings({...settings, website: e.target.value})} className="mb-0 pl-10" />
                       </div>

                       <div className="space-y-4">
                          <Input label="Entity Email" icon={Mail} value={settings.email || ''} onChange={e => setSettings({...settings, email: e.target.value})} className="mb-0 pl-10" />
                          <Input label="Tax/VAT ID" icon={Hash} value={settings.taxId || ''} onChange={e => setSettings({...settings, taxId: e.target.value})} className="mb-0 pl-10" />
                       </div>
                    </div>
                    <div className="flex justify-end pt-8 border-t mt-6">
                       <Button onClick={handleSave} icon={Save} disabled={isSaving}>Save Organization Details</Button>
                    </div>
                 </Card>
               </div>
            )}

            {isAdmin && activeSection === 'PREFIXES' && (
               <Card title="Document Prefixes">
                  <div className="grid grid-cols-2 gap-6">
                     <Input label="GSRF Prefix" value={settings.prefixes.gsrf} onChange={e => setSettings({...settings, prefixes: {...settings.prefixes, gsrf: e.target.value}})} />
                     <Input label="PR Prefix" value={settings.prefixes.pr} onChange={e => setSettings({...settings, prefixes: {...settings.prefixes, pr: e.target.value}})} />
                     <Input label="PO Prefix" value={settings.prefixes.po} onChange={e => setSettings({...settings, prefixes: {...settings.prefixes, po: e.target.value}})} />
                  </div>
                  <div className="flex justify-end pt-4">
                     <Button onClick={handleSave} icon={Save} disabled={isSaving}>Update Prefixes</Button>
                  </div>
               </Card>
            )}

            {isAdmin && activeSection === 'USERS' && (
              <Card title="User Management">
                <div className="overflow-x-auto">
                   <table className="min-w-full divide-y divide-slate-200">
                     <thead className="bg-slate-50">
                        <tr>
                          <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">User</th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Role</th>
                          <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Department</th>
                          <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Action</th>
                        </tr>
                     </thead>
                     <tbody className="bg-white divide-y divide-slate-200">
                        {users.map(u => (
                          <tr key={u.id}>
                            <td className="px-6 py-4">
                              <div className="text-sm font-medium text-slate-900">{u.name}</div>
                              <div className="text-xs text-slate-500">{u.email}</div>
                            </td>
                            <td className="px-6 py-4"><span className="px-2 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">{u.role}</span></td>
                            <td className="px-6 py-4 text-sm text-slate-500">{u.department}</td>
                            <td className="px-6 py-4 text-right text-sm font-medium">
                                <button className="text-gov-600 hover:text-gov-900"><Edit2 className="w-3 h-3"/></button>
                            </td>
                          </tr>
                        ))}
                     </tbody>
                   </table>
                </div>
              </Card>
            )}
          </div>
        )}
      </div>

      {/* Dept Modal */}
      {showDeptModal && editingDept && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
              <div className="bg-white p-6 rounded-lg w-full max-w-md shadow-2xl">
                  <h3 className="text-lg font-bold mb-4">Configure Department</h3>
                  <div className="space-y-4">
                      <div className="grid grid-cols-2 gap-4">
                          <Input label="Dept Name" value={editingDept.name} onChange={e => setEditingDept({...editingDept, name: e.target.value})} />
                          <Input label="Dept Code" value={editingDept.code} onChange={e => setEditingDept({...editingDept, code: e.target.value})} />
                      </div>

                      <div>
                          <label className="block text-sm font-medium text-slate-700 mb-1">Assign Manager</label>
                          <select 
                            className="w-full h-10 rounded-md border border-slate-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                            value={editingDept.managerId || ''}
                            onChange={e => setEditingDept({...editingDept, managerId: e.target.value})}
                          >
                              <option value="">-- No Manager Assigned --</option>
                              {managers.map(u => <option key={u.id} value={u.id}>{u.name} ({u.role})</option>)}
                          </select>
                          <p className="text-[10px] text-slate-400 mt-1">1 Manager can be assigned to multiple departments.</p>
                      </div>

                      <div>
                          <label className="block text-sm font-medium text-slate-700 mb-1">Assign Supervisor</label>
                          <select 
                            className="w-full h-10 rounded-md border border-slate-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                            value={editingDept.supervisorId || ''}
                            onChange={e => setEditingDept({...editingDept, supervisorId: e.target.value})}
                          >
                              <option value="">-- No Supervisor Assigned --</option>
                              {supervisors.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                          </select>
                      </div>
                  </div>
                  <div className="flex justify-end gap-2 mt-8">
                      <Button variant="outline" onClick={() => setShowDeptModal(false)}>Cancel</Button>
                      <Button onClick={handleSaveDept}>Save Department</Button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React from 'react';
import { ProcurementWorkflow, SystemSettings, ProcurementStatus } from '../types';

interface DocumentTemplateProps {
  type: 'GSRF' | 'PRF' | 'PO' | 'PEF';
  data: ProcurementWorkflow;
  settings?: SystemSettings | null;
}

export const DocumentTemplate: React.FC<DocumentTemplateProps> = ({ type, data, settings }) => {
  const currentYear = new Date().getFullYear();

  const renderHeader = (title: string, refNo: string) => (
    <div className="flex flex-col mb-6 border-b-2 border-black pb-4">
      <div className="flex justify-between items-start w-full relative min-h-[80px]">
        {settings?.templateConfig?.showLogo && settings?.logoUrl && (
           <div className="w-24 h-20 flex items-center justify-center flex-shrink-0">
             <img src={settings.logoUrl} alt="Logo" className="max-w-full max-h-full object-contain" />
           </div>
        )}
        <div className="flex-1 text-right pl-4">
          <h1 className="text-xl font-bold uppercase tracking-wider mb-1 font-serif">
              {settings?.officeName || 'Government Entity of State'}
          </h1>
          <h2 className="text-sm uppercase text-slate-700 mb-1 font-serif">
              {settings?.departmentName || 'Department of Administration & Finance'}
          </h2>
          <div className="text-[10px] text-slate-600 leading-tight">
             <p className="whitespace-pre-line">{settings?.officeAddress || 'Address Not Configured'}</p>
             <div className="mt-1 flex flex-wrap justify-end gap-x-3">
                {settings?.phone && <span>Tel: {settings.phone}</span>}
                {settings?.email && <span>Email: {settings.email}</span>}
                {settings?.website && <span>Web: {settings.website}</span>}
                {settings?.taxId && <span>Tax ID: {settings.taxId}</span>}
             </div>
          </div>
        </div>
      </div>
      <div className="w-full flex justify-between items-end mt-4 pt-2 border-t border-slate-200">
        <div>
          <p className="text-xs font-bold uppercase tracking-wide text-gov-800">Official Document: {title}</p>
        </div>
        <div className="text-right">
          <p className="text-sm"><span className="font-bold uppercase text-[10px] text-slate-500 block">Reference Number</span> {refNo}</p>
          <p className="text-[10px] text-slate-500 font-bold uppercase mt-1">Date: {new Date().toLocaleDateString()}</p>
        </div>
      </div>
    </div>
  );

  const renderCustomBlocks = () => {
      if (!settings?.templateConfig?.customBlocks || settings.templateConfig.customBlocks.length === 0) return null;

      return (
          <div className="mt-8 pt-4 border-t-2 border-dashed border-slate-300">
              {settings.templateConfig.customBlocks.map(block => (
                  <div key={block.id} className="mb-4">
                      {block.type === 'title' && <h3 className="text-lg font-bold uppercase mb-2">{block.content}</h3>}
                      {block.type === 'text' && <p className="text-xs text-slate-700 whitespace-pre-wrap">{block.content}</p>}
                      {block.type === 'divider' && <hr className="border-black my-4" />}
                      {block.type === 'signature' && (
                          <div className="mt-8 pt-2 border-t border-black w-48">
                              <p className="text-xs font-bold uppercase">{block.content || 'Authorized Signature'}</p>
                          </div>
                      )}
                      {block.type === 'image' && (
                          <div className="h-24 w-24 bg-slate-100 flex items-center justify-center text-slate-400 border border-slate-300">
                              IMG
                          </div>
                      )}
                  </div>
              ))}
          </div>
      );
  };

  const renderFooter = () => (
      <div className="mt-auto pt-8 border-t border-slate-300 text-center text-[9px] text-slate-500">
          <p>{settings?.templateConfig?.footerText || 'System Generated Document'}</p>
          <p className="mt-1">Generated by GovTrack System • {new Date().toLocaleString()}</p>
      </div>
  );

  const renderSignatureBlock = (role: string, name: string | undefined, signature: string | undefined, date: string | undefined) => (
    <div className="flex-1 flex flex-col items-center">
      <div className="h-16 w-32 mb-1 flex items-end justify-center">
        {signature ? <img src={signature} alt="Signed" className="max-h-16 object-contain" /> : <div className="h-8"></div>}
      </div>
      <div className="w-32 border-t border-black pt-1 text-center">
        <p className="text-[10px] font-bold uppercase">{role}</p>
        <p className="text-[10px] truncate max-w-full">{name || '________________'}</p>
        <p className="text-[9px] text-slate-500">{date ? new Date(date).toLocaleDateString() : ''}</p>
      </div>
    </div>
  );

  // --- Goods & Services Requisition Form (GSRF) ---
  if (type === 'GSRF') {
    const isIssued = data.status === ProcurementStatus.ISSUED || data.status === ProcurementStatus.COMPLETED || data.status === ProcurementStatus.PO_ISSUED;
    return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader('GOODS & SERVICES REQUISITION FORM', data.gsrfRefNumber || `GSRF/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-x-8 gap-y-2 text-xs">
          <div><span className="font-bold block">Requesting Section:</span> {data.section || data.requesterDepartment}</div>
          <div><span className="font-bold block">Required By Date:</span> {data.requiredDate ? new Date(data.requiredDate).toLocaleDateString() : 'N/A'}</div>
          <div className="col-span-2 mt-2">
              <span className="font-bold block">Purpose / Remarks:</span> 
              <div className="border border-slate-300 p-2 min-h-[40px] rounded bg-slate-50">{data.remarks || 'N/A'}</div>
          </div>
          {data.issueDetails && (
            <div className="col-span-2 border-t border-slate-300 pt-2 mt-2">
                <span className="font-bold">Issue Status:</span> <span className="text-green-800 font-semibold">ISSUED</span> to {data.issueDetails.receiverName} on {new Date(data.issueDetails.issueDate).toLocaleDateString()}
            </div>
          )}
        </div>

        <table className="w-full border-collapse border border-black mb-6 text-xs">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">#</th>
              <th className="border border-black p-2 text-left">Description</th>
              <th className="border border-black p-2 w-20">Req Qty</th>
              <th className="border border-black p-2 w-20">Issued</th>
              <th className="border border-black p-2">Notes</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center font-bold">{item.quantity}</td>
                <td className="border border-black p-2 text-center">{isIssued ? item.quantity : ''}</td>
                <td className="border border-black p-2"></td>
              </tr>
            ))}
            {/* Fill empty rows to maintain layout consistency */}
            {[...Array(Math.max(0, 8 - data.items.length))].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

        <div className="flex justify-between mt-8 gap-2">
          {renderSignatureBlock('REQUESTED BY', data.requesterName, data.requesterSignature, data.requestDate)}
          {renderSignatureBlock('SECTION HEAD', 'Supervisor', undefined, undefined)}
          {renderSignatureBlock('STOCK KEEPER', 'Stores Officer', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('RECEIVED BY', data.issueDetails?.receiverName || 'Receiver', undefined, data.issueDetails?.issueDate)}
        </div>

        {renderCustomBlocks()}
        {renderFooter()}
      </div>
    );
  }

  // --- Purchase Request Form (PRF) ---
  if (type === 'PRF') {
     return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader('PURCHASE REQUEST FORM', data.prRefNumber || `PR/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-x-8 gap-y-2 text-xs">
           <div><span className="font-bold">GSRF Reference:</span> {data.gsrfRefNumber || 'N/A'}</div>
           <div><span className="font-bold">Date Raised:</span> {new Date().toLocaleDateString()}</div>
           <div className="col-span-2 border-b border-black pb-2 mb-2"></div>
           <div><span className="font-bold">Department:</span> {data.section || data.requesterDepartment}</div>
           <div><span className="font-bold">Required Date:</span> {data.requiredDate ? new Date(data.requiredDate).toLocaleDateString() : 'N/A'}</div>
        </div>

        <table className="w-full border-collapse border border-black mb-8 text-xs">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">#</th>
              <th className="border border-black p-2 text-left">Description</th>
              <th className="border border-black p-2 w-24">In Stock</th>
              <th className="border border-black p-2 w-24">Purchase Qty</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center text-slate-500">0</td>
                <td className="border border-black p-2 text-center font-bold">{item.quantity}</td>
              </tr>
            ))}
            {[...Array(Math.max(0, 8 - data.items.length))].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

         <div className="flex justify-between mt-12 gap-8">
          {renderSignatureBlock('PREPARED BY', 'Stock Keeper', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('VERIFIED BY', 'Finance Officer', undefined, undefined)}
          {renderSignatureBlock('AUTHORIZED BY', 'Head of Procurement', data.authorizedBySignature, undefined)}
        </div>

        {renderCustomBlocks()}
        {renderFooter()}
      </div>
     );
  }

  // --- Price Evaluation Form (PEF) ---
  if (type === 'PEF') {
    // Single Source
    if (data.evaluationType === 'SINGLE_SOURCE') {
        return (
          <div className="printable-area flex flex-col text-black font-sans">
             {renderHeader('SINGLE SOURCE JUSTIFICATION', data.poNumber || 'PENDING')}

             <div className="mb-6 space-y-4 text-xs">
                <div className="flex justify-between">
                    <div><span className="font-bold">Requesting Section:</span> {data.section || data.requesterDepartment}</div>
                    <div><span className="font-bold">PR Ref No:</span> {data.prRefNumber}</div>
                </div>

                <div className="border border-black p-4 bg-slate-50 min-h-[100px]">
                    <p className="font-bold mb-2 uppercase text-[10px] text-slate-600">Justification for Single Source Procurement:</p>
                    <p className="italic text-sm">{data.singleSourceJustification}</p>
                </div>

                <div className="grid grid-cols-2 gap-6 pt-4">
                    <div className="border border-black p-3">
                        <p className="font-bold text-[10px] uppercase text-slate-500">Selected Vendor</p>
                        <p className="font-bold text-lg">{data.selectedVendor}</p>
                    </div>
                    <div className="border border-black p-3">
                        <p className="font-bold text-[10px] uppercase text-slate-500">Total Estimated Cost</p>
                        <p className="font-bold text-lg">MVR {(data.quotations?.[0]?.price || 0).toFixed(2)}</p>
                    </div>
                </div>
             </div>

             <div className="flex justify-between mt-12 gap-4">
                {renderSignatureBlock('REQUESTED BY', 'Procurement Officer', data.stockKeeperSignature, undefined)}
                {renderSignatureBlock('APPROVED BY', 'Director General', data.authorizedBySignature, undefined)}
            </div>

            {renderCustomBlocks()}
            {renderFooter()}
          </div>
        );
    }

    // Matrix Evaluation
    return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader('PRICE EVALUATION FORM', data.evalRefNumber || 'PENDING')}

        <div className="mb-4 grid grid-cols-3 gap-4 text-xs">
          <div><span className="font-bold">Dept:</span> {data.section || data.requesterDepartment}</div>
          <div><span className="font-bold">Method:</span> {data.evaluationMethod}</div>
          <div><span className="font-bold">PR Ref:</span> {data.prRefNumber}</div>
        </div>

        {data.evaluationType === 'QUOTATION' ? (
           // Quotation Based Table
           <table className="w-full border-collapse border border-black mb-6 text-xs">
             <thead>
               <tr className="bg-slate-100">
                 <th className="border border-black p-2 w-10">#</th>
                 <th className="border border-black p-2 text-left">Vendor Name</th>
