        {renderCustomBlocks()}
        {renderFooter()}
      </div>
    );
  }

  // --- Purchase Order (PO) ---
  if (type === 'PO') {
     const selectedQuote = data.quotations?.find(q => q.selected);
     const totalAmount = selectedQuote ? selectedQuote.price : 0;

     return (
       <div className="printable-area flex flex-col text-black font-sans">
