      category: item.category,
      qty: item.quantity,
      loc: item.location,
      price: item.pricePerUnit,
      minStockLevel: item.minStockLevel,
      barcode: item.barcode || '',
      sku: item.sku,
      govId: item.govId
    });
    setShowForm(true);
  };

