export const InventoryView = () => {
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [settings, setSettings] = useState<SystemSettings | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isManualGovId, setIsManualGovId] = useState(false);
  const [govIdError, setGovIdError] = useState('');

  // Printing State
  const [itemToPrint, setItemToPrint] = useState<InventoryItem | null>(null);
  const [printQty, setPrintQty] = useState(1);

  // Form state
  const [formData, setFormData] = useState({ 
    name: '', 
    category: '', 
    productType: '',
    isAsset: false,
    qty: 0, 
    loc: '', 
    price: 0, 
    minStockLevel: 5, 
    barcode: '', 
    sku: '',
    govId: ''
  });

  useEffect(() => {
    InventoryService.getAll().then(setItems);
    SettingsService.get().then(s => {
      setSettings(s);
      if (s.categories.length > 0) {
        setFormData(prev => ({ ...prev, category: s.categories[0].id }));
      }
    });
  }, []);

  const handleSave = async () => {
    setGovIdError('');
    let finalGovId = formData.govId;

    if (!isManualGovId && !editingId) {
      const cat = settings?.categories.find(c => c.id === formData.category);
      const type = settings?.itemTypes.find(t => t.id === formData.productType);
      finalGovId = InventoryService.generateGovId(
        new Date().getFullYear().toString(), 
        cat?.code || '00', 
        type?.code || '00'
      );
    }

    // Validation: Check for duplicates
    const isUnique = await InventoryService.isGovIdUnique(finalGovId, editingId || undefined);
    if (!isUnique) {
      setGovIdError('This GOV ID is already assigned to another item.');
      return;
    }

    if (editingId) {
      // Update existing item
      const itemToUpdate = items.find(i => i.id === editingId);
      if (itemToUpdate) {
        await InventoryService.update({
          ...itemToUpdate,
          name: formData.name,
          category: formData.category,
          productType: formData.productType,
          isAsset: formData.isAsset,
          quantity: formData.qty,
          location: formData.loc,
          pricePerUnit: formData.price,
          minStockLevel: formData.minStockLevel,
          barcode: formData.barcode,
          govId: finalGovId
        });
      }
    } else {
      // Create new item
      await InventoryService.add({
        name: formData.name,
        category: formData.category,
        productType: formData.productType,
        isAsset: formData.isAsset,
        quantity: formData.qty,
        location: formData.loc,
        pricePerUnit: formData.price,
        minStockLevel: formData.minStockLevel,
        govId: finalGovId,
        barcode: formData.barcode
      });
    }

    setItems(await InventoryService.getAll());
    resetForm();
  };

  const handleEdit = (item: InventoryItem) => {
    setEditingId(item.id);
    setIsManualGovId(true);
    setFormData({
      name: item.name,
      category: item.category,
      productType: item.productType || '',
      isAsset: item.isAsset,
      qty: item.quantity,
      loc: item.location,
      price: item.pricePerUnit,
      minStockLevel: item.minStockLevel,
      barcode: item.barcode || '',
      sku: item.sku,
      govId: item.govId
    });
    setShowForm(true);
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setIsManualGovId(false);
    setGovIdError('');
    setFormData({ 
      name: '', 
      category: settings?.categories[0]?.id || '', 
      productType: '',
      isAsset: false,
      qty: 0, 
      loc: '', 
      price: 0, 
      minStockLevel: 5, 
      barcode: '', 
      sku: '', 
      govId: '' 
    });
  };

  const openPrintModal = (item: InventoryItem) => {
    setItemToPrint(item);
    setPrintQty(item.quantity > 0 ? item.quantity : 1);
  };

  const handlePrint = () => {
    window.print();
  };

  const filteredTypes = settings?.itemTypes.filter(t => t.categoryId === formData.category) || [];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Inventory Management</h2>
        <Button onClick={() => setShowForm(!showForm)} icon={Plus}>Add Item</Button>
      </div>

      {showForm && (
        <Card className="mb-6 bg-slate-50 border-slate-200">
          <h3 className="font-bold mb-4">{editingId ? 'Edit Item' : 'New Item Entry'}</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div className="col-span-2">
                <label className="block text-sm font-medium text-slate-700 mb-1">Government ID</label>
                <div className="flex gap-2 items-start">
                   <div className="flex-1">
                      <Input 
                        value={isManualGovId ? formData.govId : (editingId ? formData.govId : 'Auto-Generated on Save')} 
                        onChange={e => setFormData({...formData, govId: e.target.value})}
                        disabled={!isManualGovId}
                        className={`mb-1 ${govIdError ? 'border-red-500' : ''}`}
                        placeholder="Manual GOV ID format: 263|YYYY|CAT|TYPE|###"
                      />
                      {govIdError && <p className="text-[10px] text-red-600 font-bold flex items-center gap-1"><AlertCircle className="w-3 h-3"/> {govIdError}</p>}
                   </div>
                   <button 
                      type="button"
                      onClick={() => setIsManualGovId(!isManualGovId)}
                      className={`h-10 px-3 rounded-md border flex items-center gap-2 text-xs font-bold transition-colors ${isManualGovId ? 'bg-amber-50 border-amber-300 text-amber-700' : 'bg-slate-100 border-slate-300 text-slate-600'}`}
                      title={isManualGovId ? "Switch to Auto-Generation" : "Manual ID Entry"}
                   >
                      {isManualGovId ? <Unlock className="w-4 h-4" /> : <Lock className="w-4 h-4" />}
                      {isManualGovId ? "Manual" : "Auto"}
                   </button>
                </div>
             </div>

             {editingId && (
                <div className="mb-4">
                  <label className="block text-sm font-medium text-slate-700 mb-1">SKU (Auto-Generated)</label>
                  <div className="flex h-10 w-full items-center rounded-md border border-slate-200 bg-slate-100 px-3 text-sm font-mono text-slate-600">
                    {formData.sku}
                  </div>
                </div>
             )}

             <Input label="Item Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />

             <div className="flex items-center gap-4 pt-6">
                <label className="flex items-center gap-2 cursor-pointer group">
                  <input 
                    type="checkbox" 
                    checked={formData.isAsset}
                    onChange={e => setFormData({...formData, isAsset: e.target.checked})}
                    className="w-4 h-4 rounded text-gov-600 focus:ring-gov-500"
                  />
                  <span className="text-sm font-bold text-slate-700 group-hover:text-gov-800 transition-colors">Mark as Fixed Asset</span>
                </label>
             </div>

             <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
                <select 
                  className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                  value={formData.category}
                  onChange={e => setFormData({...formData, category: e.target.value, productType: ''})}
                >
                  {settings?.categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
             </div>

             <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Product Type</label>
                <select 
                  className="flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gov-500"
                  value={formData.productType}
                  onChange={e => setFormData({...formData, productType: e.target.value})}
                  disabled={filteredTypes.length === 0}
                >
                  <option value="">-- Select Product Type --</option>
                  {filteredTypes.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                </select>
             </div>

             <Input label="Barcode" value={formData.barcode} onChange={e => setFormData({...formData, barcode: e.target.value})} placeholder="Scan or enter barcode" />
             <Input type="number" label="Quantity" value={formData.qty} onChange={e => setFormData({...formData, qty: parseInt(e.target.value)})} />
             <Input type="number" label="Reorder Point (Low Stock Alert)" value={formData.minStockLevel} onChange={e => setFormData({...formData, minStockLevel: parseInt(e.target.value)})} />
             <Input label="Location" value={formData.loc} onChange={e => setFormData({...formData, loc: e.target.value})} />
             <Input type="number" label="Price per Unit (MVR)" value={formData.price} onChange={e => setFormData({...formData, price: parseFloat(e.target.value)})} />
          </div>
          <div className="mt-4 flex justify-end gap-2">
            <Button variant="outline" onClick={resetForm}>Cancel</Button>
            <Button onClick={handleSave}>{editingId ? 'Update Item' : 'Save to Inventory'}</Button>
          </div>
        </Card>
      )}

      {/* Barcode Print Modal */}
      {itemToPrint && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl max-w-4xl w-full max-h-[90vh] flex flex-col">
            <div className="p-4 border-b flex justify-between items-center no-print">
              <h3 className="font-bold text-lg">Print Inventory Labels</h3>
              <button onClick={() => setItemToPrint(null)} className="text-slate-500 hover:text-slate-800">
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="p-4 bg-slate-50 border-b no-print">
               <div className="flex items-end gap-4">
                  <div className="flex-1">
                      <p className="text-sm font-bold text-slate-700">{itemToPrint.name}</p>
                      <p className="text-xs text-slate-500">Current Stock: {itemToPrint.quantity}</p>
                  </div>
                  <div>
                      <Input 
                        label="Quantity of Labels" 
                        type="number" 
                        value={printQty} 
                        onChange={e => setPrintQty(parseInt(e.target.value) || 0)} 
                        className="mb-0 w-32"
                      />
                  </div>
               </div>
            </div>

            <div className="flex-1 overflow-y-auto p-8 bg-slate-100 flex justify-center">
               <div className="printable-area label-print label-grid bg-white shadow-sm w-[80mm] p-4">
                  {Array.from({ length: printQty }).map((_, i) => (
                    <div key={i} className="label-item flex flex-col items-center justify-center p-2 border border-slate-200 rounded text-center h-[120px] overflow-hidden">
                       <p className="text-[10px] font-bold truncate w-full mb-1">{itemToPrint.name}</p>

                       <div className="flex flex-col gap-1 items-center justify-center w-full transform scale-75 origin-center">
                          {itemToPrint.barcode && (
                             <div className="mb-1">
                               <Barcode value={itemToPrint.barcode} height={20} width={1} fontSize={10} displayValue={true} />
                             </div>
                          )}
                          <Barcode value={itemToPrint.sku} height={25} width={1.2} fontSize={10} displayValue={true} format="CODE128" />
                       </div>
                    </div>
                  ))}
               </div>
            </div>

            <div className="p-4 border-t flex justify-end gap-2 no-print bg-white">
               <Button variant="outline" onClick={() => setItemToPrint(null)}>Close</Button>
               <Button onClick={handlePrint} icon={Printer}>Print Labels</Button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-lg shadow overflow-hidden border border-slate-200">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">SKU</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Gov ID</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Item Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Category</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Stock</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Asset</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Action</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-200">
              {items.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50">
                  <td className="px-6 py-4 whitespace-nowrap text-xs font-mono font-bold text-slate-700">{item.sku}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-xs font-mono text-slate-500">{item.govId}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900">{item.name}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">
                    {settings?.categories.find(c => c.id === item.category)?.name || 'N/A'}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${item.quantity < item.minStockLevel ? 'bg-red-100 text-red-800' : 'bg-green-100 text-green-800'}`}>
                      {item.quantity}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm">
                    {item.isAsset ? <span className="text-xs bg-amber-100 text-amber-800 px-2 py-0.5 rounded font-bold uppercase tracking-tighter">Fixed Asset</span> : <span className="text-slate-300">Consumable</span>}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium flex justify-end gap-2">
                    <button onClick={() => openPrintModal(item)} className="text-slate-600 hover:text-slate-900 flex items-center" title="Print Labels">
                      <Printer className="w-4 h-4" />
                    </button>
                    <button onClick={() => handleEdit(item)} className="text-gov-600 hover:text-gov-900 flex items-center gap-1">
                      <Edit2 className="w-4 h-4" /> Edit
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { AuthService, SettingsService, UserService, DepartmentService } from '../services/mockService';
import { SystemSettings, UserRole, User, TemplateBlock, Department, ItemCategoryDef, ItemTypeDef } from '../types';
import { Card, Button, Input, SignaturePad } from './SharedComponents';
import { 
  Save, Building, FileText, LayoutTemplate, User as UserIcon, Users, 
  Lock, Edit2, RefreshCw, Plus, Mail, Phone, Briefcase, BadgeCheck, 
  PenTool, Type, AlignLeft, Minus, Image as ImageIcon, Trash2, 
  Layers, ChevronRight, UserCheck, Globe, Hash, Upload, Tags, Package
} from 'lucide-react';

export const SettingsView = () => {
  const [currentUser, setCurrentUser] = useState(AuthService.getCurrentUser()!);
  const [settings, setSettings] = useState<SystemSettings | null>(null);
  const [activeSection, setActiveSection] = useState<'PROFILE' | 'ORG' | 'PREFIXES' | 'TEMPLATE' | 'USERS' | 'DEPARTMENTS' | 'ITEMS'>('PROFILE');
  const [isSaving, setIsSaving] = useState(false);

  // Profile & Password State
  const [profileForm, setProfileForm] = useState({
    name: '',
    email: '',
    designation: '',
    phone: ''
  });
  const [signature, setSignature] = useState('');

  // Admin: User Management State
  const [users, setUsers] = useState<User[]>([]);

  // Admin: Department Management State
  const [departments, setDepartments] = useState<Department[]>([]);
  const [showDeptModal, setShowDeptModal] = useState(false);
  const [editingDept, setEditingDept] = useState<Partial<Department> | null>(null);

  // Item Management State
  const [showCatModal, setShowCatModal] = useState(false);
  const [showTypeModal, setShowTypeModal] = useState(false);
  const [editingCat, setEditingCat] = useState<Partial<ItemCategoryDef> | null>(null);
  const [editingType, setEditingType] = useState<Partial<ItemTypeDef> | null>(null);

  // Template Builder State
  const [builderTab, setBuilderTab] = useState<'CONTENT' | 'SETTINGS'>('CONTENT');

  const logoInputRef = useRef<HTMLInputElement>(null);

  const isAdmin = currentUser.role === UserRole.ADMIN;

  useEffect(() => {
    SettingsService.get().then(setSettings);
    UserService.getAll().then(setUsers);
    DepartmentService.getAll().then(setDepartments);

    setProfileForm({
      name: currentUser.name,
      email: currentUser.email,
      designation: currentUser.designation || '',
      phone: currentUser.phone || ''
    });
    setSignature(currentUser.signatureUrl || '');
  }, [currentUser]);

  const handleSave = async () => {
    if (settings && isAdmin) {
      setIsSaving(true);
      await SettingsService.update(settings);
      setTimeout(() => setIsSaving(false), 800);
    }
  };

  const handleProfileUpdate = async () => {
     setIsSaving(true);
     const updatedUser = { 
        ...currentUser, 
        name: profileForm.name,
        email: profileForm.email,
        designation: profileForm.designation,
        phone: profileForm.phone,
        signatureUrl: signature
     };
     await UserService.update(updatedUser);
     setCurrentUser(updatedUser);
     setIsSaving(false);
     alert("Profile updated successfully.");
  };

  const handleUserSwitch = (id: string) => {
    const newUser = AuthService.switchUser(id);
    setCurrentUser(newUser);
    window.location.reload();
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && settings) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSettings({ ...settings, logoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  // --- Category Logic ---
  const handleSaveCat = async () => {
    if (!settings || !editingCat?.name || !editingCat?.code) return;
    const newCat = { 
        ...editingCat, 
        id: editingCat.id || Math.random().toString(36).substr(2, 9) 
    } as ItemCategoryDef;

    const categories = editingCat.id 
        ? settings.categories.map(c => c.id === editingCat.id ? newCat : c)
        : [...settings.categories, newCat];

    setSettings({ ...settings, categories });
    setShowCatModal(false);
  };

  const removeCat = (id: string) => {
    if (!settings) return;
    setSettings({
        ...settings,
        categories: settings.categories.filter(c => c.id !== id),
        itemTypes: settings.itemTypes.filter(t => t.categoryId !== id)
    });
  };

  // --- Type Logic ---
  const handleSaveType = async () => {
    if (!settings || !editingType?.name || !editingType?.code || !editingType?.categoryId) return;
    const newType = { 
        ...editingType, 
        id: editingType.id || Math.random().toString(36).substr(2, 9) 
    } as ItemTypeDef;

    const itemTypes = editingType.id 
        ? settings.itemTypes.map(t => t.id === editingType.id ? newType : t)
        : [...settings.itemTypes, newType];

    setSettings({ ...settings, itemTypes });
    setShowTypeModal(false);
  };

  const removeType = (id: string) => {
    if (!settings) return;
    setSettings({
        ...settings,
        itemTypes: settings.itemTypes.filter(t => t.id !== id)
    });
  };

  // --- Department Logic ---
  const handleSaveDept = async () => {
      if (editingDept && editingDept.name && editingDept.code) {
          if (editingDept.id) {
              await DepartmentService.update(editingDept as Department);
          } else {
              await DepartmentService.add(editingDept as Omit<Department, 'id'>);
          }
          setDepartments(await DepartmentService.getAll());
          setShowDeptModal(false);
      }
  };

  const openEditDept = (dept: Department) => {
      setEditingDept({...dept});
      setShowDeptModal(true);
  };

  // --- Builder Logic ---
  const addBlock = (type: TemplateBlock['type']) => {
    if (!settings || !isAdmin) return;
    const newBlock: TemplateBlock = {
        id: Math.random().toString(36).substr(2, 9),
        type,
        content: type === 'title' ? 'New Title Here' : type === 'text' ? 'Enter your text content here...' : '',
    };
    const currentBlocks = settings.templateConfig.customBlocks || [];
    setSettings({
        ...settings,
        templateConfig: {
            ...settings.templateConfig,
            customBlocks: [...currentBlocks, newBlock]
        }
    });
  };

  const updateBlock = (id: string, content: string) => {
      if (!settings || !isAdmin) return;
      const blocks = settings.templateConfig.customBlocks?.map(b => b.id === id ? { ...b, content } : b) || [];
      setSettings({
          ...settings,
          templateConfig: { ...settings.templateConfig, customBlocks: blocks }
      });
  };

  const removeBlock = (id: string) => {
      if (!settings || !isAdmin) return;
      const blocks = settings.templateConfig.customBlocks?.filter(b => b.id !== id) || [];
      setSettings({
          ...settings,
          templateConfig: { ...settings.templateConfig, customBlocks: blocks }
      });
  };

  if (!settings) return <div>Loading settings...</div>;

  const NavItem = ({ id, label, icon: Icon }: any) => (
    <button
      onClick={() => setActiveSection(id)}
      className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-lg transition-colors mb-1 ${
        activeSection === id ? 'bg-gov-100 text-gov-800' : 'text-slate-600 hover:bg-slate-50'
      }`}
    >
      <Icon className="w-4 h-4" />
      {label}
    </button>
  );

  const managers = users.filter(u => u.role === UserRole.MANAGER || u.role === UserRole.ADMIN);
  const supervisors = users.filter(u => u.role === UserRole.SUPERVISOR);

  return (
    <div className="flex flex-col md:flex-row gap-6 max-w-7xl h-[calc(100vh-100px)]">
      <div className="w-full md:w-64 flex-shrink-0">
         <Card className="h-full">
            <h3 className="font-bold text-slate-800 mb-4 px-2">Settings</h3>
            <nav>
               <NavItem id="PROFILE" label="User Profile" icon={UserIcon} />

               {isAdmin && (
                 <>
                   <div className="text-[10px] font-bold text-slate-400 uppercase mt-4 mb-2 px-4 tracking-widest">Administration</div>
                   <NavItem id="DEPARTMENTS" label="Departments" icon={Layers} />
                   <NavItem id="USERS" label="User Management" icon={Users} />
                   <NavItem id="ORG" label="Organization Details" icon={Building} />
                   <NavItem id="PREFIXES" label="Document Prefixes" icon={FileText} />
                   <NavItem id="ITEMS" label="Categories & Types" icon={Tags} />
                   <NavItem id="TEMPLATE" label="Template Builder" icon={LayoutTemplate} />
                 </>
               )}
            </nav>
         </Card>
      </div>

      <div className="flex-1 overflow-hidden flex flex-col">
        {isAdmin && activeSection === 'TEMPLATE' ? (
            <div className="flex h-full border border-slate-300 rounded-lg overflow-hidden bg-slate-100">
                <div className="flex-1 overflow-auto p-8 flex justify-center bg-[#525659]">
                    <div className="w-[210mm] min-h-[297mm] bg-white shadow-lg p-[15mm] flex flex-col relative transition-all">
                        <div className="border-b-2 border-black pb-4 mb-6 opacity-50 pointer-events-none grayscale">
                            <div className="flex justify-between items-center">
                                <div>
                                    <h1 className="text-xl font-bold uppercase">{settings.officeName}</h1>
                                    <p className="text-xs">{settings.officeAddress}</p>
                                </div>
                                <div className="w-16 h-16 flex items-center justify-center">
                                  {settings.logoUrl ? (
                                    <img src={settings.logoUrl} alt="Logo" className="max-h-16 object-contain" />
                                  ) : (
                                    <div className="w-16 h-16 bg-slate-200 flex items-center justify-center text-[10px]">LOGO</div>
                                  )}
                                </div>
                            </div>
                        </div>

                        <div className="flex-1 border-2 border-dashed border-blue-200 rounded p-4 min-h-[200px] relative group">
                            {settings.templateConfig.customBlocks?.map((block) => (
                                <div key={block.id} className="relative group/block hover:ring-2 hover:ring-blue-400 hover:ring-offset-2 rounded p-2 transition-all">
                                    <div className="absolute -right-3 -top-3 hidden group-hover/block:flex gap-1">
                                        <button onClick={() => removeBlock(block.id)} className="bg-red-500 text-white p-1 rounded-full shadow hover:bg-red-600">
                                            <Trash2 className="w-3 h-3" />
                                        </button>
                                    </div>

                                    {block.type === 'title' && (
                                        <input 
                                            className="w-full text-lg font-bold border-none focus:ring-0 bg-transparent"
                                            value={block.content}
                                            onChange={(e) => updateBlock(block.id, e.target.value)}
                                        />
                                    )}
                                    {block.type === 'text' && (
                                        <textarea 
                                            className="w-full text-sm resize-none border-none focus:ring-0 bg-transparent"
                                            value={block.content}
                                            onChange={(e) => updateBlock(block.id, e.target.value)}
                                            rows={3}
                                        />
                                    )}
                                    {block.type === 'divider' && <hr className="border-black my-2" />}
                                    {block.type === 'signature' && (
                                        <div className="mt-4 pt-8 border-t border-black w-48">
                                            <input 
                                                className="w-full text-xs font-bold uppercase border-none focus:ring-0 bg-transparent"
                                                value={block.content || 'Authorized Signature'}
                                                onChange={(e) => updateBlock(block.id, e.target.value)}
                                            />
                                        </div>
                                    )}
                                    {block.type === 'image' && <div className="h-24 bg-slate-100 flex items-center justify-center text-slate-400 border border-slate-300 rounded"><ImageIcon className="w-8 h-8 opacity-50" /></div>}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="w-80 bg-white border-l border-slate-200 flex flex-col shadow-xl z-10">
                    <div className="flex border-b border-slate-200">
                        <button onClick={() => setBuilderTab('CONTENT')} className={`flex-1 py-3 text-sm font-medium ${builderTab === 'CONTENT' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-slate-600'}`}>CONTENT</button>
                        <button onClick={() => setBuilderTab('SETTINGS')} className={`flex-1 py-3 text-sm font-medium ${builderTab === 'SETTINGS' ? 'text-blue-600 border-b-2 border-blue-600' : 'text-slate-600'}`}>SETTINGS</button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 bg-slate-50/50">
                        {builderTab === 'CONTENT' && (
                            <div className="grid grid-cols-2 gap-3">
                                <button onClick={() => addBlock('title')} className="flex flex-col items-center justify-center p-4 bg-white border border-slate-200 rounded hover:shadow-md transition-all group">
                                    <Type className="w-8 h-8 text-slate-400 group-hover:text-blue-500 mb-2" /><span className="text-xs font-semibold text-slate-600">Title</span>
                                </button>
                                <button onClick={() => addBlock('text')} className="flex flex-col items-center justify-center p-4 bg-white border border-slate-200 rounded hover:shadow-md transition-all group">
                                    <AlignLeft className="w-8 h-8 text-slate-400 group-hover:text-blue-500 mb-2" /><span className="text-xs font-semibold text-slate-600">Text</span>
                                </button>
                                <button onClick={() => addBlock('divider')} className="flex flex-col items-center justify-center p-4 bg-white border border-slate-200 rounded hover:shadow-md transition-all group">
                                    <Minus className="w-8 h-8 text-slate-400 group-hover:text-blue-500 mb-2" /><span className="text-xs font-semibold text-slate-600">Divider</span>
                                </button>
                                <button onClick={() => addBlock('signature')} className="flex flex-col items-center justify-center p-4 bg-white border border-slate-200 rounded hover:shadow-md transition-all group">
                                    <PenTool className="w-8 h-8 text-slate-400 group-hover:text-blue-500 mb-2" /><span className="text-xs font-semibold text-slate-600">Signature</span>
                                </button>
                            </div>
                        )}
                    </div>
                    <div className="p-4 border-t border-slate-200 bg-white">
                        <Button onClick={handleSave} className="w-full" disabled={isSaving}>Save Template</Button>
                    </div>
                </div>
            </div>
        ) : (
          <div className="overflow-y-auto h-full pr-2">
            {activeSection === 'PROFILE' && (
              <div className="space-y-6">
                <Card title="Personal Information">
                   <div className="space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                         <Input label="Full Name" value={profileForm.name} onChange={e => setProfileForm({...profileForm, name: e.target.value})} className="mb-0"/>
                         <Input label="Email Address" value={profileForm.email} onChange={e => setProfileForm({...profileForm, email: e.target.value})} className="mb-0"/>
                         <Input label="Designation" value={profileForm.designation} onChange={e => setProfileForm({...profileForm, designation: e.target.value})} className="mb-0"/>
                         <Input label="Phone Number" value={profileForm.phone} onChange={e => setProfileForm({...profileForm, phone: e.target.value})} className="mb-0"/>
                      </div>
                      <div className="flex justify-end pt-2">
                          <Button onClick={handleProfileUpdate} icon={Save} disabled={isSaving}>Save Profile</Button>
                      </div>
                   </div>
                </Card>

                <Card title="Digital Signature">
                   <SignaturePad label="Sign here to save your official signature" onChange={setSignature} initialValue={signature} />
