import { ProcurementWorkflow, ProcurementStatus, User, UserRole, SystemSettings, InventoryItem, Vendor, ItemCategory } from '../../types';
import { Button, Card } from '../SharedComponents';
import { DocumentTemplate } from '../DocumentTemplate';
import { Printer, ArrowRight, Check, X, DollarSign, AlertCircle, CreditCard, PackageCheck, ShieldCheck, ThumbsUp, ThumbsDown, FileText, Download, Wrench, CheckCircle, Award } from 'lucide-react';
import { IssueStockModal, BudgetModal, SingleSourceModal, EvaluationModal, ReceiveGoodsModal, AssessmentModal, ServiceCompletionModal, FinalCertificateModal } from './ProcurementModals';

interface ProcurementDetailProps {
  request: ProcurementWorkflow;
  currentUser: User;
  settings: SystemSettings | null;
  inventory: InventoryItem[];
  vendors: Vendor[];
  onBack: () => void;
  onUpdateStatus: (id: string, status: ProcurementStatus, log: string, extraUpdates?: any) => Promise<void>;
  onReceiveGoods: (id: string, items: any[], actor: string) => Promise<void>;
}

export const ProcurementDetail: React.FC<ProcurementDetailProps> = ({ request: r, currentUser, settings, inventory, vendors, onBack, onUpdateStatus, onReceiveGoods }) => {
  const [isPrintMode, setIsPrintMode] = useState(false);
  const [activeDocType, setActiveDocType] = useState<'GSRF' | 'PRF' | 'PEF' | 'PO' | 'CERT'>('GSRF');
  const [modalOpen, setModalOpen] = useState<'ISSUE' | 'EVAL' | 'SINGLE' | 'BUDGET' | 'RECEIVE' | 'ASSESS' | 'COMPLETION' | 'CERT_FINAL' | null>(null);

  const isService = r.requestType === 'SERVICE';

  // Determine available documents based on status
  const getAvailableDocuments = () => {
    const docs: { type: 'GSRF' | 'PRF' | 'PEF' | 'PO' | 'CERT'; label: string }[] = [
        { type: 'GSRF', label: `Requisition Form (${isService ? 'SRF' : 'GSRF'})` }
    ];

    const s = r.status;

    if ([
        ProcurementStatus.PR_CREATED, 
        ProcurementStatus.EVALUATION, 
        ProcurementStatus.PENDING_APPROVAL,
        ProcurementStatus.BUDGET_CHECK, 
        ProcurementStatus.PO_ISSUED, 
        ProcurementStatus.COMPLETED
    ].includes(s)) {
        docs.push({ type: 'PRF', label: isService ? 'Service Request (SR)' : 'Purchase Request (PR)' });
    }

    if ([
        ProcurementStatus.EVALUATION, 
        ProcurementStatus.PENDING_APPROVAL,
        ProcurementStatus.BUDGET_CHECK, 
        ProcurementStatus.PO_ISSUED, 
        ProcurementStatus.COMPLETED
    ].includes(s)) {
        docs.push({ type: 'PEF', label: 'Price Evaluation (PEF)' });
    }

    if ([
        ProcurementStatus.PO_ISSUED, 
        ProcurementStatus.COMPLETED
    ].includes(s)) {
        docs.push({ type: 'PO', label: isService ? 'Service Order (SO)' : 'Purchase Order (PO)' });
    }

    if (r.status === ProcurementStatus.COMPLETED && r.certificate) {
        docs.push({ type: 'CERT', label: 'Completion Certificate' });
    }

    return docs;
  };

  useEffect(() => {
      if (isPrintMode) {
        const available = getAvailableDocuments();
        setActiveDocType(available[available.length - 1].type);
      }
  }, [isPrintMode, r.status, r.certificate]);

  const renderStatusBadge = (status: ProcurementStatus) => {
    const colors: Record<string, string> = {
      [ProcurementStatus.DRAFT]: 'bg-slate-100 text-slate-800',
      [ProcurementStatus.SUBMITTED]: 'bg-blue-100 text-blue-800',
      [ProcurementStatus.APPROVED]: 'bg-green-100 text-green-800',
      [ProcurementStatus.REJECTED]: 'bg-red-100 text-red-800',
      [ProcurementStatus.ISSUED]: 'bg-purple-100 text-purple-800',
      [ProcurementStatus.PROCUREMENT_NEEDED]: 'bg-orange-100 text-orange-800',
      [ProcurementStatus.PR_CREATED]: 'bg-indigo-100 text-indigo-800',
      [ProcurementStatus.EVALUATION]: 'bg-pink-100 text-pink-800',
      [ProcurementStatus.PENDING_APPROVAL]: 'bg-amber-100 text-amber-800',
      [ProcurementStatus.BUDGET_CHECK]: 'bg-yellow-100 text-yellow-800',
      [ProcurementStatus.PO_ISSUED]: 'bg-teal-100 text-teal-800',
      [ProcurementStatus.COMPLETED]: 'bg-emerald-100 text-emerald-800',
    };
    return <span className={`px-2 py-1 rounded-full text-xs font-semibold ${colors[status] || 'bg-slate-100'}`}>{status}</span>;
  };

  // --- Handlers ---
  const handleIssueConfirm = async (details: any) => {
    await onUpdateStatus(r.id, ProcurementStatus.ISSUED, 'Items Issued from Stock', { 
      stockKeeperSignature: currentUser.signatureUrl || 'signed',
      stockCheckDate: new Date().toISOString(),
      issueDetails: {
        receiverName: details.receiverName,
        receiverDepartment: details.receiverDept,
        issueDate: new Date().toISOString(),
        remarks: details.remarks
      }
    });
    setModalOpen(null);
  };

  const handleAssessmentConfirm = async (data: any) => {
      const nextStatus = data.inHouseRepair ? ProcurementStatus.COMPLETED : ProcurementStatus.PROCUREMENT_NEEDED;
      const logMsg = data.inHouseRepair ? 'In-house Service Completed' : 'Service Assessment: Out-sourced Procurement Needed';

      await onUpdateStatus(r.id, nextStatus, logMsg, {
          assessmentDetails: {
              assessedBy: currentUser.name,
              assessmentDate: new Date().toISOString(),
              findings: data.findings,
              inHouseRepairPossible: data.inHouseRepair
          },
          stockKeeperSignature: currentUser.signatureUrl
      });
      setModalOpen(null);
  };

  const handleServiceCompletion = async (data: any) => {
      await onUpdateStatus(r.id, ProcurementStatus.COMPLETED, 'Service Work Completed & Verified', {
          serviceCompletionDetails: {
              completionDate: new Date().toISOString(),
              verifiedBy: currentUser.name,
              remarks: data.remarks,
              totalCost: data.cost
          }
      });
      setModalOpen(null);
  };

  const handleFinalizeCertificate = async (data: any) => {
      const certNo = `CERT/${new Date().getFullYear()}/${Math.floor(1000 + Math.random() * 9000)}`;
      const awardedDate = r.budgetVerifiedDate || r.requestDate;

      await onUpdateStatus(r.id, ProcurementStatus.COMPLETED, 'Completion Certificate Generated', {
          certificate: {
              ...data,
              certificateNumber: certNo,
              awardedDate,
              documentDate: new Date().toISOString().split('T')[0],
              managerName: 'Finance Director', // Fallback, usually signed by manager role
          }
      });
      setModalOpen(null);
  };

  const handleManagerSignCertificate = async () => {
      if (!r.certificate) return;
      await onUpdateStatus(r.id, ProcurementStatus.COMPLETED, 'Completion Certificate Signed by Manager', {
          certificate: {
              ...r.certificate,
              managerName: currentUser.name,
              managerSignature: currentUser.signatureUrl
          }
      });
  };

  const handleEvaluationConfirm = async (data: any) => {
    const sortedVendors = [...data.vendors].map((v: any) => ({...v, selected: false}));
    const activeVendors = sortedVendors.filter((v: any) => v.vendorName && v.price > 0);

    if (activeVendors.length > 0) {
       const minPrice = Math.min(...activeVendors.map((v: any) => v.price));
       const cheapestIndex = sortedVendors.findIndex((v: any) => v.price === minPrice && v.vendorName);
       if (cheapestIndex >= 0) sortedVendors[cheapestIndex].selected = true;
    }

    await onUpdateStatus(r.id, ProcurementStatus.PENDING_APPROVAL, 'Price Evaluation Submitted - Awaiting Manager Approval', {
      evaluationMethod: data.method,
      evaluationType: data.type,
      quotations: sortedVendors,
      stockKeeperSignature: currentUser.signatureUrl
    });
    setModalOpen(null);
  };

  const handleSingleSourceConfirm = async (data: any) => {
    await onUpdateStatus(r.id, ProcurementStatus.PENDING_APPROVAL, 'Single Source Justification Added - Awaiting Manager Approval', {
      evaluationType: 'SINGLE_SOURCE',
      singleSourceJustification: data.justification,
      selectedVendor: data.vendorName,
      quotations: [{ vendorName: data.vendorName, price: data.estimatedPrice, selected: true }],
      stockKeeperSignature: currentUser.signatureUrl
    });
    setModalOpen(null);
  };

  const handleManagerDecision = async (approved: boolean) => {
    if (approved) {
      await onUpdateStatus(r.id, ProcurementStatus.BUDGET_CHECK, 'Evaluation Approved by Manager', {
        authorizedBySignature: currentUser.signatureUrl
      });
    } else {
      await onUpdateStatus(r.id, ProcurementStatus.PR_CREATED, 'Evaluation Rejected by Manager - Re-evaluation Required', {});
    }
  };

  const handleBudgetConfirm = async (code: string) => {
    const prefix = isService ? 'SO' : 'PO';
    const poNumber = `${prefix}/${new Date().getFullYear()}/${Math.floor(Math.random()*10000).toString().padStart(4, '0')}`;
    const selectedVendor = r.quotations?.find(q => q.selected)?.vendorName || 'Unknown Vendor';

    await onUpdateStatus(r.id, ProcurementStatus.PO_ISSUED, `Budget Confirmed & ${isService ? 'SO' : 'PO'} Generated`, {
      budgetCode: code,
      budgetVerifiedDate: new Date().toISOString(),
      poNumber: poNumber,
      selectedVendor: selectedVendor,
      authorizedBySignature: currentUser.signatureUrl
    });
    setModalOpen(null);
  };

  const handleReceiveConfirm = async (items: any[]) => {
    await onReceiveGoods(r.id, items, currentUser.name);
    setModalOpen(null);
  };

  const initialReceiveData = r.items.map(item => ({
      description: item.description,
      orderedQty: item.quantity,
      receivedQty: item.quantity,
      addToInventory: true,
      inventoryAction: item.itemId || 'NEW',
      newCategory: 'c1', // Simple default category
      newLocation: 'Main Store',
      price: r.quotations?.find(q => q.selected)?.price || 0
  }));

  const availableDocs = getAvailableDocuments();

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <Button variant="outline" onClick={() => { onBack(); setIsPrintMode(false); }} icon={ArrowRight} className="rotate-180">Back</Button>
        <div className="flex gap-2">
          {!isPrintMode && <Button variant="secondary" icon={Printer} onClick={() => setIsPrintMode(true)}>Print / Download Documents</Button>}
          {isPrintMode && <Button variant="outline" onClick={() => setIsPrintMode(false)}>Close Preview</Button>}
        </div>
      </div>

      {isPrintMode ? (
        <div className="space-y-4">
             <div className="bg-white p-4 rounded-lg shadow-sm border border-slate-200 flex flex-wrap gap-2 no-print">
                <div className="text-sm font-bold text-slate-500 flex items-center mr-2">Available Documents:</div>
                {availableDocs.map(doc => (
                    <button
                        key={doc.type}
                        onClick={() => setActiveDocType(doc.type)}
                        className={`px-4 py-2 rounded-full text-sm font-medium transition-colors flex items-center gap-2 ${
                            activeDocType === doc.type 
                            ? 'bg-gov-600 text-white shadow-md' 
                            : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                        }`}
                    >
                        <FileText className="w-4 h-4" /> {doc.label}
                    </button>
                ))}
                <div className="ml-auto">
                    <Button icon={Download} onClick={() => window.print()}>Download PDF / Print</Button>
                </div>
             </div>

            <div className="document-preview-wrapper rounded border border-slate-300">
              <DocumentTemplate type={activeDocType} data={r} settings={settings} />
            </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 space-y-6">
            <Card title={`${isService ? 'Service' : 'Goods'} Request #${r.gsrfRefNumber || r.id.toUpperCase()}`}>
              <div className="flex justify-between mb-4">
                <div>
                  <p className="text-sm text-slate-500">Requester</p>
                  <p className="font-medium">{r.requesterName} ({r.section || r.requesterDepartment})</p>
                </div>
                <div className="text-right">
                  <p className="text-sm text-slate-500">Status</p>
                  {renderStatusBadge(r.status)}
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4 mb-4 text-sm">
                 <div>
                   <span className="text-slate-500 block">Date Submitted</span>
                   <span>{new Date(r.requestDate).toLocaleDateString()}</span>
                 </div>
                 <div>
                   <span className="text-slate-500 block">Required By</span>
                   <span>{r.requiredDate ? new Date(r.requiredDate).toLocaleDateString() : 'N/A'}</span>
                 </div>
                 <div className="col-span-2">
                   <span className="text-slate-500 block">Remarks</span>
                   <p className="bg-slate-50 p-2 rounded border border-slate-100">{r.remarks || 'No remarks provided.'}</p>
                 </div>
              </div>

              <div className="mt-4">
                <h4 className="text-sm font-medium border-b border-slate-100 pb-2 mb-2">
                    {!isService ? 'Items Requested' : 'Services Requested'}
                </h4>
                {r.items.map((item, i) => (
                  <div key={i} className="flex justify-between py-2 border-b border-slate-50 text-sm">
                    <div className="flex items-center gap-2">
                       {item.itemId ? <span className="bg-blue-100 text-blue-800 text-[10px] font-bold px-1.5 py-0.5 rounded">INV</span> : null}
                       <span>{item.description}</span>
                    </div>
                    <span className="font-mono bg-slate-100 px-2 rounded">{item.quantity}</span>
                  </div>
                ))}
              </div>

              {/* SERVICE ASSESSMENT SECTION */}
              {r.assessmentDetails && (
                  <div className="mt-4 bg-amber-50 p-3 rounded border border-amber-200">
                      <h4 className="text-sm font-bold text-amber-800 mb-2 flex items-center gap-2"><Wrench className="w-4 h-4"/> Technical Assessment</h4>
                      <p className="text-sm mb-1"><span className="font-semibold">Assessed By:</span> {r.assessmentDetails.assessedBy} on {new Date(r.assessmentDetails.assessmentDate).toLocaleDateString()}</p>
                      <p className="text-sm mb-1"><span className="font-semibold">Findings:</span> {r.assessmentDetails.findings}</p>
                      <p className="text-sm">
                          <span className="font-semibold">Recommendation:</span> {r.assessmentDetails.inHouseRepairPossible ? 'Internal/In-house Fix' : 'External/Contractor Required'}
                      </p>
                  </div>
              )}

              {/* SERVICE COMPLETION SECTION */}
              {r.serviceCompletionDetails && (
                   <div className="mt-4 bg-emerald-50 p-3 rounded border border-emerald-100">
                        <h4 className="text-sm font-bold text-emerald-800 mb-2 flex items-center gap-2"><CheckCircle className="w-4 h-4"/> Completion Verification</h4>
                        <p className="text-sm mb-1"><span className="font-semibold">Verified By:</span> {r.serviceCompletionDetails.verifiedBy} on {new Date(r.serviceCompletionDetails.completionDate).toLocaleDateString()}</p>
                        <p className="text-sm mb-1"><span className="font-semibold">Work Done:</span> {r.serviceCompletionDetails.remarks}</p>
                        <p className="text-sm font-bold text-emerald-900">Total Cost: MVR {r.serviceCompletionDetails.totalCost.toFixed(2)}</p>
                   </div>
              )}

              {r.certificate && (
                 <div className="mt-4 bg-indigo-50 p-3 rounded border border-indigo-200">
                    <h4 className="text-sm font-bold text-indigo-800 mb-2 flex items-center gap-2"><Award className="w-4 h-4"/> Completion Certificate Issued</h4>
                    <p className="text-sm"><span className="font-bold">Cert #:</span> {r.certificate.certificateNumber}</p>
                    <p className="text-sm"><span className="font-bold">Agreement #:</span> {r.certificate.agreementNumber}</p>
                    <p className="text-sm"><span className="font-bold">Status:</span> {r.certificate.managerSignature ? <span className="text-green-600 font-bold">SIGNED</span> : <span className="text-orange-600 font-bold">AWAITING SIGNATURE</span>}</p>
                 </div>
              )}

              {r.issueDetails && (
                <div className="mt-4 bg-purple-50 p-3 rounded border border-purple-100">
                   <h4 className="text-sm font-bold text-purple-800 mb-2">Issue Details</h4>
                   <p className="text-sm">Issued To: {r.issueDetails.receiverName} ({r.issueDetails.receiverDepartment})</p>
                   <p className="text-sm">Date: {new Date(r.issueDetails.issueDate).toLocaleDateString()}</p>
                   <p className="text-sm italic">"{r.issueDetails.remarks}"</p>
                </div>
              )}
              {r.evaluationType === 'SINGLE_SOURCE' && r.singleSourceJustification && (
                <div className="mt-4 bg-teal-50 p-3 rounded border border-teal-100">
                   <h4 className="text-sm font-bold text-teal-800 mb-2">Single Source Procurement</h4>
                   <p className="text-sm"><span className="font-semibold">Selected Vendor:</span> {r.quotations?.[0]?.vendorName}</p>
                   <p className="text-sm mt-1"><span className="font-semibold">Justification:</span> {r.singleSourceJustification}</p>
                </div>
              )}
              {r.evaluationType !== 'SINGLE_SOURCE' && r.evalRefNumber && (
                <div className="mt-4 bg-pink-50 p-3 rounded border border-pink-100">
                   <h4 className="text-sm font-bold text-pink-800 mb-2">Price Evaluation ({r.evalRefNumber})</h4>
                   <p className="text-sm">Method: {r.evaluationMethod} | Type: {r.evaluationType || 'FORM'}</p>
                   <div className="flex gap-4 mt-2 overflow-x-auto">
                     {r.quotations?.map((q, i) => (
                       <div key={i} className={`p-2 border rounded text-xs min-w-[120px] ${q.selected ? 'bg-green-100 border-green-300 shadow-sm' : 'bg-white'}`}>
                         {q.selected && <div className="text-green-700 font-bold mb-1 text-[10px] uppercase">✓ Best Offer</div>}
                         <p className="font-bold">{q.vendorName}</p>
                         {q.quoteNumber && <p className="text-[10px] text-slate-500">#{q.quoteNumber}</p>}
                         <p className="mt-1 font-mono">MVR {(q.price || 0).toFixed(2)}</p>
                       </div>
                     ))}
                   </div>
                </div>
              )}
              {(r.status === ProcurementStatus.PO_ISSUED || r.status === ProcurementStatus.COMPLETED) && r.poNumber && (
                 <div className="mt-4 bg-teal-50 p-3 rounded border border-teal-100">
                    <h4 className="text-sm font-bold text-teal-800 mb-2 flex items-center"><Check className="w-4 h-4 mr-1"/> {isService ? 'Service Order' : 'Purchase Order'} Generated</h4>
                    <p className="text-sm"><span className="font-bold">{isService ? 'SO' : 'PO'} Number:</span> {r.poNumber}</p>
                    <p className="text-sm"><span className="font-bold">Budget Code:</span> {r.budgetCode}</p>
                    <p className="text-sm"><span className="font-bold">Vendor:</span> {r.quotations?.find(q => q.selected)?.vendorName}</p>
                 </div>
              )}
            </Card>

            {/* Workflow Actions */}
            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.SUBMITTED && (
              <Card title={`${!isService ? 'Store' : 'Service'} Officer Action`}>
                {!isService ? (
                   <>
                    <p className="text-sm text-slate-600 mb-4">Check stock availability for requested items.</p>
                    <div className="flex gap-4">
                        <Button className="flex-1" onClick={() => setModalOpen('ISSUE')}>
                        <Check className="mr-2 h-4 w-4" /> Available - Issue Stock
                        </Button>
                        <Button className="flex-1" variant="secondary" onClick={() => onUpdateStatus(r.id, ProcurementStatus.PROCUREMENT_NEEDED, 'Marked for Procurement', { stockKeeperSignature: currentUser.signatureUrl || 'signed', stockCheckDate: new Date().toISOString(), gsrfRefNumber: r.gsrfRefNumber })}>
                        <X className="mr-2 h-4 w-4" /> Not Available - Create PR
                        </Button>
                    </div>
                   </>
                ) : (
                    <>
                        <p className="text-sm text-slate-600 mb-4">Assess the service request for in-house resolution or external procurement.</p>
                        <Button className="w-full" icon={Wrench} onClick={() => setModalOpen('ASSESS')}>Perform Technical Assessment</Button>
                    </>
                )}
              </Card>
            )}

            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PROCUREMENT_NEEDED && (
              <Card title="Procurement Processing">
                <p className="text-sm text-slate-600 mb-4">Convert this request into a formal {isService ? 'Service Request' : 'Purchase Request'}.</p>
                <Button onClick={() => onUpdateStatus(r.id, ProcurementStatus.PR_CREATED, `${isService ? 'Service' : 'Purchase'} Request Created`, { prRefNumber: `${isService ? 'SR' : 'PR'}/${new Date().getFullYear()}/${Math.floor(Math.random()*1000)}`, stockKeeperSignature: currentUser.signatureUrl })}>
                  Generate {isService ? 'Service Request (SR)' : 'Purchase Request (PR)'}
                </Button>
              </Card>
            )}

            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PR_CREATED && (
              <Card title="Procurement Action">
                <p className="text-sm text-slate-600 mb-4">Choose procurement method for this {r.requestType.toLowerCase()}.</p>
                <div className="flex flex-col gap-3">
                  <Button onClick={() => setModalOpen('EVAL')}>
                    <DollarSign className="mr-2 h-4 w-4" /> Start Price Evaluation
                  </Button>
                  <Button variant="outline" onClick={() => setModalOpen('SINGLE')}>
                    <AlertCircle className="mr-2 h-4 w-4" /> Single Source Procurement
                  </Button>
                </div>
              </Card>
            )}

            {r.status === ProcurementStatus.PENDING_APPROVAL && (
              <Card title="Approval Required">
                {(currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN) ? (
                  <>
                    <p className="text-sm text-slate-600 mb-4">Review the evaluation and approve to proceed to budgeting.</p>
                    <div className="flex gap-4">
                      <Button className="flex-1" onClick={() => handleManagerDecision(true)}>
                        <ThumbsUp className="mr-2 h-4 w-4" /> Approve
                      </Button>
                      <Button className="flex-1" variant="danger" onClick={() => handleManagerDecision(false)}>
                        <ThumbsDown className="mr-2 h-4 w-4" /> Reject (Re-do)
                      </Button>
                    </div>
                  </>
                ) : (
                  <div className="flex flex-col items-center justify-center py-6 text-slate-500">
                    <ShieldCheck className="w-12 h-12 text-amber-400 mb-2" />
                    <p className="text-center font-medium">Pending Manager Approval</p>
                  </div>
                )}
              </Card>
            )}

            {(currentUser.role === UserRole.STOCK_KEEPER || currentUser.role === UserRole.FINANCE_OFFICER) && r.status === ProcurementStatus.BUDGET_CHECK && (
               <Card title="Budget Verification">
                  <p className="text-sm text-slate-600 mb-4">Verify budget availability and assign a Budget Code.</p>
                  <div className="flex justify-end">
                     <Button onClick={() => setModalOpen('BUDGET')} icon={CreditCard}>Verify Budget & Issue {isService ? 'SO' : 'PO'}</Button>
                  </div>
               </Card>
            )}

            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PO_ISSUED && (
              <Card title={!isService ? 'Goods Receipt (GRN)' : 'Work Completion'}>
                  <p className="text-sm text-slate-600 mb-4">
                      {!isService ? 'Confirm receipt of items and update inventory.' : 'Verify service work completion and final costs.'}
                  </p>
                  {!isService ? (
                      <Button onClick={() => setModalOpen('RECEIVE')} icon={PackageCheck}>Receive Items & Update Inventory</Button>
                  ) : (
                      <Button onClick={() => setModalOpen('COMPLETION')} icon={CheckCircle}>Verify Work Completion</Button>
                  )}
              </Card>
            )}

            {r.status === ProcurementStatus.COMPLETED && !r.certificate && currentUser.role === UserRole.STOCK_KEEPER && (
              <Card title="Completion Certificate">
                 <p className="text-sm text-slate-600 mb-4">Generate the formal Completion Certificate for the vendor/contractor.</p>
                 <Button onClick={() => setModalOpen('CERT_FINAL')} icon={Award}>Finalize Certificate Details</Button>
              </Card>
            )}

            {r.status === ProcurementStatus.COMPLETED && r.certificate && !r.certificate.managerSignature && (currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN) && (
              <Card title="Certificate Signature Needed">
                 <p className="text-sm text-slate-600 mb-4">The completion certificate for this {r.requestType.toLowerCase()} is ready. Review and sign to finalize.</p>
                 <Button onClick={handleManagerSignCertificate} icon={CheckCircle}>Sign Completion Certificate</Button>
              </Card>
            )}

          </div>

          <div className="space-y-6">
             <Card title="Signatures">
               <div className="space-y-4">
                 <div>
                   <p className="text-xs text-slate-500">Requester</p>
                   {r.requesterSignature ? <img src={r.requesterSignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                 </div>
                 <div>
                   <p className="text-xs text-slate-500">{!isService ? 'Store' : 'Technical'} Officer</p>
                   {r.stockKeeperSignature ? <img src={r.stockKeeperSignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                 </div>
                 {r.authorizedBySignature && (
                    <div>
                      <p className="text-xs text-slate-500">Authorized Official</p>
                      <img src={r.authorizedBySignature} className="h-8 border border-slate-200 mt-1"/>
                    </div>
                 )}
                 {r.certificate?.managerSignature && (
                    <div>
                      <p className="text-xs text-slate-500">Manager (Certificate Signatory)</p>
                      <img src={r.certificate.managerSignature} className="h-8 border border-slate-200 mt-1"/>
                    </div>
                 )}
               </div>
             </Card>

             <Card title="History Log">
               <ul className="space-y-3 relative border-l border-slate-200 ml-2 pl-4">
                 {r.logs.map((log, i) => (
                   <li key={i} className="text-xs">
                     <div className="absolute w-2 h-2 bg-slate-300 rounded-full -left-[5px] mt-1"></div>
                     <p className="font-semibold text-slate-700">{log.action}</p>
                     <p className="text-slate-500">{new Date(log.date).toLocaleString()} by {log.actor}</p>
                   </li>
                 ))}
               </ul>
             </Card>
          </div>
        </div>
      )}

      {/* Modals */}
      {modalOpen === 'ISSUE' && <IssueStockModal onClose={() => setModalOpen(null)} onConfirm={handleIssueConfirm} />}
      {modalOpen === 'ASSESS' && <AssessmentModal onClose={() => setModalOpen(null)} onConfirm={handleAssessmentConfirm} />}
      {modalOpen === 'COMPLETION' && <ServiceCompletionModal onClose={() => setModalOpen(null)} onConfirm={handleServiceCompletion} />}
      {modalOpen === 'CERT_FINAL' && <FinalCertificateModal onClose={() => setModalOpen(null)} onConfirm={handleFinalizeCertificate} />}
      {modalOpen === 'BUDGET' && <BudgetModal requestType={r.requestType} onClose={() => setModalOpen(null)} onConfirm={handleBudgetConfirm} />}
      {modalOpen === 'SINGLE' && <SingleSourceModal onClose={() => setModalOpen(null)} onConfirm={handleSingleSourceConfirm} />}
      {modalOpen === 'EVAL' && <EvaluationModal vendors={vendors} onClose={() => setModalOpen(null)} onConfirm={handleEvaluationConfirm} />}
      {modalOpen === 'RECEIVE' && <ReceiveGoodsModal initialItems={initialReceiveData} inventory={inventory} onClose={() => setModalOpen(null)} onConfirm={handleReceiveConfirm} />}
    </div>
  );
};

import React from 'react';
import { ProcurementWorkflow, SystemSettings, ProcurementStatus } from '../types';

interface DocumentTemplateProps {
  type: 'GSRF' | 'PRF' | 'PO' | 'PEF' | 'CERT';
  data: ProcurementWorkflow;
  settings?: SystemSettings | null;
}

export const DocumentTemplate: React.FC<DocumentTemplateProps> = ({ type, data, settings }) => {
  const currentYear = new Date().getFullYear();
  const isService = data.requestType === 'SERVICE';

  const renderHeader = (title: string, refNo: string) => (
    <div className="flex flex-col mb-6 border-b-2 border-black pb-4">
      <div className="flex justify-between items-start w-full relative min-h-[80px]">
        {settings?.templateConfig?.showLogo && settings?.logoUrl && (
           <div className="w-24 h-20 flex items-center justify-center flex-shrink-0">
             <img src={settings.logoUrl} alt="Logo" className="max-w-full max-h-full object-contain" />
           </div>
        )}
        <div className="flex-1 text-right pl-4">
          <h1 className="text-xl font-bold uppercase tracking-wider mb-1 font-serif">
              {settings?.officeName || 'Government Entity of State'}
          </h1>
          <h2 className="text-sm uppercase text-slate-700 mb-1 font-serif">
              {settings?.departmentName || 'Department of Administration & Finance'}
          </h2>
          <div className="text-[10px] text-slate-600 leading-tight">
             <p className="whitespace-pre-line">{settings?.officeAddress || 'Address Not Configured'}</p>
             <div className="mt-1 flex flex-wrap justify-end gap-x-3">
                {settings?.phone && <span>Tel: {settings.phone}</span>}
                {settings?.email && <span>Email: {settings.email}</span>}
                {settings?.website && <span>Web: {settings.website}</span>}
                {settings?.taxId && <span>Tax ID: {settings.taxId}</span>}
             </div>
          </div>
        </div>
      </div>
      <div className="w-full flex justify-between items-end mt-4 pt-2 border-t border-slate-200">
        <div>
          <p className="text-xs font-bold uppercase tracking-wide text-gov-800">Official Document: {title}</p>
        </div>
        <div className="text-right">
          <p className="text-sm"><span className="font-bold uppercase text-[10px] text-slate-500 block">Reference Number</span> {refNo}</p>
          <p className="text-[10px] text-slate-500 font-bold uppercase mt-1">Date: {new Date().toLocaleDateString()}</p>
        </div>
      </div>
    </div>
  );

  const renderCustomBlocks = () => {
      if (!settings?.templateConfig?.customBlocks || settings.templateConfig.customBlocks.length === 0) return null;

      return (
          <div className="mt-8 pt-4 border-t-2 border-dashed border-slate-300">
              {settings.templateConfig.customBlocks.map(block => (
                  <div key={block.id} className="mb-4">
                      {block.type === 'title' && <h3 className="text-lg font-bold uppercase mb-2">{block.content}</h3>}
                      {block.type === 'text' && <p className="text-xs text-slate-700 whitespace-pre-wrap">{block.content}</p>}
                      {block.type === 'divider' && <hr className="border-black my-4" />}
                      {block.type === 'signature' && (
                          <div className="mt-8 pt-2 border-t border-black w-48">
                              <p className="text-xs font-bold uppercase">{block.content || 'Authorized Signature'}</p>
                          </div>
                      )}
                      {block.type === 'image' && (
                          <div className="h-24 w-24 bg-slate-100 flex items-center justify-center text-slate-400 border border-slate-300">
                              IMG
                          </div>
                      )}
                  </div>
              ))}
          </div>
      );
  };

  const renderFooter = () => (
      <div className="mt-auto pt-8 border-t border-slate-300 text-center text-[9px] text-slate-500">
          <p>{settings?.templateConfig?.footerText || 'System Generated Document'}</p>
          <p className="mt-1">Generated by GovTrack System • {new Date().toLocaleString()}</p>
      </div>
  );

  const renderSignatureBlock = (role: string, name: string | undefined, signature: string | undefined, date: string | undefined) => (
    <div className="flex-1 flex flex-col items-center">
      <div className="h-16 w-32 mb-1 flex items-end justify-center">
        {signature ? <img src={signature} alt="Signed" className="max-h-16 object-contain" /> : <div className="h-8"></div>}
      </div>
      <div className="w-32 border-t border-black pt-1 text-center">
        <p className="text-[10px] font-bold uppercase">{role}</p>
        <p className="text-[10px] truncate max-w-full">{name || '________________'}</p>
        <p className="text-[9px] text-slate-500">{date ? new Date(date).toLocaleDateString() : ''}</p>
      </div>
    </div>
  );

  // --- Completion Certificate (CERT) ---
  if (type === 'CERT' && data.certificate) {
    const c = data.certificate;
    const vendorName = data.quotations?.find(q => q.selected)?.vendorName || 'Selected Vendor';
    const totalPrice = data.serviceCompletionDetails?.totalCost || data.quotations?.find(q => q.selected)?.price || 0;

    return (
        <div className="printable-area flex flex-col text-black font-sans">
            {renderHeader('COMPLETION CERTIFICATE', c.certificateNumber)}

            <div className="text-center my-8">
                <h2 className="text-2xl font-bold uppercase underline tracking-widest font-serif">Certificate of Completion</h2>
            </div>

            <div className="space-y-6 text-sm leading-relaxed">
                <p>This is to certify that the following work/service has been successfully completed to the satisfaction of <span className="font-bold">{settings?.officeName}</span>.</p>

                <div className="border border-black p-4 space-y-3 bg-slate-50">
                    <div className="grid grid-cols-3 gap-4">
                        <div className="font-bold text-slate-500 uppercase text-[10px]">Work Details:</div>
                        <div className="col-span-2 font-medium">{data.items.map(i => i.description).join(', ')}</div>
                    </div>
                    <div className="grid grid-cols-3 gap-4 border-t border-slate-200 pt-2">
                        <div className="font-bold text-slate-500 uppercase text-[10px]">Work Performed by:</div>
                        <div className="col-span-2 font-bold text-gov-800">{vendorName}</div>
                    </div>
                    <div className="grid grid-cols-3 gap-4 border-t border-slate-200 pt-2">
                        <div className="font-bold text-slate-500 uppercase text-[10px]">Awarded by:</div>
                        <div className="col-span-2">{settings?.officeName}</div>
                    </div>
                    <div className="grid grid-cols-3 gap-4 border-t border-slate-200 pt-2">
                        <div className="font-bold text-slate-500 uppercase text-[10px]">Agreement / Contract #:</div>
                        <div className="col-span-2 font-mono">{c.agreementNumber}</div>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-8 py-4">
                    <div className="space-y-2">
                        <div className="flex justify-between border-b border-slate-200 pb-1">
                            <span className="text-[10px] font-bold text-slate-500">Awarded Date:</span>
                            <span>{new Date(c.awardedDate).toLocaleDateString()}</span>
                        </div>
                        <div className="flex justify-between border-b border-slate-200 pb-1">
                            <span className="text-[10px] font-bold text-slate-500">Started Date:</span>
                            <span>{c.startedDate ? new Date(c.startedDate).toLocaleDateString() : 'N/A'}</span>
                        </div>
                        <div className="flex justify-between border-b border-slate-200 pb-1">
                            <span className="text-[10px] font-bold text-slate-500">Completed Date:</span>
                            <span>{new Date(c.completionDate).toLocaleDateString()}</span>
                        </div>
                    </div>
                    <div className="space-y-2">
                        <div className="flex justify-between border-b border-slate-200 pb-1">
                            <span className="text-[10px] font-bold text-slate-500">Duration:</span>
                            <span>{c.duration || 'N/A'}</span>
                        </div>
                        <div className="flex justify-between border-b border-slate-200 pb-1">
                            <span className="text-[10px] font-bold text-slate-500">Total Price:</span>
                            <span className="font-bold">MVR {totalPrice.toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between border-b border-slate-200 pb-1">
                            <span className="text-[10px] font-bold text-slate-500">Document Date:</span>
                            <span>{new Date(c.documentDate).toLocaleDateString()}</span>
                        </div>
                    </div>
                </div>

                <div className="space-y-2 pt-4">
                    <p className="text-[10px] font-bold text-slate-500 uppercase">Amount in Words:</p>
                    <p className="italic font-medium border border-slate-200 p-2 rounded bg-slate-50">{c.totalPriceInWords}</p>
                </div>

                {c.additionalNotes && (
                    <div className="space-y-2 pt-4">
                        <p className="text-[10px] font-bold text-slate-500 uppercase">Additional Notes / Observations:</p>
                        <p className="text-xs whitespace-pre-wrap">{c.additionalNotes}</p>
                    </div>
                )}
            </div>

            <div className="mt-16 flex justify-end">
                <div className="w-64 text-center">
                    <div className="h-20 flex items-end justify-center mb-1">
                        {c.managerSignature ? (
                            <img src={c.managerSignature} alt="Signed" className="max-h-20 object-contain" />
                        ) : (
                            <div className="h-1 bg-slate-300 w-full mb-2"></div>
                        )}
                    </div>
                    <div className="border-t border-black pt-2">
                        <p className="text-xs font-bold uppercase">Authorized Signatory (Manager)</p>
                        <p className="text-sm">{c.managerName || '________________________'}</p>
                        <p className="text-[10px] text-slate-500">{settings?.officeName}</p>
                    </div>
                </div>
            </div>

            {renderCustomBlocks()}
            {renderFooter()}
        </div>
    );
  }

  // --- Goods & Services Requisition Form (GSRF) ---
  if (type === 'GSRF') {
    const isGoods = data.requestType === 'GOODS';
    const isIssued = data.status === ProcurementStatus.ISSUED || data.status === ProcurementStatus.COMPLETED || data.status === ProcurementStatus.PO_ISSUED;

    return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader(isGoods ? 'GOODS REQUISITION FORM' : 'SERVICE REQUISITION FORM', data.gsrfRefNumber || `GSRF/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-x-8 gap-y-2 text-xs">
          <div><span className="font-bold block">Requesting Section:</span> {data.section || data.requesterDepartment}</div>
          <div><span className="font-bold block">Required By Date:</span> {data.requiredDate ? new Date(data.requiredDate).toLocaleDateString() : 'N/A'}</div>
          <div className="col-span-2 mt-2">
              <span className="font-bold block">{isGoods ? 'Purpose / Remarks:' : 'Work Scope / Description of Problem:'}</span> 
              <div className="border border-slate-300 p-2 min-h-[40px] rounded bg-slate-50">{data.remarks || 'N/A'}</div>
          </div>
          {isGoods && data.issueDetails && (
            <div className="col-span-2 border-t border-slate-300 pt-2 mt-2">
                <span className="font-bold">Issue Status:</span> <span className="text-green-800 font-semibold">ISSUED</span> to {data.issueDetails.receiverName} on {new Date(data.issueDetails.issueDate).toLocaleDateString()}
            </div>
          )}
          {!isGoods && data.assessmentDetails && (
             <div className="col-span-2 border-t border-slate-300 pt-2 mt-2">
                <span className="font-bold">Technical Findings:</span> <span className="text-slate-700">{data.assessmentDetails.findings}</span>
            </div>
          )}
        </div>

        <table className="w-full border-collapse border border-black mb-6 text-xs">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">#</th>
              <th className="border border-black p-2 text-left">{isGoods ? 'Item Description' : 'Service Task / Requirement'}</th>
              <th className="border border-black p-2 w-20">{isGoods ? 'Req Qty' : 'Qty'}</th>
              {isGoods && <th className="border border-black p-2 w-20">Issued</th>}
              <th className="border border-black p-2">Notes</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                <td className="border border-black p-2 text-center font-bold">{item.quantity}</td>
                {isGoods && <td className="border border-black p-2 text-center">{isIssued ? item.quantity : ''}</td>}
                <td className="border border-black p-2"></td>
              </tr>
            ))}
            {[...Array(Math.max(0, 8 - data.items.length))].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                {isGoods && <td className="border border-black"></td>}
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

        <div className="flex justify-between mt-8 gap-2">
          {renderSignatureBlock('REQUESTED BY', data.requesterName, data.requesterSignature, data.requestDate)}
          {renderSignatureBlock('SECTION HEAD', 'Supervisor', undefined, undefined)}
          {renderSignatureBlock(isGoods ? 'STOCK KEEPER' : 'TECHNICAL OFFICER', isGoods ? 'Stores Officer' : 'Maintenance Lead', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('RECEIVED BY / VERIFIED BY', data.issueDetails?.receiverName || data.serviceCompletionDetails?.verifiedBy || 'Authorized Party', undefined, data.issueDetails?.issueDate || data.serviceCompletionDetails?.completionDate)}
        </div>

        {renderCustomBlocks()}
        {renderFooter()}
      </div>
    );
  }

  // --- Purchase Request Form (PRF) ---
  if (type === 'PRF') {
     return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader(isService ? 'SERVICE REQUEST FORM' : 'PURCHASE REQUEST FORM', data.prRefNumber || `${isService ? 'SR' : 'PR'}/${currentYear}/PENDING`)}

        <div className="mb-6 grid grid-cols-2 gap-x-8 gap-y-2 text-xs">
           <div><span className="font-bold">{isService ? 'SRF' : 'GSRF'} Reference:</span> {data.gsrfRefNumber || 'N/A'}</div>
           <div><span className="font-bold">Date Raised:</span> {new Date().toLocaleDateString()}</div>
           <div className="col-span-2 border-b border-black pb-2 mb-2"></div>
           <div><span className="font-bold">Department:</span> {data.section || data.requesterDepartment}</div>
           <div><span className="font-bold">Required Date:</span> {data.requiredDate ? new Date(data.requiredDate).toLocaleDateString() : 'N/A'}</div>
        </div>

        <table className="w-full border-collapse border border-black mb-8 text-xs">
          <thead>
            <tr className="bg-slate-100">
              <th className="border border-black p-2 w-12">#</th>
              <th className="border border-black p-2 text-left">Description</th>
              {!isService && <th className="border border-black p-2 w-24">In Stock</th>}
              <th className="border border-black p-2 w-24">{isService ? 'Quantity' : 'Purchase Qty'}</th>
            </tr>
          </thead>
          <tbody>
            {data.items.map((item, idx) => (
              <tr key={idx}>
                <td className="border border-black p-2 text-center">{idx + 1}</td>
                <td className="border border-black p-2">{item.description}</td>
                {!isService && <td className="border border-black p-2 text-center text-slate-500">0</td>}
                <td className="border border-black p-2 text-center font-bold">{item.quantity}</td>
              </tr>
            ))}
            {[...Array(Math.max(0, 8 - data.items.length))].map((_, i) => (
               <tr key={`empty-${i}`} className="h-8">
                <td className="border border-black"></td>
                <td className="border border-black"></td>
                {!isService && <td className="border border-black"></td>}
                <td className="border border-black"></td>
               </tr>
            ))}
          </tbody>
        </table>

         <div className="flex justify-between mt-12 gap-8">
          {renderSignatureBlock('PREPARED BY', isService ? 'Technical Officer' : 'Procurement Officer', data.stockKeeperSignature, data.stockCheckDate)}
          {renderSignatureBlock('VERIFIED BY', 'Finance Officer', undefined, undefined)}
          {renderSignatureBlock('AUTHORIZED BY', isService ? 'Maintenance Head' : 'Head of Procurement', data.authorizedBySignature, undefined)}
        </div>

        {renderCustomBlocks()}
        {renderFooter()}
      </div>
     );
  }

  // --- Price Evaluation Form (PEF) ---
  if (type === 'PEF') {
    // Single Source
    if (data.evaluationType === 'SINGLE_SOURCE') {
        return (
          <div className="printable-area flex flex-col text-black font-sans">
             {renderHeader('SINGLE SOURCE JUSTIFICATION', data.poNumber || 'PENDING')}

             <div className="mb-6 space-y-4 text-xs">
                <div className="flex justify-between">
                    <div><span className="font-bold">Requesting Section:</span> {data.section || data.requesterDepartment}</div>
                    <div><span className="font-bold">{isService ? 'SR' : 'PR'} Ref No:</span> {data.prRefNumber}</div>
                </div>

                <div className="border border-black p-4 bg-slate-50 min-h-[100px]">
                    <p className="font-bold mb-2 uppercase text-[10px] text-slate-600">Justification for Single Source Procurement:</p>
                    <p className="italic text-sm">{data.singleSourceJustification}</p>
                </div>

                <div className="grid grid-cols-2 gap-6 pt-4">
                    <div className="border border-black p-3">
                        <p className="font-bold text-[10px] uppercase text-slate-500">Selected Vendor / Contractor</p>
                        <p className="font-bold text-lg">{data.selectedVendor}</p>
                    </div>
                    <div className="border border-black p-3">
                        <p className="font-bold text-[10px] uppercase text-slate-500">Total Estimated Cost</p>
                        <p className="font-bold text-lg">MVR {(data.quotations?.[0]?.price || 0).toFixed(2)}</p>
                    </div>
                </div>
             </div>

             <div className="flex justify-between mt-12 gap-4">
                {renderSignatureBlock('REQUESTED BY', isService ? 'Technical Officer' : 'Procurement Officer', data.stockKeeperSignature, undefined)}
                {renderSignatureBlock('APPROVED BY', 'Director General', data.authorizedBySignature, undefined)}
            </div>

            {renderCustomBlocks()}
            {renderFooter()}
          </div>
        );
    }

    // Matrix Evaluation
    return (
      <div className="printable-area flex flex-col text-black font-sans">
        {renderHeader('PRICE EVALUATION FORM', data.evalRefNumber || 'PENDING')}

        <div className="mb-4 grid grid-cols-3 gap-4 text-xs">
          <div><span className="font-bold">Dept:</span> {data.section || data.requesterDepartment}</div>
          <div><span className="font-bold">Method:</span> {data.evaluationMethod}</div>
          <div><span className="font-bold">{isService ? 'SR' : 'PR'} Ref:</span> {data.prRefNumber}</div>
        </div>

        {data.evaluationType === 'QUOTATION' ? (
           // Quotation Based Table
           <table className="w-full border-collapse border border-black mb-6 text-xs">
             <thead>
               <tr className="bg-slate-100">
                 <th className="border border-black p-2 w-10">#</th>
                 <th className="border border-black p-2 text-left">Vendor Name</th>
                 <th className="border border-black p-2 w-24">Quote No</th>
                 <th className="border border-black p-2 w-24">Date</th>
                 <th className="border border-black p-2 w-28 text-right">Total (MVR)</th>
               </tr>
             </thead>
             <tbody>
                {data.quotations?.map((q, idx) => (
                    <tr key={idx} className={q.selected ? "bg-green-50" : ""}>
                        <td className="border border-black p-2 text-center">{idx + 1}</td>
                        <td className="border border-black p-2 font-medium">
                            {q.vendorName}
                            {q.selected && <span className="block text-[9px] font-bold text-green-700 mt-1">[RECOMMENDED]</span>}
                        </td>
                        <td className="border border-black p-2 text-center">{q.quoteNumber || '-'}</td>
                        <td className="border border-black p-2 text-center">{q.quoteDate ? new Date(q.quoteDate).toLocaleDateString() : '-'}</td>
                        <td className="border border-black p-2 text-right font-mono font-bold">{(q.price || 0).toFixed(2)}</td>
                    </tr>
                ))}
             </tbody>
           </table>
        ) : (
           // Form Based Table (Item Matrix)
           <table className="w-full border-collapse border border-black mb-6 text-[10px]">
            <thead>
                <tr className="bg-slate-100">
                <th className="border border-black p-1 w-8">#</th>
                <th className="border border-black p-1 text-left">Description</th>
                <th className="border border-black p-1 w-12">Qty</th>
                {data.quotations?.map((q, i) => (
                    <th key={i} className="border border-black p-1 w-24">
                        <div className="font-bold truncate">{q.vendorName || `Vendor ${i+1}`}</div>
                        <div className="font-normal text-[9px]">Unit Price</div>
                    </th>
                )) || <th className="border border-black p-1">Vendor Details</th>}
                </tr>
            </thead>
            <tbody>
                {data.items.map((item, idx) => (
                <tr key={idx}>
                    <td className="border border-black p-1 text-center">{idx + 1}</td>
                    <td className="border border-black p-1">{item.description}</td>
                    <td className="border border-black p-1 text-center">{item.quantity}</td>
                    {data.quotations?.map((q, i) => (
                    <td key={i} className="border border-black p-1 text-center">
                        {q.price > 0 ? `${q.price.toFixed(2)}` : '-'}
                    </td>
                    ))}
                </tr>
                ))}
                <tr className="font-bold bg-slate-50 border-t-2 border-black">
                    <td colSpan={3} className="border border-black p-1 text-right">TOTAL (MVR)</td>
                    {data.quotations?.map((q, i) => (
                    <td key={i} className={`border border-black p-2 text-center ${q.selected ? 'bg-green-100' : ''}`}>
                        {q.price > 0 ? `${(q.price * (data.items[0]?.quantity || 1)).toFixed(2)}` : '-'}
                        {q.selected && <div className="text-[9px] text-green-800">RECOMMENDED</div>}
                    </td>
                    ))}
                </tr>
            </tbody>
            </table>
        )}

        <div className="mt-4 mb-4 text-xs border border-black p-3">
          <p className="font-bold mb-1 uppercase text-slate-500 text-[10px]">Recommendation / Committee Notes:</p>
          <p>
             Based on the evaluation above, it is recommended to award the contract to 
             <span className="font-bold underline mx-1">{data.quotations?.find(q => q.selected)?.vendorName}</span> 
             as they meet the technical requirements at the most competitive price.
          </p>
        </div>

        <div className="flex justify-between mt-auto pt-8 gap-4">
          {renderSignatureBlock('PREPARED BY', isService ? 'Technical Officer' : 'Procurement Officer', data.stockKeeperSignature, undefined)}
          {renderSignatureBlock('CHECKED BY', 'Finance Officer', undefined, undefined)}
          {renderSignatureBlock('APPROVED BY', 'Director', data.authorizedBySignature, undefined)}
        </div>

        {renderCustomBlocks()}
        {renderFooter()}
      </div>
    );
  }

  // --- Service Order (SO) or Purchase Order (PO) ---
  if (type === 'PO') {
     const selectedQuote = data.quotations?.find(q => q.selected);
     const totalAmount = selectedQuote ? selectedQuote.price : 0;
     const docTitle = isService ? 'SERVICE ORDER' : 'PURCHASE ORDER';
     const refLabel = isService ? 'SO' : 'PO';

     return (
       <div className="printable-area flex flex-col text-black font-sans">
         {renderHeader(docTitle, data.poNumber || 'PENDING')}

         <div className="flex justify-between mb-8 text-xs gap-8">
            <div className="w-1/2 border border-black p-3">
               <h3 className="font-bold uppercase mb-2 border-b border-black pb-1">{isService ? 'Contractor Details' : 'Vendor Details'}</h3>
               <p className="font-bold text-sm">{selectedQuote?.vendorName || 'N/A'}</p>
               <p className="text-slate-600">Quote Ref: {selectedQuote?.quoteNumber || 'N/A'}</p>
               {selectedQuote?.quoteDate && <p className="text-slate-600">Date: {new Date(selectedQuote.quoteDate).toLocaleDateString()}</p>}
            </div>
            <div className="w-1/2 border border-black p-3 bg-slate-50">
