                    <AlertCircle className="mr-2 h-4 w-4" /> Single Source Procurement
                  </Button>
                </div>
              </Card>
            )}

            {r.status === ProcurementStatus.PENDING_APPROVAL && (
              <Card title="Approval Required">
                {(currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN) ? (
                  <>
                    <p className="text-sm text-slate-600 mb-4">Review the evaluation and approve to proceed to budgeting.</p>
                    <div className="flex gap-4">
                      <Button className="flex-1" onClick={() => handleManagerDecision(true)}>
                        <ThumbsUp className="mr-2 h-4 w-4" /> Approve
                      </Button>
                      <Button className="flex-1" variant="danger" onClick={() => handleManagerDecision(false)}>
                        <ThumbsDown className="mr-2 h-4 w-4" /> Reject (Re-do)
                      </Button>
                    </div>
                  </>
                ) : (
                  <div className="flex flex-col items-center justify-center py-6 text-slate-500">
                    <ShieldCheck className="w-12 h-12 text-amber-400 mb-2" />
                    <p className="text-center font-medium">Pending Manager Approval</p>
                  </div>
                )}
              </Card>
            )}

            {(currentUser.role === UserRole.STOCK_KEEPER || currentUser.role === UserRole.FINANCE_OFFICER) && r.status === ProcurementStatus.BUDGET_CHECK && (
               <Card title="Budget Verification">
                  <p className="text-sm text-slate-600 mb-4">Verify budget availability and assign a Budget Code.</p>
                  <div className="flex justify-end">
                     <Button onClick={() => setModalOpen('BUDGET')} icon={CreditCard}>Verify Budget & Issue {isService ? 'SO' : 'PO'}</Button>
                  </div>
               </Card>
            )}

            {currentUser.role === UserRole.STOCK_KEEPER && r.status === ProcurementStatus.PO_ISSUED && (
              <Card title={!isService ? 'Goods Receipt (GRN)' : 'Work Completion'}>
                  <p className="text-sm text-slate-600 mb-4">
                      {!isService ? 'Confirm receipt of items and update inventory.' : 'Verify service work completion and final costs.'}
                  </p>
                  {!isService ? (
                      <Button onClick={() => setModalOpen('RECEIVE')} icon={PackageCheck}>Receive Items & Update Inventory</Button>
                  ) : (
                      <Button onClick={() => setModalOpen('COMPLETION')} icon={CheckCircle}>Verify Work Completion</Button>
                  )}
              </Card>
            )}

            {r.status === ProcurementStatus.COMPLETED && !r.certificate && currentUser.role === UserRole.STOCK_KEEPER && (
              <Card title="Completion Certificate">
                 <p className="text-sm text-slate-600 mb-4">Generate the formal Completion Certificate for the vendor/contractor.</p>
                 <Button onClick={() => setModalOpen('CERT_FINAL')} icon={Award}>Finalize Certificate Details</Button>
              </Card>
            )}

            {r.status === ProcurementStatus.COMPLETED && r.certificate && !r.certificate.managerSignature && (currentUser.role === UserRole.MANAGER || currentUser.role === UserRole.ADMIN) && (
              <Card title="Certificate Signature Needed">
                 <p className="text-sm text-slate-600 mb-4">The completion certificate for this {r.requestType.toLowerCase()} is ready. Review and sign to finalize.</p>
                 <Button onClick={handleManagerSignCertificate} icon={CheckCircle}>Sign Completion Certificate</Button>
              </Card>
            )}

          </div>

          <div className="space-y-6">
             <Card title="Signatures">
               <div className="space-y-4">
                 <div>
                   <p className="text-xs text-slate-500">Requester</p>
                   {r.requesterSignature ? <img src={r.requesterSignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                 </div>
                 <div>
                   <p className="text-xs text-slate-500">{!isService ? 'Store' : 'Technical'} Officer</p>
                   {r.stockKeeperSignature ? <img src={r.stockKeeperSignature} className="h-8 border border-slate-200 mt-1"/> : <span className="text-xs italic">Pending</span>}
                 </div>
                 {r.authorizedBySignature && (
                    <div>
                      <p className="text-xs text-slate-500">Authorized Official</p>
                      <img src={r.authorizedBySignature} className="h-8 border border-slate-200 mt-1"/>
                    </div>
                 )}
                 {r.certificate?.managerSignature && (
                    <div>
                      <p className="text-xs text-slate-500">Manager (Certificate Signatory)</p>
                      <img src={r.certificate.managerSignature} className="h-8 border border-slate-200 mt-1"/>
                    </div>
                 )}
               </div>
             </Card>

             <Card title="History Log">
               <ul className="space-y-3 relative border-l border-slate-200 ml-2 pl-4">
                 {r.logs.map((log, i) => (
                   <li key={i} className="text-xs">
                     <div className="absolute w-2 h-2 bg-slate-300 rounded-full -left-[5px] mt-1"></div>
                     <p className="font-semibold text-slate-700">{log.action}</p>
                     <p className="text-slate-500">{new Date(log.date).toLocaleString()} by {log.actor}</p>
                   </li>
                 ))}
               </ul>
             </Card>
          </div>
        </div>
      )}

      {/* Modals */}
      {modalOpen === 'ISSUE' && <IssueStockModal onClose={() => setModalOpen(null)} onConfirm={handleIssueConfirm} />}
      {modalOpen === 'ASSESS' && <AssessmentModal onClose={() => setModalOpen(null)} onConfirm={handleAssessmentConfirm} />}
      {modalOpen === 'COMPLETION' && <ServiceCompletionModal onClose={() => setModalOpen(null)} onConfirm={handleServiceCompletion} />}
      {modalOpen === 'CERT_FINAL' && <FinalCertificateModal onClose={() => setModalOpen(null)} onConfirm={handleFinalizeCertificate} />}
      {modalOpen === 'BUDGET' && <BudgetModal requestType={r.requestType} onClose={() => setModalOpen(null)} onConfirm={handleBudgetConfirm} />}
      {modalOpen === 'SINGLE' && <SingleSourceModal vendors={vendors} onClose={() => setModalOpen(null)} onConfirm={handleSingleSourceConfirm} />}
      {modalOpen === 'EVAL' && <EvaluationModal vendors={vendors} onClose={() => setModalOpen(null)} onConfirm={handleEvaluationConfirm} />}
      {modalOpen === 'RECEIVE' && <ReceiveGoodsModal initialItems={initialReceiveData} inventory={inventory} onClose={() => setModalOpen(null)} onConfirm={handleReceiveConfirm} />}
    </div>
  );
};

/**
 * Utility to handle browser-level Web Notifications
 */
export const BrowserNotificationService = {
  /**
   * Request permission from the user to show browser notifications
   */
  requestPermission: async (): Promise<NotificationPermission> => {
    if (!("Notification" in window)) {
      console.warn("This browser does not support desktop notification");
      return "denied";
    }

    if (Notification.permission !== "granted" && Notification.permission !== "denied") {
      return await Notification.requestPermission();
    }

    return Notification.permission;
  },

  /**
   * Send a browser notification if permission is granted
   */
  send: (title: string, message: string, tag?: string) => {
    if (!("Notification" in window)) return;

    if (Notification.permission === "granted") {
      const options: NotificationOptions = {
        body: message,
        icon: 'https://cdn-icons-png.flaticon.com/512/2555/2555013.png', // Mock government/shield icon
        tag: tag || 'govtrack-alert',
        badge: 'https://cdn-icons-png.flaticon.com/512/2555/2555013.png',
        silent: false,
      };

      const notification = new Notification(title, options);

      notification.onclick = function(event) {
        event.preventDefault();
        window.focus();
        notification.close();
      };
    }
  },

  getPermissionStatus: () => {
    if (!("Notification" in window)) return "unsupported";
    return Notification.permission;
  }
};

