  create: (req: Omit<ProcurementWorkflow, 'id' | 'logs' | 'gsrfRefNumber'>) => {
    const year = new Date().getFullYear();
    const count = MOCK_REQUESTS.length + 407; 
    const prefix = MOCK_SETTINGS.prefixes.gsrf;
    const gsrfRefNumber = `${prefix}/${MOCK_SETTINGS.officeCode}/${year}/${count}`;

    const newReq: ProcurementWorkflow = { 
      ...req, 
      id: Math.random().toString(36).substr(2, 9),
      gsrfRefNumber,
      logs: [{ date: new Date().toISOString(), action: 'Request Submitted', actor: req.requesterName }]
    };

    NotificationService.add({
      title: 'New Procurement Request',
      message: `${req.requesterName} submitted a new request.`,
      type: 'info',
      link: { tab: 'PROCUREMENT', itemId: newReq.id }
    });

    MOCK_REQUESTS.push(newReq);
    return Promise.resolve(newReq);
  },
  updateStatus: async (id: string, status: ProcurementStatus, logEntry: string, actor: string, updates?: Partial<ProcurementWorkflow>) => {
    const req = MOCK_REQUESTS.find(r => r.id === id);
    if (req) {
      if (status === ProcurementStatus.EVALUATION && !req.evalRefNumber) {
         const year = new Date().getFullYear();
         const pefPrefix = MOCK_SETTINGS.prefixes.pef;
         req.evalRefNumber = `${pefPrefix}${MOCK_SETTINGS.officeCode}/${year}/45`;
      }

      // HANDLE INVENTORY UPDATE ON ISSUE
      if (status === ProcurementStatus.ISSUED) {
          for (const item of req.items) {
              if (item.itemId) {
                  await InventoryService.updateStock(item.itemId, -item.quantity);
              }
          }
      }

      req.status = status;
      req.logs.push({ date: new Date().toISOString(), action: logEntry, actor });
      if (updates) Object.assign(req, updates);

      NotificationService.add({
          title: `Status Updated`,
          message: `Request ${req.gsrfRefNumber} moved to ${status}.`,
          type: 'info',
          link: { tab: 'PROCUREMENT', itemId: req.id }
      });
    }
    return Promise.resolve(req);
  },
  receiveGoods: async (id: string, receivedItems: any[], actor: string) => {
      const req = MOCK_REQUESTS.find(r => r.id === id);
      if (req) {
          for (const item of receivedItems) {
              if (item.inventoryAction === 'NEW') {
                  const govId = InventoryService.generateGovId(new Date().getFullYear().toString(), item.newCategory, '001');
                  await InventoryService.add({
                      name: item.description,
                      category: item.newCategory,
                      quantity: item.receivedQty,
                      location: item.newLocation || 'Main Store',
                      minStockLevel: 5,
                      pricePerUnit: item.price || 0,
                      govId,
                      isAsset: false // Default to false during receipt unless specified
                  });
              } else {
                  await InventoryService.updateStock(item.inventoryAction, item.receivedQty);
              }
          }

          req.status = ProcurementStatus.COMPLETED;
          req.logs.push({ date: new Date().toISOString(), action: 'Goods Received & Inventory Updated', actor });
      }
      return Promise.resolve(req);
  }
};

export const AuthService = {
  getCurrentUser: () => currentUserIndex !== null ? MOCK_USERS[currentUserIndex] : null,
  login: (email: string) => {
    const idx = MOCK_USERS.findIndex(u => u.email === email);
    if (idx !== -1) {
        currentUserIndex = idx;
        return Promise.resolve(MOCK_USERS[idx]);
    }
    return Promise.reject("Invalid credentials");
  },
  logout: () => {
      currentUserIndex = null;
      return Promise.resolve();
  },
  switchUser: (id: string) => {
    const idx = MOCK_USERS.findIndex(u => u.id === id);
    if (idx !== -1) currentUserIndex = idx;
    return MOCK_USERS[currentUserIndex!];
  },
  getAllUsers: () => MOCK_USERS
};

import React, { useState, useEffect, useCallback } from 'react';
import { AuthService, NotificationService } from './services/mockService';
import { BrowserNotificationService } from './services/notificationUtils';
import { AppNotification, AppTab, User } from './types';
import { ProcurementModule } from './components/ProcurementModule';
import { DashboardView } from './components/DashboardView';
import { InventoryView } from './components/InventoryView';
import { AssetView } from './components/AssetView';
import { ReportsView } from './components/ReportsView';
import { SettingsView } from './components/SettingsView';
import { VendorManagement } from './components/VendorManagement';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { LoginView } from './components/LoginView';
import { AlertCircle, X, BellRing } from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState<AppTab>('DASHBOARD');
  const [targetId, setTargetId] = useState<string | null>(null);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);

  // Toast state for in-app transient alerts
  const [toasts, setToasts] = useState<AppNotification[]>([]);

  // Auth State
  const [user, setUser] = useState<User | null>(AuthService.getCurrentUser());

  const addToast = useCallback((notif: AppNotification) => {
    setToasts(prev => [...prev, notif]);
    // Auto-remove after 6 seconds
    setTimeout(() => {
        setToasts(prev => prev.filter(t => t.id !== notif.id));
    }, 6000);
  }, []);

  useEffect(() => {
    if (!user) return;

    // Load initial data
    const loadNotifications = async () => {
      const data = await NotificationService.getAll();

      // Check if new notifications arrived (simple length check for demo)
      if (data.length > notifications.length && notifications.length > 0) {
          const newItems = data.slice(0, data.length - notifications.length);
          newItems.forEach(item => addToast(item));
      }

      setNotifications(data);
    };
    loadNotifications();

    // Poll for changes
    const interval = setInterval(loadNotifications, 5000);

    // Request Browser Notification Permission on mount/login
    BrowserNotificationService.requestPermission();

    return () => clearInterval(interval);
  }, [user, notifications.length, addToast]);

  const handleLogin = (newUser: User) => {
    setUser(newUser);
    setActiveTab('DASHBOARD');
    BrowserNotificationService.requestPermission();
  };

  const handleLogout = async () => {
    await AuthService.logout();
    setUser(null);
  };

  const markRead = async (e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    await NotificationService.markAllRead();
    setNotifications(await NotificationService.getAll());
  };

  const handleTabChange = (tab: AppTab) => {
    setActiveTab(tab);
    setTargetId(null);
    setMobileMenuOpen(false);
  };

  const handleNotificationClick = (notification: AppNotification) => {
    if (notification.link) {
        setActiveTab(notification.link.tab);
        if (notification.link.itemId) {
            setTargetId(notification.link.itemId);
        }
    }
    setShowNotifications(false);
    // Also remove from toasts if clicked
    setToasts(prev => prev.filter(t => t.id !== notification.id));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'DASHBOARD': return <DashboardView />;
      case 'INVENTORY': return <InventoryView />;
      case 'PROCUREMENT': return <ProcurementModule initialRequestId={activeTab === 'PROCUREMENT' ? targetId : null} />;
      case 'ASSETS': return <AssetView />;
      case 'VENDORS': return <VendorManagement />;
      case 'REPORTS': return <ReportsView />;
      case 'SETTINGS': return <SettingsView />;
      default: return <DashboardView />;
    }
  };

  if (!user) {
    return <LoginView onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex font-sans text-slate-900">
      <Sidebar 
        activeTab={activeTab} 
        onTabChange={handleTabChange} 
        mobileMenuOpen={mobileMenuOpen} 
        currentUser={user}
        onLogout={handleLogout}
      />

      <div className="flex-1 flex flex-col overflow-hidden relative">
        <Header 
            activeTab={activeTab}
            mobileMenuOpen={mobileMenuOpen}
            setMobileMenuOpen={setMobileMenuOpen}
            showNotifications={showNotifications}
            setShowNotifications={setShowNotifications}
            notifications={notifications}
            markRead={markRead}
            handleNotificationClick={handleNotificationClick}
        />

        <main className="flex-1 overflow-auto p-4 md:p-8 relative">
          {renderContent()}
        </main>

        {/* Improved Notification Toast Stack */}
        <div className="fixed top-20 right-4 z-[100] flex flex-col gap-3 w-80 md:w-96 pointer-events-none">
            {toasts.map(toast => (
                <div 
                    key={toast.id}
                    className="pointer-events-auto bg-white border-l-4 border-gov-600 rounded-lg shadow-2xl p-4 flex gap-4 animate-in slide-in-from-right fade-in duration-300 transform transition-all hover:scale-[1.02] cursor-pointer"
                    onClick={() => handleNotificationClick(toast)}
                >
                    <div className={`mt-1 flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${toast.type === 'warning' ? 'bg-amber-100 text-amber-600' : 'bg-blue-100 text-blue-600'}`}>
                        {toast.type === 'warning' ? <AlertCircle className="w-5 h-5" /> : <BellRing className="w-5 h-5" />}
                    </div>
                    <div className="flex-1">
                        <div className="flex justify-between items-start">
                            <h4 className="font-bold text-sm text-slate-900">{toast.title}</h4>
                            <button 
                                onClick={(e) => {
                                    e.stopPropagation();
                                    setToasts(prev => prev.filter(t => t.id !== toast.id));
                                }}
                                className="text-slate-400 hover:text-slate-600"
                            >
                                <X className="w-4 h-4" />
                            </button>
                        </div>
                        <p className="text-xs text-slate-600 mt-1 line-clamp-2">{toast.message}</p>
                    </div>
                </div>
            ))}
        </div>
      </div>

      {mobileMenuOpen && <div className="fixed inset-0 bg-black bg-opacity-50 z-40 md:hidden" onClick={() => setMobileMenuOpen(false)}></div>}

      {showNotifications && <div className="fixed inset-0 z-30" onClick={() => setShowNotifications(false)}></div>}
    </div>
  );
}

import React, { useState } from 'react';
import { Menu, Bell, ShieldAlert, Check } from 'lucide-react';
import { AppNotification, AppTab } from '../types';
import { BrowserNotificationService } from '../services/notificationUtils';

interface HeaderProps {
    activeTab: AppTab;
    mobileMenuOpen: boolean;
    setMobileMenuOpen: (open: boolean) => void;
    showNotifications: boolean;
    setShowNotifications: (show: boolean) => void;
    notifications: AppNotification[];
    markRead: (e?: React.MouseEvent) => void;
    handleNotificationClick: (n: AppNotification) => void;
}

export const Header: React.FC<HeaderProps> = ({
    activeTab,
    mobileMenuOpen,
    setMobileMenuOpen,
    showNotifications,
    setShowNotifications,
    notifications,
    markRead,
    handleNotificationClick
}) => {
    const unreadCount = notifications.filter(n => !n.read).length;
    const browserPerm = BrowserNotificationService.getPermissionStatus();

    const handleEnableBrowser = async () => {
        const res = await BrowserNotificationService.requestPermission();
        if (res === 'granted') {
            BrowserNotificationService.send("Success!", "Browser alerts are now enabled for GovTrack.");
        }
    };

    return (
        <header className="bg-white shadow-sm z-40 p-4 flex items-center justify-between sticky top-0">
           <div className="flex items-center">
             <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2 text-slate-600 md:hidden mr-2">
               <Menu className="w-6 h-6" />
             </button>
             <span className="font-bold text-gov-900 md:hidden">GovTrack</span>
             <h2 className="hidden md:block text-lg font-semibold text-slate-700 capitalize">
                {activeTab.toLowerCase().replace('_', ' ')}
             </h2>
           </div>

           <div className="flex items-center gap-4">
              {/* Notification Bell */}
              <div className="relative">
                <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-slate-500 hover:text-gov-600 relative outline-none focus:ring-2 focus:ring-gov-200 rounded-full transition-all">
                   <Bell className="w-6 h-6" />
                   {unreadCount > 0 && (
                       <span className="absolute top-1 right-1 h-3 w-3 bg-red-500 rounded-full border-2 border-white animate-pulse"></span>
                   )}
                </button>
                {/* Notification Dropdown */}
                {showNotifications && (
                    <div className="absolute right-0 mt-2 w-80 md:w-96 bg-white rounded-lg shadow-2xl border border-slate-200 z-50 overflow-hidden transform origin-top-right transition-all">
                        <div className="p-4 border-b bg-slate-50 flex justify-between items-center">
                            <h3 className="font-bold text-sm text-slate-700 flex items-center gap-2">
                                <Bell className="w-4 h-4" /> Notifications
                            </h3>
                            {unreadCount > 0 && (
                                <button onClick={markRead} className="text-xs text-gov-600 font-bold hover:underline">Mark all read</button>
                            )}
                        </div>

                        {/* Browser Permission Prompt */}
                        {browserPerm !== 'granted' && (
                            <div className="px-4 py-3 bg-indigo-50 border-b border-indigo-100 flex items-center justify-between">
                                <div className="flex items-center gap-2 text-[11px] text-indigo-700 font-medium">
                                    <ShieldAlert className="w-4 h-4" /> Desktop alerts are off
                                </div>
                                <button 
                                    onClick={handleEnableBrowser}
                                    className="bg-indigo-600 text-white text-[10px] font-bold px-2 py-1 rounded hover:bg-indigo-700"
                                >
                                    Enable
                                </button>
                            </div>
                        )}

                        <div className="max-h-96 overflow-y-auto">
                            {notifications.length === 0 ? (
                                <p className="p-8 text-sm text-slate-400 text-center italic">No new activity</p>
                            ) : (
                                notifications.map(n => (
                                    <div 
                                      key={n.id} 
                                      onClick={() => handleNotificationClick(n)}
                                      className={`p-4 border-b hover:bg-slate-50 last:border-0 cursor-pointer transition-colors ${!n.read ? 'bg-blue-50/40' : ''}`}
                                    >
                                        <div className="flex justify-between items-start mb-1">
                                            <div className="flex items-center gap-2">
                                                <span className={`w-2 h-2 rounded-full ${!n.read ? 'bg-gov-500' : 'bg-transparent'}`}></span>
                                                <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded uppercase tracking-wide ${
                                                    n.type === 'warning' ? 'bg-amber-100 text-amber-800' : 
                                                    n.type === 'success' ? 'bg-green-100 text-green-800' : 
                                                    'bg-blue-100 text-blue-800'
                                                }`}>
                                                    {n.type === 'error' ? 'Alert' : n.type}
                                                </span>
                                            </div>
                                            <span className="text-[10px] text-slate-400 font-medium">{n.time}</span>
                                        </div>
                                        <p className="text-sm font-bold text-slate-800 leading-tight">{n.title}</p>
                                        <p className="text-xs text-slate-500 mt-1 leading-normal line-clamp-2">{n.message}</p>
                                    </div>
                                ))
                            )}
                        </div>

                        <div className="p-3 bg-slate-50 border-t text-center">
                             <button className="text-xs text-slate-500 hover:text-gov-800 font-medium">View all activity history</button>
                        </div>
                    </div>
                )}
              </div>
           </div>
        </header>
    );
};

