                                {u.role}
                              </span>
                            </td>
                            <td className="px-6 py-4 text-sm text-slate-500 font-medium">{u.department}</td>
                            <td className="px-6 py-4 text-right text-sm font-medium">
                                <div className="flex justify-end gap-2">
                                  <button 
