  const [evalType, setEvalType] = useState<EvaluationType>('FORM');
  const [evalData, setEvalData] = useState({
    method: EvaluationMethod.EMAIL,
    vendors: [
      { vendorName: '', quoteNumber: '', quoteDate: '', price: 0, selected: false },
